static int append_literal(struct buffer *buf, const char *text) {
    return buffer_append(buf, text, strlen(text));
}

static int append_format(struct buffer *buf, const char *fmt, ...) {
    char small[1024];
    char *dynamic_buf = NULL;
    va_list ap;
    va_list copy;
    int needed;
    int rc;

    va_start(ap, fmt);
    va_copy(copy, ap);
    needed = vsnprintf(small, sizeof(small), fmt, ap);
    va_end(ap);
    if (needed < 0) {
        va_end(copy);
        return -1;
    }
    if ((size_t)needed < sizeof(small)) {
        va_end(copy);
        return buffer_append(buf, small, (size_t)needed);
    }
    dynamic_buf = malloc((size_t)needed + 1U);
    if (dynamic_buf == NULL) {
        va_end(copy);
        return -1;
    }
    rc = vsnprintf(dynamic_buf, (size_t)needed + 1U, fmt, copy);
    va_end(copy);
    if (rc < 0) {
        free(dynamic_buf);
        return -1;
    }
    rc = buffer_append(buf, dynamic_buf, (size_t)rc);
    free(dynamic_buf);
    return rc;
}

static int write_text_once_errno(const char *path, const char *text) {
    int fd = open(path, O_WRONLY | O_CLOEXEC);
    int saved_errno;

    if (fd < 0) {
        return -errno;
    }
    if (write_all_fd(fd, text, strlen(text)) < 0) {
        saved_errno = errno;
        close(fd);
        return -saved_errno;
    }
    if (close(fd) < 0) {
        return -errno;
    }
    return 0;
}

static int append_late_per_proxy_corrected_rc1_enumerate(struct buffer *stdout_buf,
                                                         const char *phase,
                                                         int per_mgr_subsys_esoc0_count,
                                                         int pm_service_powerup_thread_count,
                                                         bool *write_executed_out) {
    const char *rc_sel_path = "/sys/kernel/debug/pci-msm/rc_sel";
    const char *case_path = "/sys/kernel/debug/pci-msm/case";
    int rc_sel_rc;
    int case_rc = 0;
    int case_attempted = 0;
    bool write_executed;

    rc_sel_rc = write_text_once_errno(rc_sel_path, "2\n");
    if (rc_sel_rc == 0) {
        case_attempted = 1;
        case_rc = write_text_once_errno(case_path, "11\n");
    }
    write_executed = rc_sel_rc == 0 && case_attempted && case_rc == 0;
    if (write_executed_out) {
        *write_executed_out = write_executed;
    }

    return append_format(stdout_buf,
                         "pm_service_trigger_observer.corrected_rc1_enumerate.begin=1\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.triggered=1\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.phase=%s\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.monotonic_ms=%ld\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.gate_per_mgr_subsys_esoc0_count=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.gate_pm_service_powerup_thread_count=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.rc_sel_path=%s\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.case_path=%s\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.rc_sel_attempted=1\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.rc_sel_rc=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.case_attempted=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.case_rc=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.debugfs_control_write_executed=%d\n"
                         "pm_service_trigger_observer.response_sampler.debugfs_control_write_executed=%d\n"
                         "pm_service_trigger_observer.corrected_rc1_enumerate.end=1\n",
                         phase,
                         monotonic_ms(),
                         per_mgr_subsys_esoc0_count,
                         pm_service_powerup_thread_count,
                         rc_sel_path,
                         case_path,
                         rc_sel_rc,
                         case_attempted,
                         case_attempted ? case_rc : 0,
                         write_executed ? 1 : 0,
                         write_executed ? 1 : 0);
}

struct sepolicy_inventory_path {
    const char *label;
    const char *path;
};

static void sanitize_one_line(char *value) {
    for (size_t i = 0; value[i] != '\0'; i++) {
        unsigned char ch = (unsigned char)value[i];

        if (ch == '\n' || ch == '\r') {
            value[i] = '\0';
            return;
        }
        if (ch < 0x20 || ch > 0x7e) {
            value[i] = '?';
        }
    }
}

static int read_root_first_line(const struct paths *paths,
                                const char *absolute_path,
                                char *out,
                                size_t out_size,
                                bool *present) {
    char host_path[MAX_PATH_LEN];
    int fd;
    ssize_t nread;

    *present = false;
    if (out_size == 0) {
        errno = EINVAL;
        return -1;
    }
    out[0] = '\0';
    if (path_in_root(host_path, sizeof(host_path), paths, absolute_path) < 0) {
        return -1;
    }
    fd = open(host_path, O_RDONLY | O_CLOEXEC);
    if (fd < 0) {
        if (errno == ENOENT || errno == ENOTDIR) {
            return 0;
        }
        return -1;
    }
    *present = true;
    nread = read(fd, out, out_size - 1U);
    close(fd);
    if (nread < 0) {
        out[0] = '\0';
        return -1;
    }
    out[nread] = '\0';
    sanitize_one_line(out);
    return 0;
}

static int append_sepolicy_path_info(struct buffer *buf,
                                     const struct paths *paths,
                                     const char *label,
                                     const char *absolute_path) {
    char host_path[MAX_PATH_LEN];
    char line[256];
    struct stat st;
    uint64_t hash;
    size_t bytes;
    bool present = false;

    if (path_in_root(host_path, sizeof(host_path), paths, absolute_path) < 0) {
        return append_format(buf, "sepolicy.path.%s.error=path-too-long\n", label);
    }
    if (append_format(buf, "sepolicy.path.%s.path=%s\n", label, absolute_path) < 0 ||
        append_format(buf, "sepolicy.path.%s.host_path=%s\n", label, host_path) < 0) {
        return -1;
    }
    if (lstat(host_path, &st) < 0) {
        return append_format(buf,
                             "sepolicy.path.%s.exists=0\n"
                             "sepolicy.path.%s.errno=%d\n",
                             label,
                             label,
                             errno);
    }
    if (append_format(buf,
                      "sepolicy.path.%s.exists=1\n"
                      "sepolicy.path.%s.mode=%o\n"
                      "sepolicy.path.%s.type=%s\n"
                      "sepolicy.path.%s.size=%lld\n"
                      "sepolicy.path.%s.access_r=%d\n"
                      "sepolicy.path.%s.access_x=%d\n",
                      label,
                      label,
                      st.st_mode & 07777,
                      label,
                      S_ISREG(st.st_mode) ? "regular" :
                      S_ISDIR(st.st_mode) ? "directory" :
                      S_ISLNK(st.st_mode) ? "symlink" :
                      S_ISCHR(st.st_mode) ? "char" :
                      S_ISBLK(st.st_mode) ? "block" : "other",
                      label,
                      (long long)st.st_size,
                      label,
                      access(host_path, R_OK) == 0 ? 1 : 0,
                      label,
                      access(host_path, X_OK) == 0 ? 1 : 0) < 0) {
        return -1;
    }
    if (S_ISREG(st.st_mode) && fnv1a64_file(host_path, &hash, &bytes) == 0) {
        if (append_format(buf,
                          "sepolicy.path.%s.bytes=%zu\n"
                          "sepolicy.path.%s.hash=0x%016llx\n",
                          label,
                          bytes,
                          label,
                          (unsigned long long)hash) < 0) {
            return -1;
        }
    }
    if (S_ISREG(st.st_mode) &&
        read_root_first_line(paths, absolute_path, line, sizeof(line), &present) == 0 &&
        present && line[0] != '\0') {
        if (append_format(buf, "sepolicy.path.%s.first_line=%s\n", label, line) < 0) {
            return -1;
        }
    }
    return 0;
}

static int append_sepolicy_hash_compare(struct buffer *buf,
                                        const struct paths *paths,
                                        const char *label,
                                        const char *actual_path,
                                        const char *precompiled_path) {
    char actual[256];
    char precompiled[256];
    bool actual_present = false;
    bool precompiled_present = false;
    int actual_rc;
    int precompiled_rc;
    bool match = false;

    actual_rc = read_root_first_line(paths, actual_path, actual, sizeof(actual), &actual_present);
    precompiled_rc = read_root_first_line(paths,
                                          precompiled_path,
                                          precompiled,
                                          sizeof(precompiled),
                                          &precompiled_present);
    if (actual_rc < 0 || precompiled_rc < 0) {
        return append_format(buf,
                             "sepolicy.hash.%s.error=read-failed\n"
                             "sepolicy.hash.%s.actual_rc=%d\n"
                             "sepolicy.hash.%s.precompiled_rc=%d\n",
                             label,
                             label,
                             actual_rc,
                             label,
                             precompiled_rc);
    }
    match = actual_present && precompiled_present && actual[0] != '\0' && streq(actual, precompiled);
    return append_format(buf,
                         "sepolicy.hash.%s.actual_present=%d\n"
                         "sepolicy.hash.%s.precompiled_present=%d\n"
                         "sepolicy.hash.%s.match=%d\n"
                         "sepolicy.hash.%s.actual=%s\n"
                         "sepolicy.hash.%s.precompiled=%s\n",
                         label,
                         actual_present ? 1 : 0,
                         label,
                         precompiled_present ? 1 : 0,
                         label,
                         match ? 1 : 0,
                         label,
                         actual_present ? actual : "<missing>",
                         label,
                         precompiled_present ? precompiled : "<missing>");
}

static bool root_path_exists(const struct paths *paths, const char *absolute_path) {
    char host_path[MAX_PATH_LEN];

    if (path_in_root(host_path, sizeof(host_path), paths, absolute_path) < 0) {
        return false;
    }
    return access(host_path, F_OK) == 0;
}

static int append_stat_line(struct buffer *stdout_buf,
                            const char *prefix,
                            const char *label,
                            const char *path,
                            const struct stat *st,
                            int err_no) {
    return append_format(stdout_buf,
                         "%s.%s.path=%s\n"
                         "%s.%s.present=%d\n"
                         "%s.%s.executable=%d\n"
                         "%s.%s.mode=%o\n"
                         "%s.%s.size=%lld\n"
                         "%s.%s.errno=%d\n",
                         prefix,
                         label,
                         path,
                         prefix,
                         label,
                         err_no == 0 ? 1 : 0,
                         prefix,
                         label,
                         (err_no == 0 && (st->st_mode & 0111) != 0) ? 1 : 0,
                         prefix,
                         label,
                         err_no == 0 ? (unsigned int)(st->st_mode & 07777) : 0,
                         prefix,
                         label,
                         err_no == 0 ? (long long)st->st_size : 0LL,
                         prefix,
                         label,
                         err_no);
}

static int append_root_stat_line(const struct paths *paths,
                                 struct buffer *stdout_buf,
                                 const char *prefix,
                                 const char *label,
                                 const char *absolute_path,
                                 bool *present,
                                 bool *executable) {
    char host_path[MAX_PATH_LEN];
    struct stat st;
    int err_no = 0;

    *present = false;
    *executable = false;
    if (path_in_root(host_path, sizeof(host_path), paths, absolute_path) < 0) {
        err_no = errno;
        memset(&st, 0, sizeof(st));
    } else if (stat(host_path, &st) < 0) {
        err_no = errno;
        memset(&st, 0, sizeof(st));
    } else {
        *present = true;
        *executable = (st.st_mode & 0111) != 0;
    }
    return append_stat_line(stdout_buf, prefix, label, absolute_path, &st, err_no);
}

static int append_host_stat_line(struct buffer *stdout_buf,
                                 const char *prefix,
                                 const char *label,
                                 const char *path,
                                 bool *present,
                                 bool *executable) {
    struct stat st;
    int err_no = 0;

    *present = false;
    *executable = false;
    if (stat(path, &st) < 0) {
        err_no = errno;
        memset(&st, 0, sizeof(st));
    } else {
        *present = true;
        *executable = (st.st_mode & 0111) != 0;
    }
    return append_stat_line(stdout_buf, prefix, label, path, &st, err_no);
}

static int run_wifi_connect_tool_surface(const struct config *cfg,
                                         const struct paths *paths,
                                         struct buffer *stdout_buf) {
    bool vendor_wpa_hw_present = false;
    bool vendor_wpa_hw_executable = false;
    bool vendor_wpa_present = false;
    bool vendor_wpa_executable = false;
    bool system_wificond_present = false;
    bool system_wificond_executable = false;
    bool system_ip_present = false;
    bool system_ip_executable = false;
    bool system_ping_present = false;
    bool system_ping_executable = false;
    bool system_dhcpcd_present = false;
    bool system_dhcpcd_executable = false;
    bool system_udhcpc_present = false;
    bool system_udhcpc_executable = false;
    bool cache_busybox_present = false;
    bool cache_busybox_executable = false;
    bool cache_toybox_present = false;
    bool cache_toybox_executable = false;
    bool supplicant_ready;
    bool dhcp_ready;
    bool ping_ready;

    (void)cfg;
    if (append_format(stdout_buf,
                       "wifi_connect_tool_surface.begin=1\n"
                       "wifi_connect_tool_surface.device_commands_executed=0\n"
                       "wifi_connect_tool_surface.device_mutations=0\n"
                       "wifi_connect_tool_surface.credentials_read=0\n"
                       "wifi_connect_tool_surface.scan_connect_executed=0\n"
                       "wifi_connect_tool_surface.external_ping_executed=0\n"
                       "wifi_connect_tool_surface.strategy=wpa-supplicant-plus-dhcp-plus-ping\n") < 0) {
        return -1;
    }
    if (append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "vendor_wpa_supplicant_hw",
                              "/vendor/bin/hw/wpa_supplicant",
                              &vendor_wpa_hw_present,
                              &vendor_wpa_hw_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "vendor_wpa_supplicant",
                              "/vendor/bin/wpa_supplicant",
                              &vendor_wpa_present,
                              &vendor_wpa_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "system_wificond",
                              "/system/bin/wificond",
                              &system_wificond_present,
                              &system_wificond_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "system_ip",
                              "/system/bin/ip",
                              &system_ip_present,
                              &system_ip_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "system_ping",
                              "/system/bin/ping",
                              &system_ping_present,
                              &system_ping_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "system_dhcpcd",
                              "/system/bin/dhcpcd",
                              &system_dhcpcd_present,
                              &system_dhcpcd_executable) < 0 ||
        append_root_stat_line(paths,
                              stdout_buf,
                              "wifi_connect_tool_surface",
                              "system_udhcpc",
                              "/system/bin/udhcpc",
                              &system_udhcpc_present,
                              &system_udhcpc_executable) < 0 ||
        append_host_stat_line(stdout_buf,
                              "wifi_connect_tool_surface",
                              "cache_busybox",
                              "/cache/bin/busybox",
                              &cache_busybox_present,
                              &cache_busybox_executable) < 0 ||
        append_host_stat_line(stdout_buf,
                              "wifi_connect_tool_surface",
                              "cache_toybox",
                              "/cache/bin/toybox",
                              &cache_toybox_present,
                              &cache_toybox_executable) < 0) {
        return -1;
    }
    supplicant_ready = (vendor_wpa_hw_present && vendor_wpa_hw_executable) ||
                       (vendor_wpa_present && vendor_wpa_executable);
    dhcp_ready = (system_dhcpcd_present && system_dhcpcd_executable) ||
                 (system_udhcpc_present && system_udhcpc_executable) ||
                 (cache_busybox_present && cache_busybox_executable);
    ping_ready = system_ip_present && system_ip_executable &&
                 system_ping_present && system_ping_executable;
    if (append_format(stdout_buf,
                      "wifi_connect_tool_surface.supplicant_ready=%d\n"
                      "wifi_connect_tool_surface.dhcp_ready=%d\n"
                      "wifi_connect_tool_surface.ping_ready=%d\n",
                      supplicant_ready ? 1 : 0,
                      dhcp_ready ? 1 : 0,
                      ping_ready ? 1 : 0) < 0) {
        return -1;
    }
    if (supplicant_ready && dhcp_ready && ping_ready) {
        return append_literal(stdout_buf,
                              "wifi_connect_tool_surface.result=connect-tools-ready\n"
                              "wifi_connect_tool_surface.reason=supplicant-dhcp-ping-tools-present\n"
                              "wifi_connect_tool_surface.end=1\n");
    }
    return append_literal(stdout_buf,
                          "wifi_connect_tool_surface.result=connect-tools-missing\n"
                          "wifi_connect_tool_surface.reason=supplicant-dhcp-or-ping-tool-missing\n"
                          "wifi_connect_tool_surface.end=1\n");
}

static int copy_connect_config_into_private_wifi(const struct config *cfg,
                                                 const struct paths *paths,
                                                 char *chroot_path,
                                                 size_t chroot_path_size,
                                                 char *host_path,
                                                 size_t host_path_size,
                                                 struct buffer *stdout_buf) {
    char buffer[4096];
    struct stat st;
    int src_fd = -1;
    int dst_fd = -1;
    int open_flags = O_RDONLY | O_CLOEXEC;
    ssize_t nread;
    size_t copied = 0;

#ifdef O_NOFOLLOW
    open_flags |= O_NOFOLLOW;
#endif

    if (snprintf(chroot_path,
                 chroot_path_size,
                 "/data/vendor/wifi/wpa/a90_connect_execns.conf") >= (int)chroot_path_size ||
        append_path(host_path,
                    host_path_size,
                    paths->data_vendor_wifi_wpa,
                    "a90_connect_execns.conf") < 0) {
        errno = ENAMETOOLONG;
        return -1;
    }
    src_fd = open(cfg->connect_config, open_flags);
    if (src_fd < 0) {
        return -1;
    }
    if (fstat(src_fd, &st) < 0 ||
        !S_ISREG(st.st_mode) ||
        (st.st_mode & 0077) != 0 ||
        st.st_size <= 0 ||
        st.st_size > 8192) {
        if (errno == 0) {
            errno = EINVAL;
        }
        close(src_fd);
        return -1;
    }
    dst_fd = open(host_path, O_WRONLY | O_CREAT | O_TRUNC | O_CLOEXEC, 0600);
    if (dst_fd < 0) {
        close(src_fd);
        return -1;
    }
    while ((nread = read(src_fd, buffer, sizeof(buffer))) > 0) {
        if (write_all_fd(dst_fd, buffer, (size_t)nread) < 0) {
            close(src_fd);
            close(dst_fd);
            return -1;
        }
        copied += (size_t)nread;
    }
    if (nread < 0) {
        close(src_fd);
        close(dst_fd);
        return -1;
    }
    if (fchown(dst_fd, A90_AID_WIFI, A90_AID_WIFI) < 0 ||
        fchmod(dst_fd, 0600) < 0) {
        close(src_fd);
        close(dst_fd);
        return -1;
    }
    if (close(dst_fd) < 0) {
        close(src_fd);
        return -1;
    }
    close(src_fd);
    return append_format(stdout_buf,
                         "wifi_connect_ping.connect_config.private_copy=1\n"
                         "wifi_connect_ping.connect_config.private_chroot_path=%s\n"
                         "wifi_connect_ping.connect_config.private_size=%zu\n",
                         chroot_path,
                         copied);
}

static int wait_child_quiet(pid_t pid,
                            int timeout_ms,
                            bool terminate_on_timeout,
                            int *exit_code,
                            int *signal_no,
                            bool *timed_out) {
    long deadline = monotonic_ms() + timeout_ms;
    int status = 0;

    *exit_code = -1;
    *signal_no = 0;
    *timed_out = false;
    for (;;) {
        pid_t wait_rc = waitpid(pid, &status, WNOHANG);

        if (wait_rc == pid) {
            if (WIFEXITED(status)) {
                *exit_code = WEXITSTATUS(status);
                return *exit_code;
            }
            if (WIFSIGNALED(status)) {
                *signal_no = WTERMSIG(status);
                return 128 + *signal_no;
            }
            return 125;
        }
        if (wait_rc < 0) {
            return 126;
        }
        if (monotonic_ms() >= deadline) {
            break;
        }
        usleep(100000);
    }
    *timed_out = true;
    if (terminate_on_timeout) {
        kill(pid, SIGTERM);
        usleep(300000);
        if (waitpid(pid, &status, WNOHANG) != pid) {
            kill(pid, SIGKILL);
            waitpid(pid, &status, 0);
        }
    }
    return 124;
}

static int run_quiet_argv(char *const argv[],
                          int timeout_ms,
                          int *exit_code,
                          int *signal_no,
                          bool *timed_out) {
    pid_t pid = fork();

    if (pid < 0) {
        return 126;
    }
    if (pid == 0) {
        int devnull = open("/dev/null", O_RDWR | O_CLOEXEC);

        if (devnull >= 0) {
            dup2(devnull, STDIN_FILENO);
            dup2(devnull, STDOUT_FILENO);
            dup2(devnull, STDERR_FILENO);
            if (devnull > STDERR_FILENO) {
                close(devnull);
            }
        }
        execv(argv[0], argv);
        _exit(127);
    }
    return wait_child_quiet(pid, timeout_ms, true, exit_code, signal_no, timed_out);
}

static int run_capture_argv_to_file(char *const argv[],
                                    const char *output_path,
                                    int timeout_ms,
                                    int *exit_code,
                                    int *signal_no,
                                    bool *timed_out) {
    pid_t pid = fork();

    if (pid < 0) {
        return 126;
    }
    if (pid == 0) {
        int devnull = open("/dev/null", O_RDONLY | O_CLOEXEC);
        int outfd = open(output_path, O_WRONLY | O_CREAT | O_TRUNC | O_CLOEXEC, 0600);

        if (devnull >= 0) {
            dup2(devnull, STDIN_FILENO);
            if (devnull > STDERR_FILENO) {
                close(devnull);
            }
        }
        if (outfd >= 0) {
            dup2(outfd, STDOUT_FILENO);
            dup2(outfd, STDERR_FILENO);
            if (outfd > STDERR_FILENO) {
                close(outfd);
            }
        } else {
            int fallback = open("/dev/null", O_RDWR | O_CLOEXEC);

            if (fallback >= 0) {
                dup2(fallback, STDOUT_FILENO);
                dup2(fallback, STDERR_FILENO);
                if (fallback > STDERR_FILENO) {
                    close(fallback);
                }
            }
        }
        execv(argv[0], argv);
        _exit(127);
    }
    return wait_child_quiet(pid, timeout_ms, true, exit_code, signal_no, timed_out);
}

#if A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_SAMPLER
struct tail_perf_regs_codeword_sampler {
    pid_t pid;
    long started_ms;
    bool started;
};

static void tail_perf_regs_codeword_sampler_init(struct tail_perf_regs_codeword_sampler *sampler) {
    sampler->pid = -1;
    sampler->started_ms = 0;
    sampler->started = false;
}

static int append_tail_perf_regs_codeword_sampler_start(
    struct buffer *stdout_buf,
    struct tail_perf_regs_codeword_sampler *sampler) {
    char duration_ms[32];
    char period_ns[32];
    char print_limit[32];
    struct stat helper_st;
    struct stat output_st;
    int helper_errno = 0;
    int output_parent_errno = 0;
    const char *helper_path = A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_HELPER_PATH;
    const char *output_path = A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_OUTPUT_PATH;
    const char *output_parent = "/cache";
    pid_t pid;

    tail_perf_regs_codeword_sampler_init(sampler);
    snprintf(duration_ms, sizeof(duration_ms), "%d", A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_DURATION_MS);
    snprintf(period_ns, sizeof(period_ns), "%d", A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_PERIOD_NS);
    snprintf(print_limit, sizeof(print_limit), "%d", A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_PRINT_LIMIT);

    if (stat(helper_path, &helper_st) < 0) {
        helper_errno = errno;
        memset(&helper_st, 0, sizeof(helper_st));
    }
    if (stat(output_parent, &output_st) < 0) {
        output_parent_errno = errno;
        memset(&output_st, 0, sizeof(output_st));
    }
    if (append_format(stdout_buf,
                      "tail_perf_regs_codeword_sampler.begin=1\n"
                      "tail_perf_regs_codeword_sampler.enabled=1\n"
                      "tail_perf_regs_codeword_sampler.helper=%s\n"
                      "tail_perf_regs_codeword_sampler.output=%s\n"
                      "tail_perf_regs_codeword_sampler.duration_ms=%d\n"
                      "tail_perf_regs_codeword_sampler.period_ns=%d\n"
                      "tail_perf_regs_codeword_sampler.print_limit=%d\n"
                      "tail_perf_regs_codeword_sampler.wait_ms=%d\n"
                      "tail_perf_regs_codeword_sampler.helper_exists=%d\n"
                      "tail_perf_regs_codeword_sampler.helper_mode=%04o\n"
                      "tail_perf_regs_codeword_sampler.helper_errno=%d\n"
                      "tail_perf_regs_codeword_sampler.output_parent_exists=%d\n"
                      "tail_perf_regs_codeword_sampler.output_parent_errno=%d\n",
                      helper_path,
                      output_path,
                      A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_DURATION_MS,
                      A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_PERIOD_NS,
                      A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_PRINT_LIMIT,
                      A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_WAIT_MS,
                      helper_errno == 0 ? 1 : 0,
                      helper_errno == 0 ? (unsigned int)(helper_st.st_mode & 07777) : 0U,
                      helper_errno,
                      output_parent_errno == 0 ? 1 : 0,
                      output_parent_errno) < 0) {
        return -1;
    }
    if (helper_errno != 0 || output_parent_errno != 0) {
        return append_format(stdout_buf,
                             "tail_perf_regs_codeword_sampler.started=0\n"
                             "tail_perf_regs_codeword_sampler.pid=-1\n"
                             "tail_perf_regs_codeword_sampler.reason=%s\n",
                             helper_errno != 0 ? "helper-missing" : "output-parent-missing");
    }

    pid = fork();
    if (pid < 0) {
        return append_format(stdout_buf,
                             "tail_perf_regs_codeword_sampler.started=0\n"
                             "tail_perf_regs_codeword_sampler.pid=-1\n"
                             "tail_perf_regs_codeword_sampler.reason=fork-failed-%s\n",
                             strerror(errno));
    }
    if (pid == 0) {
        char *const sampler_argv[] = {
            (char *)helper_path,
            (char *)"--duration-ms",
            duration_ms,
            (char *)"--period-ns",
            period_ns,
            (char *)"--print-limit",
            print_limit,
            (char *)"--allow-attach",
            NULL,
        };
        int devnull = open("/dev/null", O_RDONLY | O_CLOEXEC);
        int outfd = open(output_path, O_WRONLY | O_CREAT | O_TRUNC | O_CLOEXEC, 0600);

        if (devnull >= 0) {
            dup2(devnull, STDIN_FILENO);
            if (devnull > STDERR_FILENO) {
                close(devnull);
            }
        }
        if (outfd >= 0) {
            dup2(outfd, STDOUT_FILENO);
            dup2(outfd, STDERR_FILENO);
            if (outfd > STDERR_FILENO) {
                close(outfd);
            }
        } else {
            int fallback = open("/dev/null", O_RDWR | O_CLOEXEC);

            if (fallback >= 0) {
                dup2(fallback, STDOUT_FILENO);
                dup2(fallback, STDERR_FILENO);
                if (fallback > STDERR_FILENO) {
                    close(fallback);
                }
            }
        }
        execv(helper_path, sampler_argv);
        _exit(127);
    }
    sampler->pid = pid;
    sampler->started_ms = monotonic_ms();
    sampler->started = true;
    return append_format(stdout_buf,
                         "tail_perf_regs_codeword_sampler.started=1\n"
                         "tail_perf_regs_codeword_sampler.pid=%ld\n"
                         "tail_perf_regs_codeword_sampler.reason=started-before-boot-wlan\n",
                         (long)pid);
}

static int append_tail_perf_regs_codeword_sampler_finish(
    struct buffer *stdout_buf,
    struct tail_perf_regs_codeword_sampler *sampler,
    const char *phase) {
    const char *output_path = A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_OUTPUT_PATH;
    struct stat st;
    int exit_code = -1;
    int signal_no = 0;
    int wait_rc = 0;
    int stat_errno = 0;
    bool timed_out = false;
    long elapsed = sampler->started ? monotonic_ms() - sampler->started_ms : 0;

    if (!sampler->started) {
        return append_format(stdout_buf,
                             "tail_perf_regs_codeword_sampler.finish.%s.started=0\n"
                             "tail_perf_regs_codeword_sampler.finish.%s.wait_rc=0\n"
                             "tail_perf_regs_codeword_sampler.finish.%s.reason=not-started\n",
                             phase,
                             phase,
                             phase);
    }
    wait_rc = wait_child_quiet(sampler->pid,
                               A90_WIFI_TEST_BOOT_TAIL_PERF_REGS_CODEWORD_WAIT_MS,
                               true,
                               &exit_code,
                               &signal_no,
                               &timed_out);
    if (stat(output_path, &st) < 0) {
        stat_errno = errno;
        memset(&st, 0, sizeof(st));
    }
    return append_format(stdout_buf,
                         "tail_perf_regs_codeword_sampler.finish.%s.started=1\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.pid=%ld\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.wait_rc=%d\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.exit_code=%d\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.signal=%d\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.timed_out=%d\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.elapsed_ms=%ld\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.output_exists=%d\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.output_size=%ld\n"
                         "tail_perf_regs_codeword_sampler.finish.%s.output_errno=%d\n",
                         phase,
                         phase,
                         (long)sampler->pid,
                         phase,
                         wait_rc,
                         phase,
                         exit_code,
                         phase,
                         signal_no,
                         phase,
                         timed_out ? 1 : 0,
                         phase,
                         elapsed,
                         phase,
                         stat_errno == 0 ? 1 : 0,
                         phase,
                         stat_errno == 0 ? (long)st.st_size : 0L,
                         phase,
                         stat_errno);
}
#endif

static bool text_contains_any(const char *text, const char *a, const char *b, const char *c) {
    return (a != NULL && strstr(text, a) != NULL) ||
           (b != NULL && strstr(text, b) != NULL) ||
           (c != NULL && strstr(text, c) != NULL);
}

static int append_external_ping_output_summary(struct buffer *stdout_buf,
                                               const char *path,
                                               int ping_exit) {
    char text[4096];
    int err_no = 0;
    bool present;
    bool bytes_from;
    bool bad_address;
    bool unknown_host;
    bool network_unreachable;
    bool permission_denied;
    bool sendto_error;
    bool zero_received;
    bool packet_loss_100;
    const char *classifier;

    if (read_small_file_trim(path, text, sizeof(text)) < 0) {
        err_no = errno;
        text[0] = '\0';
    }
    present = err_no == 0 && text[0] != '\0';
    bytes_from = text_contains_any(text, "bytes from", "bytes_from", NULL);
    bad_address = text_contains_any(text, "bad address", "Name or service not known", "Temporary failure in name resolution");
    unknown_host = text_contains_any(text, "unknown host", "Unknown host", "No address associated");
    network_unreachable = text_contains_any(text, "Network is unreachable", "network is unreachable", "No route to host");
    permission_denied = text_contains_any(text, "Permission denied", "permission denied", "Operation not permitted");
    sendto_error = text_contains_any(text, "sendto", "sendmsg", "transmit failed");
    zero_received = text_contains_any(text, "0 packets received", "0 received", "0% packet loss") && !bytes_from;
    packet_loss_100 = text_contains_any(text, "100% packet loss", "100% loss", NULL);
    if (ping_exit == 0 || bytes_from) {
        classifier = "icmp-reply";
    } else if (bad_address || unknown_host) {
        classifier = "dns-resolution-failed";
    } else if (network_unreachable) {
        classifier = "network-unreachable";
    } else if (permission_denied) {
        classifier = "permission-denied";
    } else if (sendto_error) {
        classifier = "sendto-error";
    } else if (zero_received || packet_loss_100) {
        classifier = "icmp-no-reply";
    } else if (!present) {
        classifier = "no-output";
    } else {
        classifier = "unknown-output";
    }
    return append_format(stdout_buf,
                         "wifi_connect_ping.external_ping_output.path=%s\n"
                         "wifi_connect_ping.external_ping_output.present=%d\n"
                         "wifi_connect_ping.external_ping_output.errno=%d\n"
                         "wifi_connect_ping.external_ping_output.bytes_from=%d\n"
                         "wifi_connect_ping.external_ping_output.bad_address=%d\n"
                         "wifi_connect_ping.external_ping_output.unknown_host=%d\n"
                         "wifi_connect_ping.external_ping_output.network_unreachable=%d\n"
                         "wifi_connect_ping.external_ping_output.permission_denied=%d\n"
                         "wifi_connect_ping.external_ping_output.sendto_error=%d\n"
                         "wifi_connect_ping.external_ping_output.zero_received=%d\n"
                         "wifi_connect_ping.external_ping_output.packet_loss_100=%d\n"
                         "wifi_connect_ping.external_ping_output.classifier=%s\n",
                         path,
                         present ? 1 : 0,
                         err_no,
                         bytes_from ? 1 : 0,
                         bad_address ? 1 : 0,
                         unknown_host ? 1 : 0,
                         network_unreachable ? 1 : 0,
                         permission_denied ? 1 : 0,
                         sendto_error ? 1 : 0,
                         zero_received ? 1 : 0,
                         packet_loss_100 ? 1 : 0,
                         classifier);
}

static int append_resolv_conf_summary(struct buffer *stdout_buf) {
    struct stat st;
    char text[2048];
    int err_no = 0;
    int nameserver_count = 0;
    char *cursor;

    if (stat("/etc/resolv.conf", &st) < 0) {
        err_no = errno;
        memset(&st, 0, sizeof(st));
        text[0] = '\0';
    } else if (read_small_file_trim("/etc/resolv.conf", text, sizeof(text)) < 0) {
        err_no = errno;
        text[0] = '\0';
    }
    cursor = text;
    while ((cursor = strstr(cursor, "nameserver")) != NULL) {
        nameserver_count++;
        cursor += strlen("nameserver");
    }
    return append_format(stdout_buf,
                         "wifi_connect_ping.resolv_conf.present=%d\n"
                         "wifi_connect_ping.resolv_conf.errno=%d\n"
                         "wifi_connect_ping.resolv_conf.size=%lld\n"
                         "wifi_connect_ping.resolv_conf.nameserver_count=%d\n",
                         err_no == 0 ? 1 : 0,
                         err_no,
                         (long long)st.st_size,
                         nameserver_count);
}

static int create_android_wpa_control_socket_at(const char *dir_path, const char *socket_path) {
    int fd;
    int flags;
    struct sockaddr_un addr;
    size_t path_len;

    if (mkdir_p(dir_path, 0755) < 0) {
        return -1;
    }
    if (unlink(socket_path) < 0 && errno != ENOENT) {
        return -1;
    }
    fd = socket(AF_UNIX, SOCK_DGRAM | SOCK_CLOEXEC, 0);
    if (fd < 0) {
        return -1;
    }
    memset(&addr, 0, sizeof(addr));
    addr.sun_family = AF_UNIX;
    path_len = strlen(socket_path);
    if (path_len >= sizeof(addr.sun_path)) {
        close(fd);
        errno = ENAMETOOLONG;
        return -1;
    }
    memcpy(addr.sun_path, socket_path, path_len + 1U);
    if (bind(fd,
             (const struct sockaddr *)&addr,
             (socklen_t)(offsetof(struct sockaddr_un, sun_path) + path_len + 1U)) < 0) {
        int saved_errno = errno;

        close(fd);
        errno = saved_errno;
        return -1;
    }
    if (chown(socket_path, A90_AID_WIFI, A90_AID_WIFI) < 0 ||
        chmod(socket_path, 0660) < 0) {
        int saved_errno = errno;

        close(fd);
        errno = saved_errno;
        return -1;
    }
    flags = fcntl(fd, F_GETFD, 0);
    if (flags < 0 || fcntl(fd, F_SETFD, flags & ~FD_CLOEXEC) < 0) {
        int saved_errno = errno;

        close(fd);
        errno = saved_errno;
        return -1;
    }
    return fd;
}

static void emit_android_wpa_socket_preexec_probe(int fd, const char *phase) {
    const char *env_value = getenv("ANDROID_SOCKET_wpa_wlan0");
    int fd_flags = -1;
    int fl_flags = -1;
    int so_type = -1;
    int fd_errno = 0;
    int fl_errno = 0;
    int so_errno = 0;
    int name_errno = 0;
    int parsed_fd = -1;
    struct sockaddr_un addr;
    socklen_t addr_len = sizeof(addr);
    socklen_t so_len = sizeof(so_type);
    char sun_path[sizeof(addr.sun_path) + 1U];

    memset(&addr, 0, sizeof(addr));
    memset(sun_path, 0, sizeof(sun_path));
    if (env_value != NULL) {
        parsed_fd = atoi(env_value);
    }
    errno = 0;
    fd_flags = fcntl(fd, F_GETFD, 0);
    if (fd_flags < 0) {
        fd_errno = errno;
    }
    errno = 0;
    fl_flags = fcntl(fd, F_GETFL, 0);
    if (fl_flags < 0) {
        fl_errno = errno;
    }
    errno = 0;
    if (getsockopt(fd, SOL_SOCKET, SO_TYPE, &so_type, &so_len) < 0) {
        so_errno = errno;
    }
    errno = 0;
    if (getsockname(fd, (struct sockaddr *)&addr, &addr_len) < 0) {
        name_errno = errno;
    } else if (addr.sun_family == AF_UNIX) {
        size_t copy_len = sizeof(addr.sun_path);

        if (addr_len > offsetof(struct sockaddr_un, sun_path)) {
            copy_len = (size_t)(addr_len - offsetof(struct sockaddr_un, sun_path));
            if (copy_len > sizeof(addr.sun_path)) {
                copy_len = sizeof(addr.sun_path);
            }
        }
        memcpy(sun_path, addr.sun_path, copy_len);
        sun_path[sizeof(sun_path) - 1U] = '\0';
    }
    dprintf(STDOUT_FILENO,
            "wifi_connect_ping.supplicant_preexec.android_socket.phase=%s\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.env_present=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.env_fd=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.fd=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.fd_flags=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.fd_errno=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.fl_flags=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.fl_errno=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.so_type=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.so_errno=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.getsockname_errno=%d\n"
            "wifi_connect_ping.supplicant_preexec.android_socket.sun_path=%s\n",
            phase != NULL ? phase : "unknown",
            env_value != NULL ? 1 : 0,
            parsed_fd,
            fd,
            fd_flags,
            fd_errno,
            fl_flags,
            fl_errno,
            so_type,
            so_errno,
            name_errno,
            sun_path[0] != '\0' ? sun_path : "none");
}

