static int append_macloader_mac_source_path_snapshot(struct buffer *buf,
                                                     const struct paths *paths,
                                                     const char *prefix,
                                                     const char *label,
                                                     const char *absolute_path) {
    char host_path[MAX_PATH_LEN];
    struct stat st;
    struct statfs sfs;
    uint64_t hash = 0;
    size_t bytes = 0;
    int stat_errno = 0;
    int statfs_errno = 0;
    bool exists = false;
    bool is_reg = false;
    bool is_dir = false;
    bool readable = false;
    bool writable = false;
    bool hashed = false;
    bool statfs_ok = false;

    if (path_in_root(host_path, sizeof(host_path), paths, absolute_path) < 0) {
        return append_format(buf,
                             "%s.%s.absolute=%s\n"
                             "%s.%s.host_path=<path-too-long>\n"
                             "%s.%s.exists=0\n"
                             "%s.%s.errno=%d\n",
                             prefix,
                             label,
                             absolute_path,
                             prefix,
                             label,
                             prefix,
                             label,
                             prefix,
                             label,
                             errno);
    }
    if (stat(host_path, &st) == 0) {
        exists = true;
        is_reg = S_ISREG(st.st_mode);
        is_dir = S_ISDIR(st.st_mode);
        readable = access(host_path, R_OK) == 0;
        writable = access(host_path, W_OK) == 0;
        if (statfs(host_path, &sfs) == 0) {
            statfs_ok = true;
        } else {
            statfs_errno = errno;
            memset(&sfs, 0, sizeof(sfs));
        }
        if (is_reg && readable && fnv1a64_file(host_path, &hash, &bytes) == 0) {
            hashed = true;
        }
    } else {
        stat_errno = errno;
        memset(&st, 0, sizeof(st));
        memset(&sfs, 0, sizeof(sfs));
    }
    return append_format(buf,
                         "%s.%s.absolute=%s\n"
                         "%s.%s.host_path=%s\n"
                         "%s.%s.exists=%d\n"
                         "%s.%s.is_reg=%d\n"
                         "%s.%s.is_dir=%d\n"
                         "%s.%s.mode=%04o\n"
                         "%s.%s.uid=%lld\n"
                         "%s.%s.gid=%lld\n"
                         "%s.%s.size=%lld\n"
                         "%s.%s.readable=%d\n"
                         "%s.%s.writable=%d\n"
                         "%s.%s.statfs_ok=%d\n"
                         "%s.%s.fs_type=0x%016llx\n"
                         "%s.%s.fs_bsize=%ld\n"
                         "%s.%s.statfs_errno=%d\n"
                         "%s.%s.hash_available=%d\n"
                         "%s.%s.bytes=%zu\n"
                         "%s.%s.hash=0x%016llx\n"
                         "%s.%s.errno=%d\n",
                         prefix,
                         label,
                         absolute_path,
                         prefix,
                         label,
                         host_path,
                         prefix,
                         label,
                         exists ? 1 : 0,
                         prefix,
                         label,
                         is_reg ? 1 : 0,
                         prefix,
                         label,
                         is_dir ? 1 : 0,
                         prefix,
                         label,
                         exists ? (unsigned int)(st.st_mode & 07777) : 0U,
                         prefix,
                         label,
                         exists ? (long long)st.st_uid : -1LL,
                         prefix,
                         label,
                         exists ? (long long)st.st_gid : -1LL,
                         prefix,
                         label,
                         exists ? (long long)st.st_size : 0LL,
                         prefix,
                         label,
                         readable ? 1 : 0,
                         prefix,
                         label,
                         writable ? 1 : 0,
                         prefix,
                         label,
                         statfs_ok ? 1 : 0,
                         prefix,
                         label,
                         (unsigned long long)sfs.f_type,
                         prefix,
                         label,
                         (long)sfs.f_bsize,
                         prefix,
                         label,
                         statfs_errno,
                         prefix,
                         label,
                         hashed ? 1 : 0,
                         prefix,
                         label,
                         hashed ? bytes : 0U,
                         prefix,
                         label,
                         (unsigned long long)(hashed ? hash : 0),
                         prefix,
                         label,
                         stat_errno);
}

