static void cnss_nonlog_maps_summary_init(struct cnss_nonlog_maps_summary *summary) {
    memset(summary, 0, sizeof(*summary));
}

static int collect_cnss_nonlog_maps_summary(pid_t pid, struct cnss_nonlog_maps_summary *summary) {
    char path[MAX_PATH_LEN];
    char line[1024];
    FILE *file;

    cnss_nonlog_maps_summary_init(summary);
    proc_path(path, sizeof(path), pid, "maps");
    file = fopen(path, "re");
    if (file == NULL) {
        return -1;
    }
    summary->open_ok = true;
    while (fgets(line, sizeof(line), file) != NULL) {
        unsigned long long start = 0;
        unsigned long long end = 0;
        unsigned long long offset = 0;
        char perms[8] = {0};
        char mapped_path[512] = {0};
        int parsed;

        summary->line_count++;
        parsed = sscanf(line, "%llx-%llx %7s %llx %*s %*s %511s",
                        &start,
                        &end,
                        perms,
                        &offset,
                        mapped_path);
        if (parsed < 5 || strstr(mapped_path, "/vendor/bin/cnss-daemon") == NULL) {
            continue;
        }
        summary->path_seen = true;
        if (strchr(perms, 'x') == NULL) {
            continue;
        }
        summary->text_seen = true;
        summary->text_start = start;
        summary->text_end = end;
        summary->text_offset = offset;
        summary->load_bias = start >= offset ? start - offset : 0;
        summary->wlfw_start_runtime_pc = summary->load_bias + 0xec00ULL;
        break;
    }
    fclose(file);
    return 0;
}

static int truncate_text_once_errno(const char *path) {
    int fd = open(path, O_WRONLY | O_TRUNC | O_CLOEXEC);
    int saved_errno;

    if (fd < 0) {
        return -errno;
    }
    if (close(fd) < 0) {
        saved_errno = errno;
        return -saved_errno;
    }
    return 0;
}

static bool tracefs_root_has_uprobes(const char *root) {
    char path[MAX_PATH_LEN];

    if (snprintf(path, sizeof(path), "%s/uprobe_events", root) >= (int)sizeof(path)) {
        return false;
    }
    return access(path, F_OK) == 0;
}

static int cnss_wlfw_uprobe_find_tracefs(struct cnss_wlfw_uprobe_state *state,
                                         const struct paths *paths) {
    const char *roots[4] = {0};
    size_t root_count = 0;

    if (paths != NULL && paths->sys_kernel_debug_tracing[0] != '\0') {
        roots[root_count++] = paths->sys_kernel_debug_tracing;
    }
    if (paths != NULL && paths->sys_kernel_tracing[0] != '\0') {
        roots[root_count++] = paths->sys_kernel_tracing;
    }
    roots[root_count++] = "/sys/kernel/debug/tracing";
    roots[root_count++] = "/sys/kernel/tracing";

    for (size_t i = 0; i < root_count; i++) {
        if (roots[i] != NULL && tracefs_root_has_uprobes(roots[i])) {
            snprintf(state->tracefs_path, sizeof(state->tracefs_path), "%s", roots[i]);
            return 0;
        }
    }
    state->tracefs_errno = ENOENT;
    return -1;
}

static int cnss_wlfw_uprobe_build_paths(struct cnss_wlfw_uprobe_state *state) {
    int needed;

    needed = snprintf(state->uprobe_events_path,
                      sizeof(state->uprobe_events_path),
                      "%s/uprobe_events",
                      state->tracefs_path);
    if (needed < 0 || needed >= (int)sizeof(state->uprobe_events_path)) {
        errno = ENAMETOOLONG;
        return -1;
    }
    needed = snprintf(state->trace_path,
                      sizeof(state->trace_path),
                      "%s/trace",
                      state->tracefs_path);
    if (needed < 0 || needed >= (int)sizeof(state->trace_path)) {
        errno = ENAMETOOLONG;
        return -1;
    }
    for (size_t i = 0; i < A90_CNSS_WLFW_UPROBE_EVENT_COUNT; i++) {
        needed = snprintf(state->events[i].enable_path,
                          sizeof(state->events[i].enable_path),
                          "%s/events/a90cnss/%s/enable",
                          state->tracefs_path,
                          cnss_wlfw_uprobe_events[i].name);
        if (needed < 0 || needed >= (int)sizeof(state->events[i].enable_path)) {
            errno = ENAMETOOLONG;
            return -1;
        }
    }
    snprintf(state->enable_path,
             sizeof(state->enable_path),
             "%s",
             state->events[CNSS_WLFW_UPROBE_WLFW_START].enable_path);
    needed = snprintf(state->tracing_on_path,
                      sizeof(state->tracing_on_path),
                      "%s/tracing_on",
                      state->tracefs_path);
    if (needed < 0 || needed >= (int)sizeof(state->tracing_on_path)) {
        errno = ENAMETOOLONG;
        return -1;
    }
    return 0;
}

static void cnss_wlfw_uprobe_sync_legacy_fields(struct cnss_wlfw_uprobe_state *state) {
    struct cnss_wlfw_uprobe_event_state *event = &state->events[CNSS_WLFW_UPROBE_WLFW_START];

    state->stale_cleanup_attempted = event->stale_cleanup_attempted;
    state->stale_cleanup_rc = event->stale_cleanup_rc;
    state->register_attempted = event->register_attempted;
    state->register_rc = event->register_rc;
    state->registered = event->registered;
    state->enable_attempted = event->enable_attempted;
    state->enable_rc = event->enable_rc;
    state->enabled = event->enabled;
    state->disable_rc = event->disable_rc;
    state->cleanup_rc = event->cleanup_rc;
    state->hit_count = event->hit_count;
    snprintf(state->first_hit_line,
             sizeof(state->first_hit_line),
             "%s",
             event->first_hit_line[0] != '\0' ? event->first_hit_line : "");
}

static void cnss_wlfw_uprobe_probe_target(struct cnss_wlfw_uprobe_target_probe *probe,
                                          const char *path) {
    struct stat st;

    memset(probe, 0, sizeof(*probe));
    probe->access_rc = -ENOENT;
    probe->access_errno = ENOENT;
    probe->stat_rc = -ENOENT;
    probe->stat_errno = ENOENT;
    if (path == NULL || path[0] == '\0') {
        return;
    }
    snprintf(probe->path, sizeof(probe->path), "%s", path);
    if (access(path, R_OK) == 0) {
        probe->access_rc = 0;
        probe->access_errno = 0;
    } else {
        probe->access_rc = -errno;
        probe->access_errno = errno;
    }
    if (stat(path, &st) == 0) {
        probe->stat_rc = 0;
        probe->stat_errno = 0;
        probe->st_mode = (unsigned long long)st.st_mode;
        probe->st_size = (unsigned long long)st.st_size;
    } else {
        probe->stat_rc = -errno;
        probe->stat_errno = errno;
    }
}

static void cnss_wlfw_uprobe_select_target(struct cnss_wlfw_uprobe_state *state,
                                           const struct paths *paths) {
    char namespace_vendor_target[MAX_PATH_LEN] = {0};
    static const char *const fallback_targets[] = {
        "/mnt/vendor/bin/cnss-daemon",
        "/vendor/bin/cnss-daemon",
    };
    const char *candidates[A90_CNSS_WLFW_UPROBE_TARGET_COUNT] = {0};

    state->selected_target_index = -1;
    if (paths != NULL && paths->vendor[0] != '\0') {
        if (snprintf(namespace_vendor_target,
                     sizeof(namespace_vendor_target),
                     "%s/bin/cnss-daemon",
                     paths->vendor) >= (int)sizeof(namespace_vendor_target)) {
            namespace_vendor_target[0] = '\0';
        }
    }
    candidates[0] = namespace_vendor_target[0] != '\0' ? namespace_vendor_target : NULL;
    candidates[1] = fallback_targets[0];
    candidates[2] = fallback_targets[1];

    for (int i = 0; i < A90_CNSS_WLFW_UPROBE_TARGET_COUNT; i++) {
        cnss_wlfw_uprobe_probe_target(&state->targets[i], candidates[i]);
        if (state->selected_target_index < 0 &&
            state->targets[i].access_rc == 0 &&
            state->targets[i].stat_rc == 0 &&
            S_ISREG((mode_t)state->targets[i].st_mode)) {
            state->selected_target_index = i;
            snprintf(state->selected_target_path,
                     sizeof(state->selected_target_path),
                     "%s",
                     state->targets[i].path);
        }
    }
    if (state->selected_target_index < 0 && state->targets[0].path[0] != '\0') {
        state->selected_target_index = 0;
        snprintf(state->selected_target_path,
                 sizeof(state->selected_target_path),
                 "%s",
                 state->targets[0].path);
    }
}

static void cnss_wlfw_uprobe_cleanup_state(struct cnss_wlfw_uprobe_state *state) {
    if (!state->arm_attempted || state->cleanup_done) {
        return;
    }
    state->cleanup_attempted = true;
    for (size_t i = 0; i < A90_CNSS_WLFW_UPROBE_EVENT_COUNT; i++) {
        struct cnss_wlfw_uprobe_event_state *event = &state->events[i];
        char cleanup_line[96];

        if (event->enabled && event->enable_path[0] != '\0') {
            event->disable_rc = write_text_once_errno(event->enable_path, "0\n");
        }
        if (event->registered && state->uprobe_events_path[0] != '\0') {
            snprintf(cleanup_line,
                     sizeof(cleanup_line),
                     "-:a90cnss/%s\n",
                     cnss_wlfw_uprobe_events[i].name);
            event->cleanup_rc = write_text_once_errno(state->uprobe_events_path, cleanup_line);
        }
    }
    if (state->original_tracing_on_seen && state->tracing_on_path[0] != '\0') {
        char restore[32];

        snprintf(restore, sizeof(restore), "%s\n", state->original_tracing_on);
        state->restore_tracing_on_rc = write_text_once_errno(state->tracing_on_path, restore);
    }
    cnss_wlfw_uprobe_sync_legacy_fields(state);
    state->cleanup_done = true;
}

static void cnss_wlfw_uprobe_cleanup_atexit(void) {
    cnss_wlfw_uprobe_cleanup_state(&g_cnss_wlfw_uprobe_state);
}

