static int build_phase_label(char *out, size_t out_size, const char *phase, const char *suffix) {
    int rc = snprintf(out, out_size, "wifi_icnss_edge_%s_%s", phase, suffix);

    if (rc < 0 || (size_t)rc >= out_size) {
        errno = ENAMETOOLONG;
        return -1;
    }
    return 0;
}

