static int count_dir_entries_matching(const char *path,
                                      const char *needle,
                                      int *count,
                                      bool *matched) {
    DIR *dir;
    struct dirent *entry;

    *count = 0;
    *matched = false;
    dir = opendir(path);
    if (dir == NULL) {
        return -1;
    }
    while ((entry = readdir(dir)) != NULL) {
        if (strcmp(entry->d_name, ".") == 0 || strcmp(entry->d_name, "..") == 0) {
            continue;
        }
        (*count)++;
        if (needle != NULL && strstr(entry->d_name, needle) != NULL) {
            *matched = true;
        }
    }
    closedir(dir);
    return 0;
}

static void read_state_or_error(const char *path, char *out, size_t out_size) {
    int saved_errno;

    if (read_small_file_trim(path, out, out_size) == 0) {
        return;
    }
    saved_errno = errno;
    snprintf(out, out_size, "error:%s", strerror(saved_errno));
}

static int dir_count_or_minus_one(const char *path) {
    int count = -1;
    bool matched = false;

    if (count_dir_entries_matching(path, NULL, &count, &matched) < 0) {
        return -1;
    }
    return count;
}

struct mdm_status_irq_snapshot {
    bool present;
    bool parsed;
    int saved_errno;
    int irq;
    int gpio;
    unsigned long count_total;
    char controller[64];
    char trigger[64];
    char name[128];
    char line[512];
};

static bool parse_mdm_status_irq_line(const char *line, struct mdm_status_irq_snapshot *snapshot) {
    char copy[512];
    char *colon;
    char *token;
    char *saveptr = NULL;
    char *endptr;
    char *gpio_token;
    char *trigger_token;
    char *name_token;
    unsigned long value;
    unsigned long gpio_value;

    snprintf(copy, sizeof(copy), "%s", line);
    colon = strchr(copy, ':');
    if (colon == NULL) {
        return false;
    }
    *colon = '\0';
    errno = 0;
    value = strtoul(copy, &endptr, 10);
    if (errno != 0 || endptr == copy) {
        return false;
    }
    snapshot->irq = (int)value;

    token = strtok_r(colon + 1, " \t\r\n", &saveptr);
    while (token != NULL) {
        errno = 0;
        value = strtoul(token, &endptr, 10);
        if (errno != 0 || endptr == token || *endptr != '\0') {
            break;
        }
        snapshot->count_total += value;
        token = strtok_r(NULL, " \t\r\n", &saveptr);
    }
    if (token == NULL) {
        return false;
    }
    snprintf(snapshot->controller, sizeof(snapshot->controller), "%s", token);

    gpio_token = strtok_r(NULL, " \t\r\n", &saveptr);
    trigger_token = strtok_r(NULL, " \t\r\n", &saveptr);
    if (gpio_token == NULL || trigger_token == NULL) {
        return false;
    }
    errno = 0;
    gpio_value = strtoul(gpio_token, &endptr, 10);
    if (errno != 0 || endptr == gpio_token || *endptr != '\0') {
        return false;
    }
    snapshot->gpio = (int)gpio_value;
    snprintf(snapshot->trigger, sizeof(snapshot->trigger), "%s", trigger_token);
    name_token = saveptr;
    while (name_token != NULL && (*name_token == ' ' || *name_token == '\t')) {
        name_token++;
    }
    snprintf(snapshot->name, sizeof(snapshot->name), "%s", name_token != NULL ? name_token : "");
    sanitize_one_line(snapshot->name);
    return true;
}

static struct mdm_status_irq_snapshot collect_mdm_irq_snapshot_by_name(const char *needle) {
    struct mdm_status_irq_snapshot snapshot;
    FILE *file;
    char line[512];

    memset(&snapshot, 0, sizeof(snapshot));
    snapshot.irq = -1;
    snapshot.gpio = -1;
    file = fopen("/proc/interrupts", "re");
    if (file == NULL) {
        snapshot.saved_errno = errno;
        return snapshot;
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        if (needle == NULL || strstr(line, needle) == NULL) {
            continue;
        }
        snapshot.present = true;
        snprintf(snapshot.line, sizeof(snapshot.line), "%s", line);
        sanitize_one_line(snapshot.line);
        snapshot.parsed = parse_mdm_status_irq_line(line, &snapshot);
        break;
    }
    fclose(file);
    return snapshot;
}

static struct mdm_status_irq_snapshot collect_mdm_status_irq_snapshot(void) {
    return collect_mdm_irq_snapshot_by_name("mdm status");
}

static struct mdm_status_irq_snapshot collect_mdm_errfatal_irq_snapshot(void) {
    return collect_mdm_irq_snapshot_by_name("mdm errfatal");
}

static int append_wlan_pd_post_pm_lower_state_sample(struct buffer *buf,
                                                     const char *phase,
                                                     int sample_index) {
    char mss_state[64];
    char mss_crash_count[64];
    char mdm3_state[64];
    char mdm3_crash_count[64];
    char label[96];
    struct mdm_status_irq_snapshot mdm_status = collect_mdm_status_irq_snapshot();
    struct mdm_status_irq_snapshot mdm_errfatal = collect_mdm_errfatal_irq_snapshot();
    int pci_devices = dir_count_or_minus_one("/sys/bus/pci/devices");
    int mhi_devices = dir_count_or_minus_one("/sys/bus/mhi/devices");
    int rpmsg_devices = dir_count_or_minus_one("/sys/bus/rpmsg/devices");
    int msm_subsys_devices = dir_count_or_minus_one("/sys/bus/msm_subsys/devices");
    int mhi_pipe_exists = access("/dev/mhi_0305_01.01.00_pipe_10", F_OK) == 0 ? 1 : 0;
    int wlan0_exists = access("/sys/class/net/wlan0", F_OK) == 0 ? 1 : 0;

    read_state_or_error("/sys/devices/platform/soc/4080000.qcom,mss/subsys0/state",
                        mss_state,
                        sizeof(mss_state));
    read_state_or_error("/sys/devices/platform/soc/4080000.qcom,mss/subsys0/crash_count",
                        mss_crash_count,
                        sizeof(mss_crash_count));
    read_state_or_error("/sys/devices/platform/soc/soc:qcom,mdm3/subsys9/state",
                        mdm3_state,
                        sizeof(mdm3_state));
    read_state_or_error("/sys/devices/platform/soc/soc:qcom,mdm3/subsys9/crash_count",
                        mdm3_crash_count,
                        sizeof(mdm3_crash_count));
    if (snprintf(label,
                 sizeof(label),
                 "%s.sample_%02d",
                 phase,
                 sample_index) >= (int)sizeof(label)) {
        return append_format(buf,
                             "wlan_pd_post_pm_lower_state_observer.%s.error=label-too-long\n",
                             phase);
    }
    return append_format(buf,
                         "wlan_pd_post_pm_lower_state_observer.%s.begin=1\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.monotonic_ms=%ld\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mss_state=%s\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mss_crash_count=%s\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm3_state=%s\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm3_crash_count=%s\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_status_irq_present=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_status_irq_parsed=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_status_irq_total=%lu\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_errfatal_irq_present=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_errfatal_irq_parsed=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mdm_errfatal_irq_total=%lu\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.pci_device_count=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mhi_device_count=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.rpmsg_device_count=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.msm_subsys_device_count=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.mhi_pipe_exists=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.wlan0_exists=%d\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.no_esoc0_open=1\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.no_fake_online=1\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.no_pmic_gpio_gdsc_write=1\n"
                         "wlan_pd_post_pm_lower_state_observer.%s.end=1\n",
                         label,
                         label,
                         monotonic_ms(),
                         label,
                         mss_state,
                         label,
                         mss_crash_count,
                         label,
                         mdm3_state,
                         label,
                         mdm3_crash_count,
                         label,
                         mdm_status.present ? 1 : 0,
                         label,
                         mdm_status.parsed ? 1 : 0,
                         label,
                         mdm_status.count_total,
                         label,
                         mdm_errfatal.present ? 1 : 0,
                         label,
                         mdm_errfatal.parsed ? 1 : 0,
                         label,
                         mdm_errfatal.count_total,
                         label,
                         pci_devices,
                         label,
                         mhi_devices,
                         label,
                         rpmsg_devices,
                         label,
                         msm_subsys_devices,
                         label,
                         mhi_pipe_exists,
                         label,
                         wlan0_exists,
                         label,
                         label,
                         label,
                         label);
}

static int append_wlan_pd_post_pm_lower_state_observer(struct buffer *buf,
                                                       const char *phase,
                                                       int sample_count,
                                                       int interval_ms) {
    if (append_format(buf,
                      "wlan_pd_post_pm_lower_state_observer.%s.begin=1\n"
                      "wlan_pd_post_pm_lower_state_observer.%s.sample_count=%d\n"
                      "wlan_pd_post_pm_lower_state_observer.%s.interval_ms=%d\n"
                      "wlan_pd_post_pm_lower_state_observer.%s.no_esoc0_open=1\n"
                      "wlan_pd_post_pm_lower_state_observer.%s.no_fake_online=1\n"
                      "wlan_pd_post_pm_lower_state_observer.%s.no_pmic_gpio_gdsc_write=1\n",
                      phase,
                      phase,
                      sample_count,
                      phase,
                      interval_ms,
                      phase,
                      phase,
                      phase) < 0) {
        return -1;
    }
    for (int i = 0; i < sample_count; i++) {
        if (i > 0 && interval_ms > 0) {
            usleep((useconds_t)interval_ms * 1000U);
        }
        if (append_wlan_pd_post_pm_lower_state_sample(buf, phase, i) < 0) {
            return -1;
        }
    }
    return append_format(buf,
                         "wlan_pd_post_pm_lower_state_observer.%s.end=1\n",
                         phase);
}

static bool line_contains_any(const char *line,
                              const char *needle_a,
                              const char *needle_b,
                              const char *needle_c) {
    return (needle_a != NULL && strstr(line, needle_a) != NULL) ||
           (needle_b != NULL && strstr(line, needle_b) != NULL) ||
           (needle_c != NULL && strstr(line, needle_c) != NULL);
}

static bool read_first_matching_line_with_source(const char *path,
                                                 const char *needle_a,
                                                 const char *needle_b,
                                                 const char *needle_c,
                                                 char *out,
                                                 size_t out_size,
                                                 char *source,
                                                 size_t source_size);
static bool read_pinctrl_line_with_source(const char *needle_a,
                                          const char *needle_b,
                                          const char *needle_c,
                                          char *out,
                                          size_t out_size,
                                          char *source,
                                          size_t source_size);

static void append_sanitized_block_line(char *out,
                                        size_t out_size,
                                        size_t *used,
                                        const char *line) {
    if (out_size == 0 || *used >= out_size - 1U) {
        return;
    }
    if (*used > 0) {
        const char *sep = " | ";
        while (*sep != '\0' && *used < out_size - 1U) {
            out[(*used)++] = *sep++;
        }
    }
    for (size_t i = 0; line[i] != '\0' && *used < out_size - 1U; i++) {
        unsigned char ch = (unsigned char)line[i];

        if (ch == '\n' || ch == '\r') {
            break;
        }
        out[(*used)++] = (ch < 0x20 || ch > 0x7e) ? '?' : (char)ch;
    }
    out[*used] = '\0';
}

static bool read_matching_block_with_source(const char *path,
                                            const char *needle_a,
                                            const char *needle_b,
                                            const char *needle_c,
                                            int after_lines,
                                            char *out,
                                            size_t out_size,
                                            char *source,
                                            size_t source_size) {
    FILE *file;
    char line[512];
    bool capturing = false;
    int remaining = 0;
    size_t used = 0;

    if (out_size == 0) {
        return false;
    }
    out[0] = '\0';
    if (source_size > 0) {
        source[0] = '\0';
    }
    file = fopen(path, "re");
    if (file == NULL) {
        return false;
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        if (!capturing) {
            if (!line_contains_any(line, needle_a, needle_b, needle_c)) {
                continue;
            }
            capturing = true;
            remaining = after_lines;
            if (source_size > 0) {
                snprintf(source, source_size, "%s", path);
                sanitize_one_line(source);
            }
            append_sanitized_block_line(out, out_size, &used, line);
            if (remaining <= 0) {
                break;
            }
            continue;
        }
        append_sanitized_block_line(out, out_size, &used, line);
        remaining--;
        if (remaining <= 0) {
            break;
        }
    }
    fclose(file);
    return capturing;
}

static bool read_block_from_files_with_source(const char * const *files,
                                              const char *needle_a,
                                              const char *needle_b,
                                              const char *needle_c,
                                              int after_lines,
                                              char *out,
                                              size_t out_size,
                                              char *source,
                                              size_t source_size) {
    for (size_t i = 0; files[i] != NULL; i++) {
        if (read_matching_block_with_source(files[i],
                                            needle_a,
                                            needle_b,
                                            needle_c,
                                            after_lines,
                                            out,
                                            out_size,
                                            source,
                                            source_size)) {
            return true;
        }
    }
    return false;
}

static bool read_first_matching_line_with_source(const char *path,
                                                 const char *needle_a,
                                                 const char *needle_b,
                                                 const char *needle_c,
                                                 char *out,
                                                 size_t out_size,
                                                 char *source,
                                                 size_t source_size) {
    FILE *file;
    char line[512];

    if (out_size == 0) {
        return false;
    }
    out[0] = '\0';
    if (source_size > 0) {
        source[0] = '\0';
    }
    file = fopen(path, "re");
    if (file == NULL) {
        return false;
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        if (!line_contains_any(line, needle_a, needle_b, needle_c)) {
            continue;
        }
        snprintf(out, out_size, "%s", line);
        sanitize_one_line(out);
        if (source_size > 0) {
            snprintf(source, source_size, "%s", path);
            sanitize_one_line(source);
        }
        fclose(file);
        return true;
    }
    fclose(file);
    return false;
}

