static int append_pmic_soft_reset_preflight(struct buffer *buf, const struct config *cfg) {
    struct mdm_status_irq_snapshot irq = collect_mdm_status_irq_snapshot();
    struct stat st;
    char mdm3_state[64];
    char mdm3_crash_count[64];
    char pmic_soft_reset_line[512];
    char pmic_soft_reset_source[MAX_PATH_LEN];
    char pcie1_gdsc_line[512];
    char pcie1_gdsc_source[MAX_PATH_LEN];
    char pcie0_gdsc_line[512];
    char pcie0_gdsc_source[MAX_PATH_LEN];
    bool gpio9_class_exists = lstat("/sys/class/gpio/gpio9", &st) == 0;
    bool gpio135_class_exists = lstat("/sys/class/gpio/gpio135", &st) == 0;
    bool gpio142_class_exists = lstat("/sys/class/gpio/gpio142", &st) == 0;
    bool debugfs_pinctrl_present = lstat("/sys/kernel/debug/pinctrl", &st) == 0;
    bool debugfs_regulator_present =
        lstat("/sys/kernel/debug/regulator/regulator_summary", &st) == 0 ||
        lstat("/sys/kernel/debug/regulator_summary", &st) == 0;
    bool pmic_soft_reset_seen;
    bool pcie1_gdsc_seen;
    bool pcie0_gdsc_seen;
    bool pmic_soft_reset_mux_unclaimed;
    bool pcie1_gdsc_zero;
    bool pcie0_gdsc_zero;
    bool read_contract_ready;
    bool native_reproduction_candidate;
    const char *result;

    read_state_or_error("/sys/bus/msm_subsys/devices/subsys9/state",
                        mdm3_state,
                        sizeof(mdm3_state));
    read_state_or_error("/sys/bus/msm_subsys/devices/subsys9/crash_count",
                        mdm3_crash_count,
                        sizeof(mdm3_crash_count));
    pmic_soft_reset_seen = read_pmic_soft_reset_line(pmic_soft_reset_line,
                                                     sizeof(pmic_soft_reset_line),
                                                     pmic_soft_reset_source,
                                                     sizeof(pmic_soft_reset_source));
    pcie1_gdsc_seen = read_regulator_line("pcie_1_gdsc",
                                          pcie1_gdsc_line,
                                          sizeof(pcie1_gdsc_line),
                                          pcie1_gdsc_source,
                                          sizeof(pcie1_gdsc_source));
    pcie0_gdsc_seen = read_regulator_line("pcie_0_gdsc",
                                          pcie0_gdsc_line,
                                          sizeof(pcie0_gdsc_line),
                                          pcie0_gdsc_source,
                                          sizeof(pcie0_gdsc_source));
    if (!pmic_soft_reset_seen) {
        pmic_soft_reset_line[0] = '\0';
        pmic_soft_reset_source[0] = '\0';
    }
    if (!pcie1_gdsc_seen) {
        pcie1_gdsc_line[0] = '\0';
        pcie1_gdsc_source[0] = '\0';
    }
    if (!pcie0_gdsc_seen) {
        pcie0_gdsc_line[0] = '\0';
        pcie0_gdsc_source[0] = '\0';
    }

    pmic_soft_reset_mux_unclaimed =
        pmic_soft_reset_seen && strstr(pmic_soft_reset_line, "MUX UNCLAIMED") != NULL;
    pcie1_gdsc_zero = pcie1_gdsc_seen && strstr(pcie1_gdsc_line, "0mV") != NULL;
    pcie0_gdsc_zero = pcie0_gdsc_seen && strstr(pcie0_gdsc_line, "0mV") != NULL;
    read_contract_ready =
        debugfs_pinctrl_present &&
        pmic_soft_reset_seen &&
        !gpio9_class_exists &&
        !gpio135_class_exists &&
        !gpio142_class_exists;
    native_reproduction_candidate =
        read_contract_ready &&
        pmic_soft_reset_mux_unclaimed &&
        pcie1_gdsc_zero &&
        pcie0_gdsc_zero;
    result = read_contract_ready ? "read-only-pass" : "read-only-incomplete";

    return append_format(buf,
                         "pmic_soft_reset_preflight.begin=1\n"
                         "pmic_soft_reset_preflight.helper_version=%s\n"
                         "pmic_soft_reset_preflight.mode=read-only-fail-closed\n"
                         "pmic_soft_reset_preflight.namespace=global\n"
                         "pmic_soft_reset_preflight.expected_dts_compatible=qcom,ext-sdx50m\n"
                         "pmic_soft_reset_preflight.expected_dts_ap2mdm_soft_reset_gpio=<0x3d 0x9 0x0>\n"
                         "pmic_soft_reset_preflight.expected_android_gpio_class_absent=1\n"
                         "pmic_soft_reset_preflight.expected_android_pmic_gpiochip=GPIOs 1263-1273\n"
                         "pmic_soft_reset_preflight.allow_preflight=%d\n"
                         "pmic_soft_reset_preflight.allow_write_flag_seen=%d\n"
                         "pmic_soft_reset_preflight.write_gate_implemented=0\n"
                         "pmic_soft_reset_preflight.mutation_attempted=0\n"
                         "pmic_soft_reset_preflight.write_blocked=1\n"
                         "pmic_soft_reset_preflight.esoc_ioctl_executed=0\n"
                         "pmic_soft_reset_preflight.pm_actor_executed=0\n"
                         "pmic_soft_reset_preflight.cnss_daemon_start_executed=0\n"
                         "pmic_soft_reset_preflight.wifi_hal_start_executed=0\n"
                         "pmic_soft_reset_preflight.scan_connect_linkup=0\n"
                         "pmic_soft_reset_preflight.credentials=0\n"
                         "pmic_soft_reset_preflight.dhcp_routing=0\n"
                         "pmic_soft_reset_preflight.external_ping=0\n"
                         "pmic_soft_reset_preflight.gpio_class.gpio9_exists=%d\n"
                         "pmic_soft_reset_preflight.gpio_class.gpio135_exists=%d\n"
                         "pmic_soft_reset_preflight.gpio_class.gpio142_exists=%d\n"
                         "pmic_soft_reset_preflight.debugfs_pinctrl_present=%d\n"
                         "pmic_soft_reset_preflight.debugfs_regulator_present=%d\n"
                         "pmic_soft_reset_preflight.pmic_soft_reset_seen=%d\n"
                         "pmic_soft_reset_preflight.pmic_soft_reset_source=%s\n"
                         "pmic_soft_reset_preflight.pmic_soft_reset_line=%s\n"
                         "pmic_soft_reset_preflight.pmic_soft_reset_mux_unclaimed=%d\n"
                         "pmic_soft_reset_preflight.pcie1_gdsc_seen=%d\n"
                         "pmic_soft_reset_preflight.pcie1_gdsc_source=%s\n"
                         "pmic_soft_reset_preflight.pcie1_gdsc_line=%s\n"
                         "pmic_soft_reset_preflight.pcie1_gdsc_zero=%d\n"
                         "pmic_soft_reset_preflight.pcie0_gdsc_seen=%d\n"
                         "pmic_soft_reset_preflight.pcie0_gdsc_source=%s\n"
                         "pmic_soft_reset_preflight.pcie0_gdsc_line=%s\n"
                         "pmic_soft_reset_preflight.pcie0_gdsc_zero=%d\n"
                         "pmic_soft_reset_preflight.mdm3_state=%s\n"
                         "pmic_soft_reset_preflight.mdm3_crash_count=%s\n"
                         "pmic_soft_reset_preflight.mdm_status_irq_present=%d\n"
                         "pmic_soft_reset_preflight.mdm_status_irq_parsed=%d\n"
                         "pmic_soft_reset_preflight.mdm_status_gpio=%d\n"
                         "pmic_soft_reset_preflight.mdm_status_count_total=%lu\n"
                         "pmic_soft_reset_preflight.read_contract_ready=%d\n"
                         "pmic_soft_reset_preflight.native_reproduction_candidate=%d\n"
                         "pmic_soft_reset_preflight.result=%s\n"
                         "pmic_soft_reset_preflight.end=1\n",
                         EXECNS_VERSION,
                         cfg->allow_pmic_soft_reset_preflight ? 1 : 0,
                         cfg->allow_pmic_soft_reset_write ? 1 : 0,
                         gpio9_class_exists ? 1 : 0,
                         gpio135_class_exists ? 1 : 0,
                         gpio142_class_exists ? 1 : 0,
                         debugfs_pinctrl_present ? 1 : 0,
                         debugfs_regulator_present ? 1 : 0,
                         pmic_soft_reset_seen ? 1 : 0,
                         pmic_soft_reset_source,
                         pmic_soft_reset_line,
                         pmic_soft_reset_mux_unclaimed ? 1 : 0,
                         pcie1_gdsc_seen ? 1 : 0,
                         pcie1_gdsc_source,
                         pcie1_gdsc_line,
                         pcie1_gdsc_zero ? 1 : 0,
                         pcie0_gdsc_seen ? 1 : 0,
                         pcie0_gdsc_source,
                         pcie0_gdsc_line,
                         pcie0_gdsc_zero ? 1 : 0,
                         mdm3_state,
                         mdm3_crash_count,
                         irq.present ? 1 : 0,
                         irq.parsed ? 1 : 0,
                         irq.gpio,
                         irq.count_total,
                         read_contract_ready ? 1 : 0,
                         native_reproduction_candidate ? 1 : 0,
                         result);
}

struct pmic_gpiochip_candidate {
    int scan_count;
    int chip_index;
    int open_errno;
    int ioctl_errno;
    int lines;
    int global_base;
    int global_end;
    int expected_global_line;
    int expected_offset;
    bool dev_seen;
    bool chipinfo_ok;
    bool debugfs_line_seen;
    bool identity_match;
    bool offset_match;
    bool mapping_ready;
    char dev_path[64];
    char name[GPIO_MAX_NAME_SIZE];
    char label[GPIO_MAX_NAME_SIZE];
    char debugfs_line[512];
    char debugfs_source[MAX_PATH_LEN];
};

static bool line_contains_all3(const char *line,
                               const char *needle_a,
                               const char *needle_b,
                               const char *needle_c) {
    return (needle_a == NULL || strstr(line, needle_a) != NULL) &&
           (needle_b == NULL || strstr(line, needle_b) != NULL) &&
           (needle_c == NULL || strstr(line, needle_c) != NULL);
}

static bool read_first_matching_line_all_with_source(const char *path,
                                                     const char *needle_a,
                                                     const char *needle_b,
                                                     const char *needle_c,
                                                     char *out,
                                                     size_t out_size,
                                                     char *source,
                                                     size_t source_size) {
    FILE *file;
    char line[512];

    if (out_size == 0) {
        return false;
    }
    out[0] = '\0';
    if (source_size > 0) {
        source[0] = '\0';
    }
    file = fopen(path, "re");
    if (file == NULL) {
        return false;
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        if (!line_contains_all3(line, needle_a, needle_b, needle_c)) {
            continue;
        }
        snprintf(out, out_size, "%s", line);
        sanitize_one_line(out);
        if (source_size > 0) {
            snprintf(source, source_size, "%s", path);
            sanitize_one_line(source);
        }
        fclose(file);
        return true;
    }
    fclose(file);
    return false;
}

static bool parse_debugfs_gpio_range(const char *line, int *base, int *end) {
    const char *cursor = strstr(line, "GPIOs ");

    if (cursor == NULL) {
        return false;
    }
    return sscanf(cursor, "GPIOs %d-%d", base, end) == 2;
}

static bool gpiochip_identity_matches(const char *name, const char *label, const char *debugfs_line) {
    return strstr(name, "pm8150l") != NULL ||
           strstr(name, "c440000") != NULL ||
           strstr(label, "pm8150l") != NULL ||
           strstr(label, "c440000") != NULL ||
           strstr(debugfs_line, "pm8150l") != NULL ||
           strstr(debugfs_line, "c440000") != NULL ||
           strstr(debugfs_line, "GPIOs 1263-1273") != NULL;
}

static struct pmic_gpiochip_candidate collect_pmic_gpiochip_candidate(void) {
    struct pmic_gpiochip_candidate selected;
    const int expected_global_line = 1270;
    int scan_count = 0;

    memset(&selected, 0, sizeof(selected));
    selected.chip_index = -1;
    selected.open_errno = 0;
    selected.ioctl_errno = 0;
    selected.lines = -1;
    selected.global_base = -1;
    selected.global_end = -1;
    selected.expected_global_line = expected_global_line;
    selected.expected_offset = -1;
    for (int index = 0; index < 32; index++) {
        struct pmic_gpiochip_candidate current;
        struct gpiochip_info info;
        struct stat st;
        char needle[32];
        int fd;

        memset(&current, 0, sizeof(current));
        current.chip_index = index;
        current.open_errno = 0;
        current.ioctl_errno = 0;
        current.lines = -1;
        current.global_base = -1;
        current.global_end = -1;
        current.expected_global_line = expected_global_line;
        current.expected_offset = -1;
        snprintf(current.dev_path, sizeof(current.dev_path), "/dev/gpiochip%d", index);
        snprintf(needle, sizeof(needle), "gpiochip%d:", index);
        current.debugfs_line_seen =
            read_first_matching_line_all_with_source("/sys/kernel/debug/gpio",
                                                     needle,
                                                     "GPIOs ",
                                                     NULL,
                                                     current.debugfs_line,
                                                     sizeof(current.debugfs_line),
                                                     current.debugfs_source,
                                                     sizeof(current.debugfs_source));
        if (current.debugfs_line_seen) {
            if (!parse_debugfs_gpio_range(current.debugfs_line,
                                          &current.global_base,
                                          &current.global_end)) {
                current.global_base = -1;
                current.global_end = -1;
            }
        }
        if (lstat(current.dev_path, &st) == 0) {
            scan_count++;
            current.dev_seen = true;
            fd = open(current.dev_path, O_RDONLY | O_CLOEXEC);
            if (fd < 0) {
                current.open_errno = errno;
            } else {
                memset(&info, 0, sizeof(info));
                if (ioctl(fd, GPIO_GET_CHIPINFO_IOCTL, &info) == 0) {
                    current.chipinfo_ok = true;
                    current.lines = (int)info.lines;
                    snprintf(current.name, sizeof(current.name), "%s", info.name);
                    sanitize_one_line(current.name);
                    snprintf(current.label, sizeof(current.label), "%s", info.label);
                    sanitize_one_line(current.label);
                } else {
                    current.ioctl_errno = errno;
                }
                close(fd);
            }
        }
        if (current.global_base >= 0 &&
            current.global_end >= current.global_base &&
            expected_global_line >= current.global_base &&
            expected_global_line <= current.global_end) {
            current.expected_offset = expected_global_line - current.global_base;
        }
        current.identity_match =
            gpiochip_identity_matches(current.name, current.label, current.debugfs_line);
        current.offset_match = current.expected_offset == 7;
        current.mapping_ready =
            current.dev_seen &&
            current.chipinfo_ok &&
            current.identity_match &&
            current.offset_match;
        if (current.mapping_ready ||
            (!selected.dev_seen && (current.identity_match || current.offset_match || current.debugfs_line_seen))) {
            selected = current;
            selected.scan_count = scan_count;
            if (current.mapping_ready) {
                break;
            }
        }
    }
    selected.scan_count = scan_count;
    return selected;
}

static int append_pmic_power_write_gate_preflight(struct buffer *buf, const struct config *cfg) {
    struct mdm_status_irq_snapshot irq = collect_mdm_status_irq_snapshot();
    struct pmic_gpiochip_candidate candidate = collect_pmic_gpiochip_candidate();
    struct stat st;
    char mdm3_state[64];
    char mdm3_crash_count[64];
    char pmic_soft_reset_line[512];
    char pmic_soft_reset_source[MAX_PATH_LEN];
    char pcie1_gdsc_line[512];
    char pcie1_gdsc_source[MAX_PATH_LEN];
    char pcie0_gdsc_line[512];
    char pcie0_gdsc_source[MAX_PATH_LEN];
    bool gpio9_class_exists = lstat("/sys/class/gpio/gpio9", &st) == 0;
    bool gpio135_class_exists = lstat("/sys/class/gpio/gpio135", &st) == 0;
    bool gpio142_class_exists = lstat("/sys/class/gpio/gpio142", &st) == 0;
    bool debugfs_pinctrl_present = lstat("/sys/kernel/debug/pinctrl", &st) == 0;
    bool debugfs_regulator_present =
        lstat("/sys/kernel/debug/regulator/regulator_summary", &st) == 0 ||
        lstat("/sys/kernel/debug/regulator_summary", &st) == 0;
    bool pmic_soft_reset_seen;
    bool pcie1_gdsc_seen;
    bool pcie0_gdsc_seen;
    bool pmic_soft_reset_mux_unclaimed;
    bool pcie1_gdsc_zero;
    bool pcie0_gdsc_zero;
    bool read_contract_ready;
    bool native_reproduction_candidate;
    bool mapping_preflight_ready;
    const char *result;

    read_state_or_error("/sys/bus/msm_subsys/devices/subsys9/state",
                        mdm3_state,
                        sizeof(mdm3_state));
    read_state_or_error("/sys/bus/msm_subsys/devices/subsys9/crash_count",
                        mdm3_crash_count,
                        sizeof(mdm3_crash_count));
    pmic_soft_reset_seen = read_pmic_soft_reset_line(pmic_soft_reset_line,
                                                     sizeof(pmic_soft_reset_line),
                                                     pmic_soft_reset_source,
                                                     sizeof(pmic_soft_reset_source));
    pcie1_gdsc_seen = read_regulator_line("pcie_1_gdsc",
                                          pcie1_gdsc_line,
                                          sizeof(pcie1_gdsc_line),
                                          pcie1_gdsc_source,
                                          sizeof(pcie1_gdsc_source));
    pcie0_gdsc_seen = read_regulator_line("pcie_0_gdsc",
                                          pcie0_gdsc_line,
                                          sizeof(pcie0_gdsc_line),
                                          pcie0_gdsc_source,
                                          sizeof(pcie0_gdsc_source));
    if (!pmic_soft_reset_seen) {
        pmic_soft_reset_line[0] = '\0';
        pmic_soft_reset_source[0] = '\0';
    }
    if (!pcie1_gdsc_seen) {
        pcie1_gdsc_line[0] = '\0';
        pcie1_gdsc_source[0] = '\0';
    }
    if (!pcie0_gdsc_seen) {
        pcie0_gdsc_line[0] = '\0';
        pcie0_gdsc_source[0] = '\0';
    }
    pmic_soft_reset_mux_unclaimed =
        pmic_soft_reset_seen && strstr(pmic_soft_reset_line, "MUX UNCLAIMED") != NULL;
    pcie1_gdsc_zero = pcie1_gdsc_seen && strstr(pcie1_gdsc_line, "0mV") != NULL;
    pcie0_gdsc_zero = pcie0_gdsc_seen && strstr(pcie0_gdsc_line, "0mV") != NULL;
    read_contract_ready =
        debugfs_pinctrl_present &&
        debugfs_regulator_present &&
        pmic_soft_reset_seen &&
        pcie1_gdsc_seen &&
        pcie0_gdsc_seen &&
        !gpio9_class_exists &&
        !gpio135_class_exists &&
        !gpio142_class_exists;
    native_reproduction_candidate =
        read_contract_ready &&
        pmic_soft_reset_mux_unclaimed &&
        pcie1_gdsc_zero &&
        pcie0_gdsc_zero &&
        strcmp(mdm3_state, "OFFLINING") == 0 &&
        irq.count_total == 0;
    mapping_preflight_ready =
        native_reproduction_candidate &&
        candidate.mapping_ready;
    if (mapping_preflight_ready) {
        result = "mapping-ready-no-write";
    } else if (native_reproduction_candidate) {
        result = "native-candidate-mapping-incomplete";
    } else {
        result = "read-contract-incomplete";
    }

    return append_format(buf,
                         "pmic_power_write_gate_preflight.begin=1\n"
                         "pmic_power_write_gate_preflight.helper_version=%s\n"
                         "pmic_power_write_gate_preflight.mode=read-only-fail-closed\n"
                         "pmic_power_write_gate_preflight.allow_preflight=%d\n"
                         "pmic_power_write_gate_preflight.write_gate_implemented=0\n"
                         "pmic_power_write_gate_preflight.mutation_attempted=0\n"
                         "pmic_power_write_gate_preflight.gpio_line_request_executed=0\n"
                         "pmic_power_write_gate_preflight.esoc_ioctl_executed=0\n"
                         "pmic_power_write_gate_preflight.pm_actor_executed=0\n"
                         "pmic_power_write_gate_preflight.cnss_daemon_start_executed=0\n"
                         "pmic_power_write_gate_preflight.wifi_hal_start_executed=0\n"
                         "pmic_power_write_gate_preflight.scan_connect_linkup=0\n"
                         "pmic_power_write_gate_preflight.credentials=0\n"
                         "pmic_power_write_gate_preflight.dhcp_routing=0\n"
                         "pmic_power_write_gate_preflight.external_ping=0\n"
                         "pmic_power_write_gate_preflight.expected_dts_compatible=qcom,ext-sdx50m\n"
                         "pmic_power_write_gate_preflight.expected_global_line=1270\n"
                         "pmic_power_write_gate_preflight.expected_chip_range=1263-1273\n"
                         "pmic_power_write_gate_preflight.expected_offset=7\n"
                         "pmic_power_write_gate_preflight.gpio_class.gpio9_exists=%d\n"
                         "pmic_power_write_gate_preflight.gpio_class.gpio135_exists=%d\n"
                         "pmic_power_write_gate_preflight.gpio_class.gpio142_exists=%d\n"
                         "pmic_power_write_gate_preflight.debugfs_pinctrl_present=%d\n"
                         "pmic_power_write_gate_preflight.debugfs_regulator_present=%d\n"
                         "pmic_power_write_gate_preflight.pmic_soft_reset_seen=%d\n"
                         "pmic_power_write_gate_preflight.pmic_soft_reset_source=%s\n"
                         "pmic_power_write_gate_preflight.pmic_soft_reset_line=%s\n"
                         "pmic_power_write_gate_preflight.pmic_soft_reset_mux_unclaimed=%d\n"
                         "pmic_power_write_gate_preflight.pcie1_gdsc_seen=%d\n"
                         "pmic_power_write_gate_preflight.pcie1_gdsc_line=%s\n"
                         "pmic_power_write_gate_preflight.pcie1_gdsc_zero=%d\n"
                         "pmic_power_write_gate_preflight.pcie0_gdsc_seen=%d\n"
                         "pmic_power_write_gate_preflight.pcie0_gdsc_line=%s\n"
                         "pmic_power_write_gate_preflight.pcie0_gdsc_zero=%d\n"
                         "pmic_power_write_gate_preflight.mdm3_state=%s\n"
                         "pmic_power_write_gate_preflight.mdm3_crash_count=%s\n"
                         "pmic_power_write_gate_preflight.mdm_status_count_total=%lu\n"
                         "pmic_power_write_gate_preflight.gpiochip_scan_count=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_candidate_seen=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_candidate_path=%s\n"
                         "pmic_power_write_gate_preflight.gpiochip_candidate_name=%s\n"
                         "pmic_power_write_gate_preflight.gpiochip_candidate_label=%s\n"
                         "pmic_power_write_gate_preflight.gpiochip_candidate_lines=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_debugfs_line_seen=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_debugfs_line=%s\n"
                         "pmic_power_write_gate_preflight.gpiochip_global_base=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_global_end=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_expected_offset=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_identity_match=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_offset_match=%d\n"
                         "pmic_power_write_gate_preflight.gpiochip_mapping_ready=%d\n"
                         "pmic_power_write_gate_preflight.read_contract_ready=%d\n"
                         "pmic_power_write_gate_preflight.native_reproduction_candidate=%d\n"
                         "pmic_power_write_gate_preflight.mapping_preflight_ready=%d\n"
                         "pmic_power_write_gate_preflight.result=%s\n"
                         "pmic_power_write_gate_preflight.end=1\n",
                         EXECNS_VERSION,
                         cfg->allow_pmic_power_write_gate_preflight ? 1 : 0,
                         gpio9_class_exists ? 1 : 0,
                         gpio135_class_exists ? 1 : 0,
                         gpio142_class_exists ? 1 : 0,
                         debugfs_pinctrl_present ? 1 : 0,
                         debugfs_regulator_present ? 1 : 0,
                         pmic_soft_reset_seen ? 1 : 0,
                         pmic_soft_reset_source,
                         pmic_soft_reset_line,
                         pmic_soft_reset_mux_unclaimed ? 1 : 0,
                         pcie1_gdsc_seen ? 1 : 0,
                         pcie1_gdsc_line,
                         pcie1_gdsc_zero ? 1 : 0,
                         pcie0_gdsc_seen ? 1 : 0,
                         pcie0_gdsc_line,
                         pcie0_gdsc_zero ? 1 : 0,
                         mdm3_state,
                         mdm3_crash_count,
                         irq.count_total,
                         candidate.scan_count,
                         candidate.dev_seen ? 1 : 0,
                         candidate.dev_path,
                         candidate.name,
                         candidate.label,
                         candidate.lines,
                         candidate.debugfs_line_seen ? 1 : 0,
                         candidate.debugfs_line,
                         candidate.global_base,
                         candidate.global_end,
                         candidate.expected_offset,
                         candidate.identity_match ? 1 : 0,
                         candidate.offset_match ? 1 : 0,
                         candidate.mapping_ready ? 1 : 0,
                         read_contract_ready ? 1 : 0,
                         native_reproduction_candidate ? 1 : 0,
                         mapping_preflight_ready ? 1 : 0,
                         result);
}

static int run_pmic_soft_reset_preflight_guarded(const struct config *cfg,
                                                 struct buffer *stdout_buf) {
    return append_pmic_soft_reset_preflight(stdout_buf, cfg);
}

static int run_pmic_power_write_gate_preflight_guarded(const struct config *cfg,
                                                       struct buffer *stdout_buf) {
    return append_pmic_power_write_gate_preflight(stdout_buf, cfg);
}

struct gpiochip_devnode_open_preflight {
    char sysfs_dev[64];
    char sysfs_label[256];
    char sysfs_base[64];
    char sysfs_ngpio[64];
    char sysfs_uevent[256];
    char node_path[128];
    char chip_name[GPIO_MAX_NAME_SIZE];
    char chip_label[GPIO_MAX_NAME_SIZE];
    int major_value;
    int minor_value;
    int open_errno;
    int ioctl_errno;
    int mknod_errno;
    int unlink_errno;
    int chip_lines;
    bool sysfs_dev_ok;
    bool sysfs_label_ok;
    bool sysfs_base_ok;
    bool sysfs_ngpio_ok;
    bool sysfs_uevent_ok;
    bool expected_dev;
    bool expected_label;
    bool expected_base;
    bool expected_ngpio;
    bool mknod_attempted;
    bool mknod_ok;
    bool open_attempted;
    bool open_ok;
    bool chipinfo_ok;
    bool cleanup_attempted;
    bool cleanup_ok;
    bool ready;
};

static bool parse_major_minor(const char *value, int *major_out, int *minor_out) {
    int major_value;
    int minor_value;

    if (sscanf(value, "%d:%d", &major_value, &minor_value) != 2) {
        return false;
    }
    if (major_value < 0 || minor_value < 0) {
        return false;
    }
    *major_out = major_value;
    *minor_out = minor_value;
    return true;
}

static struct gpiochip_devnode_open_preflight run_gpiochip_devnode_open_preflight(void) {
    struct gpiochip_devnode_open_preflight result;
    struct gpiochip_info info;
    struct stat st;
    dev_t devno;
    int fd = -1;

    memset(&result, 0, sizeof(result));
    result.major_value = -1;
    result.minor_value = -1;
    result.open_errno = 0;
    result.ioctl_errno = 0;
    result.mknod_errno = 0;
    result.unlink_errno = 0;
    result.chip_lines = -1;
    snprintf(result.node_path, sizeof(result.node_path), "/tmp/a90-gpiochip2.%ld", (long)getpid());

    result.sysfs_dev_ok = read_small_file_trim("/sys/bus/gpio/devices/gpiochip2/dev",
                                               result.sysfs_dev,
                                               sizeof(result.sysfs_dev)) == 0;
    result.sysfs_label_ok = read_small_file_trim("/sys/class/gpio/gpiochip1263/label",
                                                 result.sysfs_label,
                                                 sizeof(result.sysfs_label)) == 0;
    result.sysfs_base_ok = read_small_file_trim("/sys/class/gpio/gpiochip1263/base",
                                                result.sysfs_base,
                                                sizeof(result.sysfs_base)) == 0;
    result.sysfs_ngpio_ok = read_small_file_trim("/sys/class/gpio/gpiochip1263/ngpio",
                                                 result.sysfs_ngpio,
                                                 sizeof(result.sysfs_ngpio)) == 0;
    result.sysfs_uevent_ok = read_small_file_trim("/sys/bus/gpio/devices/gpiochip2/uevent",
                                                  result.sysfs_uevent,
                                                  sizeof(result.sysfs_uevent)) == 0;
    sanitize_one_line(result.sysfs_dev);
    sanitize_one_line(result.sysfs_label);
    sanitize_one_line(result.sysfs_base);
    sanitize_one_line(result.sysfs_ngpio);
    sanitize_one_line(result.sysfs_uevent);
    result.expected_dev =
        result.sysfs_dev_ok && parse_major_minor(result.sysfs_dev, &result.major_value, &result.minor_value) &&
        result.major_value == 254 &&
        result.minor_value == 2;
    result.expected_label =
        result.sysfs_label_ok &&
        strstr(result.sysfs_label, "pm8150l@4:pinctrl@c000") != NULL;
    result.expected_base =
        result.sysfs_base_ok &&
        strcmp(result.sysfs_base, "1263") == 0;
    result.expected_ngpio =
        result.sysfs_ngpio_ok &&
        strcmp(result.sysfs_ngpio, "11") == 0;

    if (!result.expected_dev ||
        !result.expected_label ||
        !result.expected_base ||
        !result.expected_ngpio) {
        return result;
    }
    if (lstat(result.node_path, &st) == 0) {
        result.mknod_errno = EEXIST;
        return result;
    }
    devno = makedev((unsigned int)result.major_value, (unsigned int)result.minor_value);
    result.mknod_attempted = true;
    if (mknod(result.node_path, S_IFCHR | 0600, devno) < 0) {
        result.mknod_errno = errno;
        return result;
    }
    result.mknod_ok = true;
    result.open_attempted = true;
    fd = open(result.node_path, O_RDONLY | O_CLOEXEC);
    if (fd < 0) {
        result.open_errno = errno;
    } else {
        result.open_ok = true;
        memset(&info, 0, sizeof(info));
        if (ioctl(fd, GPIO_GET_CHIPINFO_IOCTL, &info) == 0) {
            result.chipinfo_ok = true;
            result.chip_lines = (int)info.lines;
            snprintf(result.chip_name, sizeof(result.chip_name), "%s", info.name);
            sanitize_one_line(result.chip_name);
            snprintf(result.chip_label, sizeof(result.chip_label), "%s", info.label);
            sanitize_one_line(result.chip_label);
        } else {
            result.ioctl_errno = errno;
        }
        close(fd);
    }
    result.cleanup_attempted = true;
    if (unlink(result.node_path) == 0) {
        result.cleanup_ok = lstat(result.node_path, &st) < 0 && errno == ENOENT;
    } else {
        result.unlink_errno = errno;
    }
    result.ready =
        result.mknod_ok &&
        result.open_ok &&
        result.chipinfo_ok &&
        result.cleanup_ok &&
        result.chip_lines == 11;
    return result;
}

