static void write_mdm_status_irq_snapshot_fd(int out_fd, const char *phase) {
    struct mdm_status_irq_snapshot snapshot = collect_mdm_status_irq_snapshot();

    dprintf(out_fd,
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_irq_present=%d\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_irq_parsed=%d\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_irq_errno=%d\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_irq=%d\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_gpio=%d\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_count_total=%lu\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_controller=%s\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_trigger=%s\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_name=%s\n"
            "esoc_conditional_response_preflight.irq_snapshot.%s.mdm_status_line=%s\n",
            phase,
            snapshot.present ? 1 : 0,
            phase,
            snapshot.parsed ? 1 : 0,
            phase,
            snapshot.saved_errno,
            phase,
            snapshot.irq,
            phase,
            snapshot.gpio,
            phase,
            snapshot.count_total,
            phase,
            snapshot.controller,
            phase,
            snapshot.trigger,
            phase,
            snapshot.name,
            phase,
            snapshot.line);
}

static int append_mdm_status_irq_snapshot(struct buffer *buf, const char *phase) {
    struct mdm_status_irq_snapshot snapshot = collect_mdm_status_irq_snapshot();

    return append_format(buf,
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_irq_present=%d\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_irq_parsed=%d\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_irq_errno=%d\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_irq=%d\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_gpio=%d\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_count_total=%lu\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_controller=%s\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_trigger=%s\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_name=%s\n"
                         "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm_status_line=%s\n",
                         phase,
                         snapshot.present ? 1 : 0,
                         phase,
                         snapshot.parsed ? 1 : 0,
                         phase,
                         snapshot.saved_errno,
                         phase,
                         snapshot.irq,
                         phase,
                         snapshot.gpio,
                         phase,
                         snapshot.count_total,
                         phase,
                         snapshot.controller,
                         phase,
                         snapshot.trigger,
                         phase,
                         snapshot.name,
                         phase,
                         snapshot.line);
}

static int append_subsys_hold_snapshot(struct buffer *buf, const char *phase) {
    char mss_state[128];
    char mdm3_state[128];
    int rpmsg_count = -1;
    bool rpmsg_ipcrtr_present = false;
    bool rpmsg_error = false;

    read_state_or_error("/sys/devices/platform/soc/4080000.qcom,mss/subsys0/state",
                        mss_state,
                        sizeof(mss_state));
    read_state_or_error("/sys/devices/platform/soc/soc:qcom,mdm3/subsys9/state",
                        mdm3_state,
                        sizeof(mdm3_state));
    if (count_dir_entries_matching("/sys/bus/rpmsg/devices",
                                   "IPCRTR",
                                   &rpmsg_count,
                                   &rpmsg_ipcrtr_present) < 0) {
        rpmsg_error = true;
    }
    return append_format(buf,
                         "wifi_companion_start.subsys_hold.%s.mss_state=%s\n"
                         "wifi_companion_start.subsys_hold.%s.mdm3_state=%s\n"
                         "wifi_companion_start.subsys_hold.%s.rpmsg_count=%d\n"
                         "wifi_companion_start.subsys_hold.%s.rpmsg_ipcrtr_present=%d\n"
                         "wifi_companion_start.subsys_hold.%s.rpmsg_error=%d\n",
                         phase,
                         mss_state,
                         phase,
                         mdm3_state,
                         phase,
                         rpmsg_count,
                         phase,
                         rpmsg_ipcrtr_present ? 1 : 0,
                         phase,
                         rpmsg_error ? 1 : 0);
}

static int append_esoc_req_subsys_hold_snapshot(struct buffer *buf, const char *phase) {
    char mss_state[128];
    char mdm3_state[128];
    int rpmsg_count = -1;
    bool rpmsg_ipcrtr_present = false;
    bool rpmsg_error = false;

    read_state_or_error("/sys/devices/platform/soc/4080000.qcom,mss/subsys0/state",
                        mss_state,
                        sizeof(mss_state));
    read_state_or_error("/sys/devices/platform/soc/soc:qcom,mdm3/subsys9/state",
                        mdm3_state,
                        sizeof(mdm3_state));
    if (count_dir_entries_matching("/sys/bus/rpmsg/devices",
                                   "IPCRTR",
                                   &rpmsg_count,
                                   &rpmsg_ipcrtr_present) < 0) {
        rpmsg_error = true;
    }
    if (append_format(buf,
                      "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mss_state=%s\n"
                      "esoc_req_registered_subsys_hold_preflight.snapshot.%s.mdm3_state=%s\n"
                      "esoc_req_registered_subsys_hold_preflight.snapshot.%s.rpmsg_count=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.snapshot.%s.rpmsg_ipcrtr_present=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.snapshot.%s.rpmsg_error=%d\n",
                      phase,
                      mss_state,
                      phase,
                      mdm3_state,
                      phase,
                      rpmsg_count,
                      phase,
                      rpmsg_ipcrtr_present ? 1 : 0,
                      phase,
                      rpmsg_error ? 1 : 0) < 0) {
        return -1;
    }
    return append_mdm_status_irq_snapshot(buf, phase);
}

static int parse_dev_major_minor(const char *path,
                                 unsigned int *major_no,
                                 unsigned int *minor_no,
                                 char *text,
                                 size_t text_size) {
    if (read_small_file_trim(path, text, text_size) < 0) {
        return -1;
    }
    if (sscanf(text, "%u:%u", major_no, minor_no) != 2) {
        errno = EINVAL;
        return -1;
    }
    return 0;
}

static int materialize_subsys_hold_node(const char *sys_dev_path,
                                        const char *node_path,
                                        const char *label,
                                        struct buffer *stdout_buf) {
    char dev_text[64];
    unsigned int major_no = 0;
    unsigned int minor_no = 0;
    int saved_errno;

    if (parse_dev_major_minor(sys_dev_path, &major_no, &minor_no, dev_text, sizeof(dev_text)) < 0) {
        saved_errno = errno;
        return append_format(stdout_buf,
                             "wifi_companion_start.subsys_hold.%s_node_ready=0\n"
                             "wifi_companion_start.subsys_hold.%s_dev_path=%s\n"
                             "wifi_companion_start.subsys_hold.%s_dev_error=%s\n",
                             label,
                             label,
                             sys_dev_path,
                             label,
                             strerror(saved_errno));
    }
    if (unlink(node_path) < 0 && errno != ENOENT) {
        saved_errno = errno;
        return append_format(stdout_buf,
                             "wifi_companion_start.subsys_hold.%s_node_ready=0\n"
                             "wifi_companion_start.subsys_hold.%s_node_error=unlink-%s\n",
                             label,
                             label,
                             strerror(saved_errno));
    }
    if (mknod(node_path, S_IFCHR | 0600, makedev(major_no, minor_no)) < 0) {
        saved_errno = errno;
        return append_format(stdout_buf,
                             "wifi_companion_start.subsys_hold.%s_node_ready=0\n"
                             "wifi_companion_start.subsys_hold.%s_node_error=mknod-%s\n",
                             label,
                             label,
                             strerror(saved_errno));
    }
    if (chmod(node_path, 0600) < 0) {
        saved_errno = errno;
        return append_format(stdout_buf,
                             "wifi_companion_start.subsys_hold.%s_node_ready=0\n"
                             "wifi_companion_start.subsys_hold.%s_node_error=chmod-%s\n",
                             label,
                             label,
                             strerror(saved_errno));
    }
    return append_format(stdout_buf,
                         "wifi_companion_start.subsys_hold.%s_node_ready=1\n"
                         "wifi_companion_start.subsys_hold.%s_dev_path=%s\n"
                         "wifi_companion_start.subsys_hold.%s_dev=%s\n"
                         "wifi_companion_start.subsys_hold.%s_node=%s\n",
                         label,
                         label,
                         sys_dev_path,
                         label,
                         dev_text,
                         label,
                         node_path);
}

static int open_subsys_hold_child_node(int out_fd, const char *path, const char *label) {
    int fd;
    int saved_errno = 0;

    fd = open(path, O_RDONLY | O_NONBLOCK | O_CLOEXEC);
    if (fd < 0 && errno == EINVAL) {
        fd = open(path, O_RDONLY | O_CLOEXEC);
    }
    if (fd < 0) {
        saved_errno = errno;
        dprintf(out_fd,
                "wifi_companion_start.subsys_hold.%s_opened=0\n"
                "wifi_companion_start.subsys_hold.%s_open_errno=%d\n"
                "wifi_companion_start.subsys_hold.%s_open_error=%s\n",
                label,
                label,
                saved_errno,
                label,
                strerror(saved_errno));
        return -1;
    }
    dprintf(out_fd,
            "wifi_companion_start.subsys_hold.%s_opened=1\n"
            "wifi_companion_start.subsys_hold.%s_fd=%d\n",
            label,
            label,
            fd);
    return fd;
}

static void wlan_pd_modem_holder_init(struct wlan_pd_modem_holder *holder) {
    holder->pid = -1;
    holder->pgid = -1;
    holder->pipe_fd = -1;
    holder->pipe_open = false;
    holder->started = false;
    holder->term_sent = false;
    holder->kill_sent = false;
    holder->reaped = false;
    holder->exit_code = -1;
    holder->signal = 0;
}

static int drain_wlan_pd_modem_holder(struct wlan_pd_modem_holder *holder,
                                      struct buffer *stdout_buf,
                                      long wait_ms) {
    long deadline = monotonic_ms() + wait_ms;

    while (holder->pipe_open &&
           holder->pipe_fd >= 0 &&
           (wait_ms <= 0 || monotonic_ms() < deadline)) {
        bool pipe_open = holder->pipe_open;
        if (drain_fd(holder->pipe_fd, stdout_buf, &pipe_open) < 0) {
            return -1;
        }
        holder->pipe_open = pipe_open;
        if (!holder->pipe_open || wait_ms <= 0) {
            break;
        }
        usleep(50000);
    }
    if (holder->pipe_open && wait_ms <= 0 && holder->pipe_fd >= 0) {
        bool pipe_open = holder->pipe_open;
        if (drain_fd(holder->pipe_fd, stdout_buf, &pipe_open) < 0) {
            return -1;
        }
        holder->pipe_open = pipe_open;
    }
    return 0;
}

static int start_wlan_pd_modem_holder(const struct paths *paths,
                                      struct buffer *stdout_buf,
                                      struct wlan_pd_modem_holder *holder) {
    char modem_node[MAX_PATH_LEN];
    int stdout_pipe[2] = {-1, -1};
    long start_ms = monotonic_ms();

    wlan_pd_modem_holder_init(holder);
    if (append_literal(stdout_buf,
                       "wlan_pd_modem_holder.begin=1\n"
                       "wlan_pd_modem_holder.mode=modem-only-subsys-open\n"
                       "wlan_pd_modem_holder.subsys_modem_open_attempted=1\n"
                       "wlan_pd_modem_holder.subsys_esoc0_open_attempted=0\n"
                       "wlan_pd_modem_holder.esoc_open_attempted=0\n"
                       "wlan_pd_modem_holder.forced_rc1_attempted=0\n") < 0 ||
        append_subsys_hold_snapshot(stdout_buf, "wlan_pd_modem_before") < 0) {
        return -1;
    }
    if (append_path(modem_node, sizeof(modem_node), paths->dev, "subsys_modem") < 0) {
        return append_literal(stdout_buf,
                              "wlan_pd_modem_holder.start_attempted=0\n"
                              "wlan_pd_modem_holder.result=setup-failed\n"
                              "wlan_pd_modem_holder.reason=subsys-modem-node-path-too-long\n"
                              "wlan_pd_modem_holder.end=1\n");
    }
    if (materialize_subsys_hold_node("/sys/class/subsys/subsys_modem/dev",
                                     modem_node,
                                     "wlan_pd_modem",
                                     stdout_buf) < 0) {
        return -1;
    }
    if (strstr(stdout_buf->data != NULL ? stdout_buf->data : "",
               "wifi_companion_start.subsys_hold.wlan_pd_modem_node_ready=0\n") != NULL) {
        unlink(modem_node);
        return append_literal(stdout_buf,
                              "wlan_pd_modem_holder.start_attempted=0\n"
                              "wlan_pd_modem_holder.result=setup-failed\n"
                              "wlan_pd_modem_holder.reason=subsys-modem-node-unavailable\n"
                              "wlan_pd_modem_holder.end=1\n");
    }
    if (pipe2(stdout_pipe, O_CLOEXEC) < 0) {
        unlink(modem_node);
        return append_format(stdout_buf,
                             "wlan_pd_modem_holder.start_attempted=0\n"
                             "wlan_pd_modem_holder.result=setup-failed\n"
                             "wlan_pd_modem_holder.reason=pipe-failed-%s\n"
                             "wlan_pd_modem_holder.end=1\n",
                             strerror(errno));
    }
    holder->pid = fork();
    if (holder->pid < 0) {
        int saved_errno = errno;
        close(stdout_pipe[0]);
        close(stdout_pipe[1]);
        unlink(modem_node);
        return append_format(stdout_buf,
                             "wlan_pd_modem_holder.start_attempted=0\n"
                             "wlan_pd_modem_holder.result=setup-failed\n"
                             "wlan_pd_modem_holder.reason=fork-failed-%s\n"
                             "wlan_pd_modem_holder.end=1\n",
                             strerror(saved_errno));
    }
    if (holder->pid == 0) {
        int modem_fd;
        int nonblock_errno = 0;

        close(stdout_pipe[0]);
        if (setsid() < 0) {
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.child_setsid_error=%s\n"
                    "wlan_pd_modem_holder.opened=0\n",
                    strerror(errno));
            close(stdout_pipe[1]);
            _exit(120);
        }
        if (chroot(paths->root) < 0) {
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.child_chroot_error=%s\n"
                    "wlan_pd_modem_holder.opened=0\n",
                    strerror(errno));
            close(stdout_pipe[1]);
            _exit(121);
        }
        if (chdir("/") < 0) {
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.child_chdir_error=%s\n"
                    "wlan_pd_modem_holder.opened=0\n",
                    strerror(errno));
            close(stdout_pipe[1]);
            _exit(122);
        }
        dprintf(stdout_pipe[1],
                "wlan_pd_modem_holder.child_chroot=1\n"
                "wlan_pd_modem_holder.path=/dev/subsys_modem\n");
        modem_fd = open("/dev/subsys_modem", O_RDONLY | O_NONBLOCK | O_CLOEXEC);
        if (modem_fd < 0) {
            nonblock_errno = errno;
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.nonblock_opened=0\n"
                    "wlan_pd_modem_holder.nonblock_errno=%d\n"
                    "wlan_pd_modem_holder.plain_retry=1\n",
                    nonblock_errno);
            modem_fd = open("/dev/subsys_modem", O_RDONLY | O_CLOEXEC);
        } else {
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.nonblock_opened=1\n"
                    "wlan_pd_modem_holder.nonblock_errno=0\n"
                    "wlan_pd_modem_holder.plain_retry=0\n");
        }
        if (modem_fd < 0) {
            int saved_errno = errno;
            dprintf(stdout_pipe[1],
                    "wlan_pd_modem_holder.opened=0\n"
                    "wlan_pd_modem_holder.open_errno=%d\n"
                    "wlan_pd_modem_holder.open_error=%s\n"
                    "wlan_pd_modem_holder.first_errno=%d\n",
                    saved_errno,
                    strerror(saved_errno),
                    nonblock_errno);
            close(stdout_pipe[1]);
            _exit(31);
        }
        dprintf(stdout_pipe[1],
                "wlan_pd_modem_holder.opened=1\n"
                "wlan_pd_modem_holder.fd=%d\n"
                "wlan_pd_modem_holder.first_errno=%d\n",
                modem_fd,
                nonblock_errno);
        close(stdout_pipe[1]);
        for (;;) {
            pause();
        }
    }

    close(stdout_pipe[1]);
    holder->pipe_fd = stdout_pipe[0];
    holder->pipe_open = true;
    holder->started = true;
    set_nonblock(holder->pipe_fd);
    holder->pgid = wait_for_child_session_pgid(holder->pid, 1000);
    if (append_format(stdout_buf,
                      "wlan_pd_modem_holder.start_attempted=1\n"
                      "wlan_pd_modem_holder.pid=%ld\n"
                      "wlan_pd_modem_holder.pgid=%ld\n"
                      "wlan_pd_modem_holder.start_elapsed_ms=%ld\n",
                      (long)holder->pid,
                      (long)holder->pgid,
                      monotonic_ms() - start_ms) < 0 ||
        drain_wlan_pd_modem_holder(holder, stdout_buf, 300) < 0 ||
        append_subsys_hold_snapshot(stdout_buf, "wlan_pd_modem_after_start") < 0) {
        return -1;
    }
    return 0;
}

static int stop_wlan_pd_modem_holder(const struct paths *paths,
                                     struct buffer *stdout_buf,
                                     struct wlan_pd_modem_holder *holder) {
    char modem_node[MAX_PATH_LEN];
    long deadline;

    if (!holder->started) {
        return 0;
    }
    if (drain_wlan_pd_modem_holder(holder, stdout_buf, 0) < 0) {
        return -1;
    }
    if (!holder->reaped && holder->pid > 0) {
        int status = 0;
        pid_t wait_rc = waitpid(holder->pid, &status, WNOHANG);
        if (wait_rc == holder->pid) {
            holder->reaped = true;
            if (WIFEXITED(status)) {
                holder->exit_code = WEXITSTATUS(status);
            } else if (WIFSIGNALED(status)) {
                holder->signal = WTERMSIG(status);
            }
        }
    }
    if (!holder->reaped && holder->pid > 0) {
        pid_t kill_target = holder->pgid > 0 ? -holder->pgid : holder->pid;
        if (kill(kill_target, SIGTERM) == 0 || errno == ESRCH) {
            holder->term_sent = true;
        }
        deadline = monotonic_ms() + 3000L;
        while (!holder->reaped && monotonic_ms() < deadline) {
            int status = 0;
            pid_t wait_rc = waitpid(holder->pid, &status, WNOHANG);
            if (wait_rc == holder->pid) {
                holder->reaped = true;
                if (WIFEXITED(status)) {
                    holder->exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    holder->signal = WTERMSIG(status);
                }
                break;
            }
            if (holder->pipe_open) {
                drain_wlan_pd_modem_holder(holder, stdout_buf, 0);
            }
            usleep(50000);
        }
    }
    if (!holder->reaped && holder->pid > 0) {
        pid_t kill_target = holder->pgid > 0 ? -holder->pgid : holder->pid;
        if (kill(kill_target, SIGKILL) == 0 || errno == ESRCH) {
            holder->kill_sent = true;
        }
        deadline = monotonic_ms() + 10000L;
        while (!holder->reaped && monotonic_ms() < deadline) {
            int status = 0;
            pid_t wait_rc = waitpid(holder->pid, &status, WNOHANG);
            if (wait_rc == holder->pid) {
                holder->reaped = true;
                if (WIFEXITED(status)) {
                    holder->exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    holder->signal = WTERMSIG(status);
                }
                break;
            }
            if (holder->pipe_open) {
                drain_wlan_pd_modem_holder(holder, stdout_buf, 0);
            }
            usleep(50000);
        }
    }
    if (holder->pipe_open) {
        drain_wlan_pd_modem_holder(holder, stdout_buf, 0);
    }
    if (holder->pipe_fd >= 0) {
        close(holder->pipe_fd);
        holder->pipe_fd = -1;
    }
    if (append_path(modem_node, sizeof(modem_node), paths->dev, "subsys_modem") == 0) {
        unlink(modem_node);
    }
    holder->started = false;
    if (append_format(stdout_buf,
                      "wlan_pd_modem_holder.stop_attempted=1\n"
                      "wlan_pd_modem_holder.term_sent=%d\n"
                      "wlan_pd_modem_holder.kill_sent=%d\n"
                      "wlan_pd_modem_holder.reaped=%d\n"
                      "wlan_pd_modem_holder.exit_code=%d\n"
                      "wlan_pd_modem_holder.signal=%d\n"
                      "wlan_pd_modem_holder.postflight_safe=%d\n"
                      "wlan_pd_modem_holder.end=1\n",
                      holder->term_sent ? 1 : 0,
                      holder->kill_sent ? 1 : 0,
                      holder->reaped ? 1 : 0,
                      holder->exit_code,
                      holder->signal,
                      holder->reaped ? 1 : 0) < 0) {
        return -1;
    }
    return holder->reaped ? 0 : -1;
}

static int open_esoc_req_registered_subsys_child_node(int out_fd) {
    int fd;
    int saved_errno = 0;

    dprintf(out_fd,
            "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_attempting=1\n");
    errno = 0;
    fd = open("/dev/subsys_esoc0", O_RDONLY | O_NONBLOCK | O_CLOEXEC);
    if (fd < 0 && errno == EINVAL) {
        errno = 0;
        fd = open("/dev/subsys_esoc0", O_RDONLY | O_CLOEXEC);
    }
    saved_errno = fd < 0 ? errno : 0;
    if (fd < 0) {
        dprintf(out_fd,
                "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_opened=0\n"
                "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_errno=%d\n"
                "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_error=%s\n",
                saved_errno,
                strerror(saved_errno));
        return -1;
    }
    dprintf(out_fd,
            "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_opened=1\n"
            "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_fd=%d\n",
            fd);
    return fd;
}

static const char *esoc_req_name(unsigned int request_value) {
    if (request_value == A90_ESOC_REQ_IMG) {
        return "ESOC_REQ_IMG";
    }
    return "unknown";
}

static bool esoc_wait_for_req_observed(int rc, unsigned int request_value) {
    return rc == (int)sizeof(request_value);
}

static const char *esoc_wait_for_req_result(int rc, int saved_errno, unsigned int request_value) {
    if (esoc_wait_for_req_observed(rc, request_value)) {
        return "request-observed";
    }
    if (rc >= 0) {
        return "short-request-read";
    }
    if (saved_errno == EINTR) {
        return "interrupted";
    }
    return "ioctl-error";
}

static int run_esoc_wait_for_req_observer_child(int out_fd, int req_fd, int hold_sec) {
    unsigned int request_value = 0;
    int rc;
    int saved_errno;
    long started_ms = monotonic_ms();
    bool request_observed;

    dprintf(out_fd,
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.begin=1\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.mode=passive\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.hold_sec=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.request=0x%lx\n",
            hold_sec,
            (unsigned long)A90_ESOC_WAIT_FOR_REQ);
    errno = 0;
    rc = ioctl(req_fd, A90_ESOC_WAIT_FOR_REQ, &request_value);
    saved_errno = rc < 0 ? errno : 0;
    request_observed = esoc_wait_for_req_observed(rc, request_value);
    dprintf(out_fd,
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.rc=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.errno=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.byte_count=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.expected_bytes=%zu\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.value=%u\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.request_name=%s\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.request_observed=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.ioctl.is_esoc_req_img=%d\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.elapsed_ms=%ld\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.result=%s\n"
            "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.end=1\n",
            rc,
            saved_errno,
            rc,
            sizeof(request_value),
            request_value,
            esoc_req_name(request_value),
            request_observed ? 1 : 0,
            request_value == A90_ESOC_REQ_IMG ? 1 : 0,
            monotonic_ms() - started_ms,
            esoc_wait_for_req_result(rc, saved_errno, request_value));
    return request_observed ? 0 : 32;
}

static int esoc_notify_response_value(int out_fd, int req_fd, const char *label, unsigned int notify_value) {
    int rc;
    int saved_errno;

    errno = 0;
    rc = ioctl(req_fd, A90_ESOC_NOTIFY, &notify_value);
    saved_errno = rc < 0 ? errno : 0;
    dprintf(out_fd,
            "esoc_conditional_response_preflight.notify.%s.request=0x%lx\n"
            "esoc_conditional_response_preflight.notify.%s.value=%u\n"
            "esoc_conditional_response_preflight.notify.%s.rc=%d\n"
            "esoc_conditional_response_preflight.notify.%s.errno=%d\n",
            label,
            (unsigned long)A90_ESOC_NOTIFY,
            label,
            notify_value,
            label,
            rc,
            label,
            saved_errno);
    return rc == 0 ? 0 : 33;
}

static int esoc_get_status_response_value(int out_fd, int req_fd, const char *label, unsigned int *status_value) {
    int rc;
    int saved_errno;

    *status_value = 0;
    errno = 0;
    rc = ioctl(req_fd, A90_ESOC_GET_STATUS, status_value);
    saved_errno = rc < 0 ? errno : 0;
    dprintf(out_fd,
            "esoc_conditional_response_preflight.status.%s.request=0x%lx\n"
            "esoc_conditional_response_preflight.status.%s.rc=%d\n"
            "esoc_conditional_response_preflight.status.%s.errno=%d\n"
            "esoc_conditional_response_preflight.status.%s.value=%u\n",
            label,
            (unsigned long)A90_ESOC_GET_STATUS,
            label,
            rc,
            label,
            saved_errno,
            label,
            *status_value);
    return rc == 0 ? 0 : 34;
}

static int run_esoc_conditional_response_child(int out_fd, int req_fd, int hold_sec) {
    unsigned int request_value = 0;
    unsigned int status_value = 0;
    int rc;
    int saved_errno;
    int notify_rc;
    int poll_count = 0;
    bool request_observed;
    bool img_xfer_done_sent = false;
    bool status_ready = false;
    bool boot_done_sent = false;
    long started_ms = monotonic_ms();
    long deadline_ms = started_ms + (hold_sec > 1 ? hold_sec - 1 : 1) * 1000L;

    dprintf(out_fd,
            "esoc_conditional_response_preflight.begin=1\n"
            "esoc_conditional_response_preflight.mode=conditional-img-xfer-status-gated-boot-done\n"
            "esoc_conditional_response_preflight.hold_sec=%d\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.request=0x%lx\n"
            "esoc_conditional_response_preflight.notify.ESOC_IMG_XFER_DONE.planned=1\n"
            "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.planned=conditional\n"
            "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.condition=GET_STATUS-1\n",
            hold_sec,
            (unsigned long)A90_ESOC_WAIT_FOR_REQ);
    errno = 0;
    rc = ioctl(req_fd, A90_ESOC_WAIT_FOR_REQ, &request_value);
    saved_errno = rc < 0 ? errno : 0;
    request_observed = esoc_wait_for_req_observed(rc, request_value);
    dprintf(out_fd,
            "esoc_conditional_response_preflight.wait_for_req.ioctl.rc=%d\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.errno=%d\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.byte_count=%d\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.expected_bytes=%zu\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.value=%u\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.request_name=%s\n"
            "esoc_conditional_response_preflight.wait_for_req.ioctl.request_observed=%d\n"
            "esoc_conditional_response_preflight.wait_for_req.result=%s\n",
            rc,
            saved_errno,
            rc,
            sizeof(request_value),
            request_value,
            esoc_req_name(request_value),
            request_observed ? 1 : 0,
            esoc_wait_for_req_result(rc, saved_errno, request_value));
    if (!request_observed || request_value != A90_ESOC_REQ_IMG) {
        dprintf(out_fd,
                "esoc_conditional_response_preflight.notify.ESOC_IMG_XFER_DONE.attempted=0\n"
                "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.attempted=0\n"
                "esoc_conditional_response_preflight.result=no-esoc-req-img\n"
                "esoc_conditional_response_preflight.elapsed_ms=%ld\n"
                "esoc_conditional_response_preflight.end=1\n",
                monotonic_ms() - started_ms);
        return 35;
    }

    write_mdm_status_irq_snapshot_fd(out_fd, "before_img_xfer");
    notify_rc = esoc_notify_response_value(out_fd, req_fd, "ESOC_IMG_XFER_DONE", A90_ESOC_IMG_XFER_DONE);
    img_xfer_done_sent = notify_rc == 0;
    write_mdm_status_irq_snapshot_fd(out_fd, "after_img_xfer");
    dprintf(out_fd,
            "esoc_conditional_response_preflight.notify.ESOC_IMG_XFER_DONE.attempted=1\n"
            "esoc_conditional_response_preflight.notify.ESOC_IMG_XFER_DONE.sent=%d\n",
            img_xfer_done_sent ? 1 : 0);
    if (!img_xfer_done_sent) {
        dprintf(out_fd,
                "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.attempted=0\n"
                "esoc_conditional_response_preflight.result=img-xfer-done-notify-failed\n"
                "esoc_conditional_response_preflight.elapsed_ms=%ld\n"
                "esoc_conditional_response_preflight.end=1\n",
                monotonic_ms() - started_ms);
        return notify_rc;
    }

    while (monotonic_ms() < deadline_ms) {
        char label[32];
        int status_rc;

        poll_count++;
        snprintf(label, sizeof(label), "poll_%02d", poll_count);
        status_rc = esoc_get_status_response_value(out_fd, req_fd, label, &status_value);
        write_mdm_status_irq_snapshot_fd(out_fd, label);
        if (status_rc == 0 && status_value == 1U) {
            status_ready = true;
            break;
        }
        usleep(100000);
    }
    write_mdm_status_irq_snapshot_fd(out_fd, "after_status_loop");
    dprintf(out_fd,
            "esoc_conditional_response_preflight.status.poll_count=%d\n"
            "esoc_conditional_response_preflight.status.ready=%d\n"
            "esoc_conditional_response_preflight.status.last_value=%u\n",
            poll_count,
            status_ready ? 1 : 0,
            status_value);
    if (status_ready) {
        notify_rc = esoc_notify_response_value(out_fd, req_fd, "ESOC_BOOT_DONE", A90_ESOC_BOOT_DONE);
        boot_done_sent = notify_rc == 0;
    }
    dprintf(out_fd,
            "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.attempted=%d\n"
            "esoc_conditional_response_preflight.notify.ESOC_BOOT_DONE.sent=%d\n"
            "esoc_conditional_response_preflight.elapsed_ms=%ld\n"
            "esoc_conditional_response_preflight.result=%s\n"
            "esoc_conditional_response_preflight.end=1\n",
            status_ready ? 1 : 0,
            boot_done_sent ? 1 : 0,
            monotonic_ms() - started_ms,
            boot_done_sent ? "boot-done-sent" : (status_ready ? "boot-done-notify-failed" : "status-not-ready-no-boot-done"));
    return boot_done_sent ? 0 : (status_ready ? 36 : 37);
}

/* v238: MHI observe child — send IMG_XFER_DONE then poll for MHI device appearance.
 * Does NOT send BOOT_DONE. Reports mhi_dev_count, gpio142_count, mhi_pipe_exists
 * every 1s for up to hold_sec seconds after IMG_XFER_DONE. */
static int run_esoc_img_xfer_mhi_observe_child(int out_fd, int req_fd, int hold_sec) {
    unsigned int request_value = 0;
    int rc;
    int saved_errno;
    int notify_rc;
    bool request_observed;
    bool img_xfer_done_sent = false;
    long started_ms = monotonic_ms();
    long poll_deadline_ms;

    dprintf(out_fd,
            "esoc_img_xfer_mhi_observe.begin=1\n"
            "esoc_img_xfer_mhi_observe.mode=img-xfer-mhi-observe-no-boot-done\n"
            "esoc_img_xfer_mhi_observe.hold_sec=%d\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.request=0x%lx\n"
            "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.planned=1\n"
            "esoc_img_xfer_mhi_observe.notify.ESOC_BOOT_DONE.planned=0\n"
            "esoc_img_xfer_mhi_observe.mhi_pipe_path=/dev/mhi_0305_01.01.00_pipe_10\n"
            "esoc_img_xfer_mhi_observe.mhi_bus_path=/sys/bus/mhi/devices\n",
            hold_sec,
            (unsigned long)A90_ESOC_WAIT_FOR_REQ);
    errno = 0;
    rc = ioctl(req_fd, A90_ESOC_WAIT_FOR_REQ, &request_value);
    saved_errno = rc < 0 ? errno : 0;
    request_observed = esoc_wait_for_req_observed(rc, request_value);
    dprintf(out_fd,
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.rc=%d\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.errno=%d\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.byte_count=%d\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.value=%u\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.request_name=%s\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.ioctl.request_observed=%d\n"
            "esoc_img_xfer_mhi_observe.wait_for_req.result=%s\n",
            rc,
            saved_errno,
            rc,
            request_value,
            esoc_req_name(request_value),
            request_observed ? 1 : 0,
            esoc_wait_for_req_result(rc, saved_errno, request_value));
    if (!request_observed || request_value != A90_ESOC_REQ_IMG) {
        dprintf(out_fd,
                "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.attempted=0\n"
                "esoc_img_xfer_mhi_observe.result=no-esoc-req-img\n"
                "esoc_img_xfer_mhi_observe.elapsed_ms=%ld\n"
                "esoc_img_xfer_mhi_observe.end=1\n",
                monotonic_ms() - started_ms);
        return 38;
    }

    notify_rc = esoc_notify_response_value(out_fd, req_fd, "ESOC_IMG_XFER_DONE", A90_ESOC_IMG_XFER_DONE);
    img_xfer_done_sent = notify_rc == 0;
    dprintf(out_fd,
            "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.attempted=1\n"
            "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.sent=%d\n"
            "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.rc=%d\n"
            "esoc_img_xfer_mhi_observe.notify.ESOC_IMG_XFER_DONE.elapsed_ms=%ld\n",
            img_xfer_done_sent ? 1 : 0,
            notify_rc,
            monotonic_ms() - started_ms);
    if (!img_xfer_done_sent) {
        dprintf(out_fd,
                "esoc_img_xfer_mhi_observe.result=img-xfer-done-notify-failed\n"
                "esoc_img_xfer_mhi_observe.elapsed_ms=%ld\n"
                "esoc_img_xfer_mhi_observe.end=1\n",
                monotonic_ms() - started_ms);
        return notify_rc != 0 ? notify_rc : 39;
    }

    /* Poll for MHI device appearance every 1s for up to hold_sec. */
    poll_deadline_ms = started_ms + (long)hold_sec * 1000L;
    {
        int poll_index = 0;
        int mhi_found = 0;

        dprintf(out_fd,
                "esoc_img_xfer_mhi_observe.mhi_poll.begin=1\n"
                "esoc_img_xfer_mhi_observe.mhi_poll.interval_ms=1000\n"
                "esoc_img_xfer_mhi_observe.mhi_poll.max_sec=%d\n",
                hold_sec);
        while (monotonic_ms() < poll_deadline_ms) {
            long now_ms = monotonic_ms();
            long elapsed_since_xfer = now_ms - started_ms;
            struct stat mhi_st;
            int mhi_pipe_exists = (stat("/dev/mhi_0305_01.01.00_pipe_10", &mhi_st) == 0) ? 1 : 0;
            struct mdm_status_irq_snapshot irq = collect_mdm_status_irq_snapshot();

            /* Count /sys/bus/mhi/devices entries */
            int mhi_bus_count = 0;
            {
                DIR *d = opendir("/sys/bus/mhi/devices");
                if (d != NULL) {
                    struct dirent *de;
                    while ((de = readdir(d)) != NULL) {
                        if (de->d_name[0] != '.') {
                            mhi_bus_count++;
                        }
                    }
                    closedir(d);
                }
            }

            dprintf(out_fd,
                    "esoc_img_xfer_mhi_observe.mhi_poll.%02d.elapsed_ms=%ld\n"
                    "esoc_img_xfer_mhi_observe.mhi_poll.%02d.mhi_pipe_exists=%d\n"
                    "esoc_img_xfer_mhi_observe.mhi_poll.%02d.mhi_bus_count=%d\n"
                    "esoc_img_xfer_mhi_observe.mhi_poll.%02d.gpio142_count=%lu\n",
                    poll_index, elapsed_since_xfer,
                    poll_index, mhi_pipe_exists,
                    poll_index, mhi_bus_count,
                    poll_index, irq.parsed ? irq.count_total : 0UL);

            if (mhi_pipe_exists || mhi_bus_count > 0) {
                mhi_found = 1;
                dprintf(out_fd,
                        "esoc_img_xfer_mhi_observe.mhi_poll.mhi_appeared=1\n"
                        "esoc_img_xfer_mhi_observe.mhi_poll.mhi_appeared_at_ms=%ld\n"
                        "esoc_img_xfer_mhi_observe.mhi_poll.mhi_appeared_at_index=%d\n",
                        elapsed_since_xfer, poll_index);
                break;
            }
            poll_index++;
            usleep(1000000);
        }
        if (!mhi_found) {
            dprintf(out_fd, "esoc_img_xfer_mhi_observe.mhi_poll.mhi_appeared=0\n");
        }
        dprintf(out_fd,
                "esoc_img_xfer_mhi_observe.mhi_poll.end=1\n"
                "esoc_img_xfer_mhi_observe.mhi_poll.total_polls=%d\n",
                poll_index);
    }

    dprintf(out_fd,
            "esoc_img_xfer_mhi_observe.notify.ESOC_BOOT_DONE.attempted=0\n"
            "esoc_img_xfer_mhi_observe.result=img-xfer-done-mhi-observe-complete\n"
            "esoc_img_xfer_mhi_observe.elapsed_ms=%ld\n"
            "esoc_img_xfer_mhi_observe.end=1\n",
            monotonic_ms() - started_ms);
    return 0;
}

static pid_t wait_for_child_session_pgid(pid_t pid, long timeout_ms);

static int run_subsys_hold_open_proof(const struct config *cfg,
                                      const struct paths *paths,
                                      struct buffer *stdout_buf,
                                      struct buffer *stderr_buf,
                                      int *child_exit_code,
                                      int *child_signal,
                                      bool *timed_out) {
    int stdout_pipe[2] = {-1, -1};
    bool stdout_open = true;
    bool child_done = false;
    bool child_started = false;
    bool term_sent = false;
    bool kill_sent = false;
    bool reaped = false;
    bool postflight_safe = true;
    char modem_node[MAX_PATH_LEN];
    char esoc_node[MAX_PATH_LEN];
    long deadline;
    pid_t pid = -1;
    pid_t pgid = -1;
    int status = 0;
    int hold_sec = cfg->timeout_sec > 3 ? cfg->timeout_sec - 2 : 1;

    (void)stderr_buf;
    *child_exit_code = -1;
    *child_signal = 0;
    *timed_out = false;

    if (append_literal(stdout_buf,
                       "wifi_companion_start.begin=1\n"
                       "wifi_companion_start.mode=subsys-hold-open-proof\n"
                       "wifi_companion_start.service_manager=0\n"
                       "wifi_companion_start.wifi_hal=0\n"
                       "wifi_companion_start.scan_connect_linkup=0\n"
                       "wifi_companion_start.external_ping=0\n"
                       "wifi_companion_start.subsys_hold.qcwlanstate_write=0\n"
                       "wifi_companion_start.subsys_hold.scan_connect_linkup=0\n"
                       "wifi_companion_start.subsys_hold.external_ping=0\n") < 0) {
        return -1;
    }
    if (!cfg->allow_wifi_companion_start_only) {
        return append_literal(stdout_buf,
                              "wifi_companion_start.allowed=0\n"
                              "wifi_companion_start.exec_attempted=0\n"
                              "wifi_companion_start.child_started=0\n"
                              "wifi_companion_start.all_observable=0\n"
                              "wifi_companion_start.all_postflight_safe=1\n"
                              "wifi_companion_start.result=subsys-hold-blocked\n"
                              "wifi_companion_start.reason=missing-allow-wifi-companion-start-only\n"
                              "wifi_companion_start.end=1\n");
    }
    if (append_literal(stdout_buf, "wifi_companion_start.allowed=1\n") < 0 ||
        append_subsys_hold_snapshot(stdout_buf, "before") < 0 ||
        append_wifi_window_surface_capture(stdout_buf, "subsys_before") < 0) {
        return -1;
    }
    if (append_path(modem_node, sizeof(modem_node), paths->dev, "subsys_modem") < 0 ||
        append_path(esoc_node, sizeof(esoc_node), paths->dev, "subsys_esoc0") < 0) {
        return -1;
    }
    if (materialize_subsys_hold_node("/sys/class/subsys/subsys_modem/dev",
                                     modem_node,
                                     "modem",
                                     stdout_buf) < 0 ||
        materialize_subsys_hold_node("/sys/class/subsys/subsys_esoc0/dev",
                                     esoc_node,
                                     "esoc0",
                                     stdout_buf) < 0) {
        return -1;
    }
    if (strstr(stdout_buf->data != NULL ? stdout_buf->data : "", "node_ready=0") != NULL) {
        append_literal(stdout_buf,
                       "wifi_companion_start.exec_attempted=0\n"
                       "wifi_companion_start.child_started=0\n"
                       "wifi_companion_start.all_observable=0\n"
                       "wifi_companion_start.all_postflight_safe=1\n"
                       "wifi_companion_start.result=subsys-hold-setup-failed\n"
                       "wifi_companion_start.reason=subsys-cdev-node-unavailable\n"
                       "wifi_companion_start.end=1\n");
        unlink(modem_node);
        unlink(esoc_node);
        return 0;
    }
    if (pipe2(stdout_pipe, O_CLOEXEC) < 0) {
        return append_format(stdout_buf,
                             "wifi_companion_start.exec_attempted=0\n"
                             "wifi_companion_start.child_started=0\n"
                             "wifi_companion_start.all_observable=0\n"
                             "wifi_companion_start.all_postflight_safe=0\n"
                             "wifi_companion_start.result=manual-review-required\n"
                             "wifi_companion_start.reason=pipe-failed-%s\n"
                             "wifi_companion_start.end=1\n",
                             strerror(errno));
    }
    pid = fork();
    if (pid < 0) {
        int saved_errno = errno;

        close(stdout_pipe[0]);
        close(stdout_pipe[1]);
        unlink(modem_node);
        unlink(esoc_node);
        return append_format(stdout_buf,
                             "wifi_companion_start.exec_attempted=0\n"
                             "wifi_companion_start.child_started=0\n"
                             "wifi_companion_start.all_observable=0\n"
                             "wifi_companion_start.all_postflight_safe=0\n"
                             "wifi_companion_start.result=manual-review-required\n"
                             "wifi_companion_start.reason=fork-failed-%s\n"
                             "wifi_companion_start.end=1\n",
                             strerror(saved_errno));
    }
    if (pid == 0) {
        int modem_fd;
        int esoc_fd;
        int any_open;

        close(stdout_pipe[0]);
        if (setsid() < 0) {
            dprintf(stdout_pipe[1], "wifi_companion_start.subsys_hold.child_setsid_error=%s\n", strerror(errno));
            _exit(120);
        }
        if (chroot(paths->root) < 0) {
            dprintf(stdout_pipe[1], "wifi_companion_start.subsys_hold.child_chroot_error=%s\n", strerror(errno));
            _exit(121);
        }
        if (chdir("/") < 0) {
            dprintf(stdout_pipe[1], "wifi_companion_start.subsys_hold.child_chdir_error=%s\n", strerror(errno));
            _exit(122);
        }
        dprintf(stdout_pipe[1],
                "wifi_companion_start.subsys_hold.child_chroot=1\n"
                "wifi_companion_start.subsys_hold.hold_sec=%d\n",
                hold_sec);
        modem_fd = open_subsys_hold_child_node(stdout_pipe[1], "/dev/subsys_modem", "modem");
        esoc_fd = open_subsys_hold_child_node(stdout_pipe[1], "/dev/subsys_esoc0", "esoc0");
        any_open = modem_fd >= 0 || esoc_fd >= 0;
        dprintf(stdout_pipe[1], "wifi_companion_start.subsys_hold.any_open=%d\n", any_open ? 1 : 0);
        if (any_open) {
            for (int i = 0; i < hold_sec * 10; i++) {
                usleep(100000);
            }
        }
        if (modem_fd >= 0) {
            close(modem_fd);
        }
        if (esoc_fd >= 0) {
            close(esoc_fd);
        }
        dprintf(stdout_pipe[1], "wifi_companion_start.subsys_hold.child_done=1\n");
        close(stdout_pipe[1]);
        _exit(any_open ? 0 : 31);
    }

    child_started = true;
    close(stdout_pipe[1]);
    stdout_pipe[1] = -1;
    set_nonblock(stdout_pipe[0]);
    pgid = wait_for_child_session_pgid(pid, 1000);
    if (append_format(stdout_buf,
                      "wifi_companion_start.exec_attempted=1\n"
                      "wifi_companion_start.child_started=1\n"
                      "wifi_companion_start.pid=%ld\n"
                      "wifi_companion_start.pgid=%ld\n",
                      (long)pid,
                      (long)pgid) < 0) {
        goto fail;
    }
    usleep(500000);
    drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
    if (append_subsys_hold_snapshot(stdout_buf, "hold") < 0 ||
        append_wifi_window_surface_capture(stdout_buf, "subsys_hold") < 0) {
        goto fail;
    }
    deadline = monotonic_ms() + cfg->timeout_sec * 1000L;
    while (stdout_open || !child_done) {
        struct pollfd fds[1];
        int nfds = 0;

        if (monotonic_ms() >= deadline) {
            *timed_out = true;
            break;
        }
        if (stdout_open) {
            fds[nfds].fd = stdout_pipe[0];
            fds[nfds].events = POLLIN | POLLHUP | POLLERR;
            nfds++;
        }
        if (nfds > 0 && poll(fds, nfds, 50) > 0 && fds[0].revents != 0) {
            drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
        } else {
            usleep(50000);
        }
        if (!child_done) {
            pid_t wait_rc = waitpid(pid, &status, WNOHANG);

            if (wait_rc == pid) {
                child_done = true;
                reaped = true;
                if (WIFEXITED(status)) {
                    *child_exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    *child_signal = WTERMSIG(status);
                }
            } else if (wait_rc < 0 && errno != EINTR && errno != ECHILD) {
                append_format(stdout_buf, "wifi_companion_start.subsys_hold.wait_error=%s\n", strerror(errno));
                break;
            }
        }
    }
    if (!child_done || stdout_open) {
        if (kill(-pgid, SIGTERM) == 0 || errno == ESRCH) {
            term_sent = true;
        }
        deadline = monotonic_ms() + 1000L;
        while ((!child_done || stdout_open) && monotonic_ms() < deadline) {
            if (!child_done) {
                if (waitpid(pid, &status, WNOHANG) == pid) {
                    child_done = true;
                    reaped = true;
                    if (WIFEXITED(status)) {
                        *child_exit_code = WEXITSTATUS(status);
                    } else if (WIFSIGNALED(status)) {
                        *child_signal = WTERMSIG(status);
                    }
                }
            }
            if (stdout_open) {
                drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
            }
            usleep(50000);
        }
    }
    if (!child_done || stdout_open) {
        if (kill(-pgid, SIGKILL) == 0 || errno == ESRCH) {
            kill_sent = true;
        }
        deadline = monotonic_ms() + 1000L;
        while ((!child_done || stdout_open) && monotonic_ms() < deadline) {
            if (!child_done) {
                if (waitpid(pid, &status, WNOHANG) == pid) {
                    child_done = true;
                    reaped = true;
                    if (WIFEXITED(status)) {
                        *child_exit_code = WEXITSTATUS(status);
                    } else if (WIFSIGNALED(status)) {
                        *child_signal = WTERMSIG(status);
                    }
                }
            }
            if (stdout_open) {
                drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
            }
            usleep(50000);
        }
    }
    if (stdout_open) {
        drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
    }
    postflight_safe = reaped && (kill(-pgid, 0) < 0 && errno == ESRCH);
    if (append_subsys_hold_snapshot(stdout_buf, "after") < 0 ||
        append_wifi_window_surface_capture(stdout_buf, "subsys_after") < 0 ||
        append_format(stdout_buf,
                      "wifi_companion_start.exited=%d\n"
                      "wifi_companion_start.exit_code=%d\n"
                      "wifi_companion_start.signal=%d\n"
                      "wifi_companion_start.timed_out=%d\n"
                      "wifi_companion_start.term_sent=%d\n"
                      "wifi_companion_start.kill_sent=%d\n"
                      "wifi_companion_start.reaped=%d\n"
                      "wifi_companion_start.all_observable=%d\n"
                      "wifi_companion_start.all_postflight_safe=%d\n",
                      child_done ? 1 : 0,
                      *child_exit_code,
                      *child_signal,
                      *timed_out ? 1 : 0,
                      term_sent ? 1 : 0,
                      kill_sent ? 1 : 0,
                      reaped ? 1 : 0,
                      child_started ? 1 : 0,
                      postflight_safe ? 1 : 0) < 0) {
        goto fail;
    }
    if (!postflight_safe) {
        append_literal(stdout_buf,
                       "wifi_companion_start.result=subsys-hold-reboot-required\n"
                       "wifi_companion_start.reason=child-not-proven-stopped\n");
    } else if (*child_exit_code == 0) {
        append_literal(stdout_buf,
                       "wifi_companion_start.result=subsys-hold-window-pass\n"
                       "wifi_companion_start.reason=temporary-subsys-cdev-open-held-and-cleaned\n");
    } else {
        append_literal(stdout_buf,
                       "wifi_companion_start.result=subsys-hold-open-failed\n"
                       "wifi_companion_start.reason=no-subsys-cdev-open-succeeded\n");
    }
    append_literal(stdout_buf, "wifi_companion_start.end=1\n");
    if (stdout_pipe[0] >= 0) close(stdout_pipe[0]);
    unlink(modem_node);
    unlink(esoc_node);
    return 0;

fail:
    if (pid > 0) {
        kill(-pid, SIGKILL);
        kill(pid, SIGKILL);
        waitpid(pid, NULL, WNOHANG);
    }
    if (stdout_pipe[0] >= 0) close(stdout_pipe[0]);
    if (stdout_pipe[1] >= 0) close(stdout_pipe[1]);
    unlink(modem_node);
    unlink(esoc_node);
    return -1;
}

static int run_wifi_companion_esoc_req_registered_subsys_hold_preflight_guarded(const struct config *cfg,
                                                                               const struct paths *paths,
                                                                               struct buffer *stdout_buf,
                                                                               struct buffer *stderr_buf,
                                                                               int *child_exit_code,
                                                                               int *child_signal,
                                                                               bool *timed_out) {
    char esoc_path[MAX_PATH_LEN];
    bool conditional_response_mode = is_wifi_companion_esoc_conditional_response_preflight_mode(cfg->mode);
    bool mhi_observe_mode = is_wifi_companion_esoc_img_xfer_mhi_observe_mode(cfg->mode);
    int req_fd = -1;
    int req_rc = -1;
    int saved_errno = 0;
    int stdout_pipe[2] = {-1, -1};
    bool stdout_open = true;
    bool child_done = false;
    bool term_sent = false;
    bool kill_sent = false;
    bool reaped = false;
    bool postflight_safe = true;
    long deadline;
    pid_t pid = -1;
    pid_t pgid = -1;
    int status = 0;
    int hold_sec = cfg->timeout_sec > 3 ? cfg->timeout_sec - 2 : 1;

    (void)stderr_buf;
    *child_exit_code = -1;
    *child_signal = 0;
    *timed_out = false;
    if (append_format(stdout_buf,
                       "esoc_req_registered_subsys_hold_preflight.begin=1\n"
                       "esoc_req_registered_subsys_hold_preflight.mode=guarded\n"
                       "esoc_req_registered_subsys_hold_preflight.conditional_response_mode=%d\n"
                       "esoc_req_registered_subsys_hold_preflight.device=/dev/esoc-0\n"
                       "esoc_req_registered_subsys_hold_preflight.subsys_device=/dev/subsys_esoc0\n"
                       "esoc_req_registered_subsys_hold_preflight.daemon_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.mdm_helper_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.ks_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.pm_proxy_helper_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.cnss_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.service_manager_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.wifi_hal_start_executed=0\n"
                       "esoc_req_registered_subsys_hold_preflight.scan_connect_linkup=0\n"
                       "esoc_req_registered_subsys_hold_preflight.credentials=0\n"
                       "esoc_req_registered_subsys_hold_preflight.dhcp_routing=0\n"
                       "esoc_req_registered_subsys_hold_preflight.external_ping=0\n"
                       "esoc_req_registered_subsys_hold_preflight.reg_cmd_eng_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.cmd_exe_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.pwr_on_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.wait_for_req_loop_implemented=0\n"
                       "esoc_req_registered_subsys_hold_preflight.wait_for_req_passive_observer_supported=1\n"
                       "esoc_req_registered_subsys_hold_preflight.wait_for_req_passive_observer_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.wait_for_req_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.wait_for_req_success_semantic=nonnegative-sizeof-u32-byte-count\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold_supported=1\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold_attempted=%d\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold.live_response_attempted=%d\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold.notify_attempted=0\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold.ESOC_REQ_IMG.value=1\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold.ESOC_IMG_XFER_DONE.value=1\n"
                       "esoc_req_registered_subsys_hold_preflight.response_scaffold.ESOC_BOOT_DONE.value=2\n"
                       "esoc_req_registered_subsys_hold_preflight.notify_attempted=0\n",
                       conditional_response_mode ? 1 : 0,
                       conditional_response_mode ? 1 : 0,
                       conditional_response_mode ? 1 : 0) < 0 ||
        append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_CODE=0x%x\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_REG_REQ_ENG.request=0x%lx\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_REG_CMD_ENG.request=0x%lx\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_CMD_EXE.request=0x%lx\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_PWR_ON.value=%u\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_WAIT_FOR_REQ.request=0x%lx\n"
                      "esoc_req_registered_subsys_hold_preflight.uapi.ESOC_NOTIFY.request=0x%lx\n",
                      A90_ESOC_CODE,
                      (unsigned long)A90_ESOC_REG_REQ_ENG,
                      (unsigned long)A90_ESOC_REG_CMD_ENG,
                      (unsigned long)A90_ESOC_CMD_EXE,
                      A90_ESOC_PWR_ON,
                      (unsigned long)A90_ESOC_WAIT_FOR_REQ,
                      (unsigned long)A90_ESOC_NOTIFY) < 0 ||
        append_private_android_node_status(stdout_buf, paths, "esoc-0", "esoc_0") < 0 ||
        append_private_android_node_status(stdout_buf, paths, "subsys_esoc0", "subsys_esoc0") < 0 ||
        append_private_android_node_status(stdout_buf, paths, "subsys_modem", "subsys_modem") < 0) {
        return -1;
    }
    if (!(mhi_observe_mode
          ? cfg->allow_esoc_img_xfer_mhi_observe
          : (conditional_response_mode
             ? cfg->allow_esoc_conditional_response_preflight
             : cfg->allow_esoc_req_registered_subsys_hold_preflight))) {
        if (append_format(stdout_buf,
                           "esoc_req_registered_subsys_hold_preflight.allowed=0\n"
                           "esoc_req_registered_subsys_hold_preflight.open_req_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.reg_req_eng_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.wait_for_req_passive_observer_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.child_started=0\n"
                           "esoc_req_registered_subsys_hold_preflight.result=blocked\n"
                           "esoc_req_registered_subsys_hold_preflight.reason=%s\n"
                           "esoc_req_registered_subsys_hold_preflight.end=1\n",
                           mhi_observe_mode
                               ? "missing-esoc-img-xfer-mhi-observe-allow-flag"
                               : (conditional_response_mode
                                  ? "missing-esoc-conditional-response-preflight-allow-flag"
                                  : "missing-esoc-req-registered-subsys-hold-preflight-allow-flag")) < 0) {
            return -1;
        }
        *child_exit_code = 0;
        return 0;
    }
    if (append_literal(stdout_buf,
                       "esoc_req_registered_subsys_hold_preflight.allowed=1\n"
                       "esoc_req_registered_subsys_hold_preflight.open_req_attempted=1\n") < 0) {
        return -1;
    }
    if (append_path(esoc_path, sizeof(esoc_path), paths->dev, "esoc-0") < 0) {
        if (append_literal(stdout_buf,
                           "esoc_req_registered_subsys_hold_preflight.result=path-too-long\n"
                           "esoc_req_registered_subsys_hold_preflight.end=1\n") < 0) {
            return -1;
        }
        *child_exit_code = 0;
        return 0;
    }
    errno = 0;
    req_fd = open(esoc_path, O_RDONLY | O_CLOEXEC);
    saved_errno = req_fd < 0 ? errno : 0;
    if (append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.open_req.path=%s\n"
                      "esoc_req_registered_subsys_hold_preflight.open_req.fd=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.open_req.errno=%d\n",
                      esoc_path,
                      req_fd,
                      saved_errno) < 0) {
        if (req_fd >= 0) {
            close(req_fd);
        }
        return -1;
    }
    if (req_fd < 0) {
        if (append_literal(stdout_buf,
                           "esoc_req_registered_subsys_hold_preflight.reg_req_eng_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.child_started=0\n"
                           "esoc_req_registered_subsys_hold_preflight.result=open-req-failed\n"
                           "esoc_req_registered_subsys_hold_preflight.end=1\n") < 0) {
            return -1;
        }
        *child_exit_code = 0;
        return 0;
    }
    errno = 0;
    req_rc = ioctl(req_fd, A90_ESOC_REG_REQ_ENG);
    saved_errno = req_rc < 0 ? errno : 0;
    if (append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.reg_req_eng_attempted=1\n"
                      "esoc_req_registered_subsys_hold_preflight.ioctl.REG_REQ_ENG.request=0x%lx\n"
                      "esoc_req_registered_subsys_hold_preflight.ioctl.REG_REQ_ENG.rc=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.ioctl.REG_REQ_ENG.errno=%d\n",
                      (unsigned long)A90_ESOC_REG_REQ_ENG,
                      req_rc,
                      saved_errno) < 0) {
        close(req_fd);
        return -1;
    }
    if (req_rc < 0) {
        close(req_fd);
        if (append_literal(stdout_buf,
                           "esoc_req_registered_subsys_hold_preflight.close_req_attempted=1\n"
                           "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_attempted=0\n"
                           "esoc_req_registered_subsys_hold_preflight.child_started=0\n"
                           "esoc_req_registered_subsys_hold_preflight.result=reg-req-eng-failed\n"
                           "esoc_req_registered_subsys_hold_preflight.end=1\n") < 0) {
            return -1;
        }
        *child_exit_code = 0;
        return 0;
    }
    if (append_esoc_req_subsys_hold_snapshot(stdout_buf, "before") < 0 ||
        append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.req_fd_held=1\n"
                      "esoc_req_registered_subsys_hold_preflight.subsys_esoc0_open_attempted=1\n"
                      "esoc_req_registered_subsys_hold_preflight.wait_for_req_passive_observer_attempted=1\n"
                      "esoc_req_registered_subsys_hold_preflight.wait_for_req_attempted=1\n"
                      "esoc_req_registered_subsys_hold_preflight.hold_sec=%d\n",
                      hold_sec) < 0) {
        close(req_fd);
        return -1;
    }
    if (pipe2(stdout_pipe, O_CLOEXEC) < 0) {
        saved_errno = errno;
        close(req_fd);
        return append_format(stdout_buf,
                             "esoc_req_registered_subsys_hold_preflight.child_started=0\n"
                             "esoc_req_registered_subsys_hold_preflight.close_req_attempted=1\n"
                             "esoc_req_registered_subsys_hold_preflight.result=manual-review-required\n"
                             "esoc_req_registered_subsys_hold_preflight.reason=pipe-failed-%s\n"
                             "esoc_req_registered_subsys_hold_preflight.end=1\n",
                             strerror(saved_errno));
    }
    pid = fork();
    if (pid < 0) {
        saved_errno = errno;
        close(stdout_pipe[0]);
        close(stdout_pipe[1]);
        close(req_fd);
        return append_format(stdout_buf,
                             "esoc_req_registered_subsys_hold_preflight.child_started=0\n"
                             "esoc_req_registered_subsys_hold_preflight.close_req_attempted=1\n"
                             "esoc_req_registered_subsys_hold_preflight.result=manual-review-required\n"
                             "esoc_req_registered_subsys_hold_preflight.reason=fork-failed-%s\n"
                             "esoc_req_registered_subsys_hold_preflight.end=1\n",
                             strerror(saved_errno));
    }
    if (pid == 0) {
        int esoc_fd;
        pid_t observer_pid = -1;
        int observer_status = 0;
        int observer_exit_code = -1;
        int observer_signal = 0;
        bool observer_term_sent = false;
        bool observer_kill_sent = false;
        bool observer_reaped = false;

        close(stdout_pipe[0]);
        if (setsid() < 0) {
            dprintf(stdout_pipe[1], "esoc_req_registered_subsys_hold_preflight.child_setsid_error=%s\n", strerror(errno));
            _exit(120);
        }
        if (chroot(paths->root) < 0) {
            dprintf(stdout_pipe[1], "esoc_req_registered_subsys_hold_preflight.child_chroot_error=%s\n", strerror(errno));
            _exit(121);
        }
        if (chdir("/") < 0) {
            dprintf(stdout_pipe[1], "esoc_req_registered_subsys_hold_preflight.child_chdir_error=%s\n", strerror(errno));
            _exit(122);
        }
        dprintf(stdout_pipe[1],
                "esoc_req_registered_subsys_hold_preflight.child_chroot=1\n"
                "esoc_req_registered_subsys_hold_preflight.child_hold_sec=%d\n",
                hold_sec);
        observer_pid = fork();
        if (observer_pid < 0) {
            dprintf(stdout_pipe[1],
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.child_started=0\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.fork_errno=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.fork_error=%s\n",
                    errno,
                    strerror(errno));
        } else if (observer_pid == 0) {
            int observer_rc = mhi_observe_mode
                ? run_esoc_img_xfer_mhi_observe_child(stdout_pipe[1], req_fd, hold_sec)
                : (conditional_response_mode
                   ? run_esoc_conditional_response_child(stdout_pipe[1], req_fd, hold_sec)
                   : run_esoc_wait_for_req_observer_child(stdout_pipe[1], req_fd, hold_sec));

            _exit(observer_rc);
        } else {
            dprintf(stdout_pipe[1],
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.child_started=1\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.conditional_response=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.mhi_observe=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.pid=%ld\n",
                    conditional_response_mode ? 1 : 0,
                    mhi_observe_mode ? 1 : 0,
                    (long)observer_pid);
        }
        esoc_fd = open_esoc_req_registered_subsys_child_node(stdout_pipe[1]);
        if (esoc_fd >= 0) {
            for (int i = 0; i < hold_sec * 10; i++) {
                usleep(100000);
            }
            close(esoc_fd);
        }
        if (observer_pid > 0) {
            pid_t wait_rc = waitpid(observer_pid, &observer_status, WNOHANG);

            if (wait_rc == observer_pid) {
                observer_reaped = true;
            } else if (wait_rc == 0) {
                if (kill(observer_pid, SIGTERM) == 0 || errno == ESRCH) {
                    observer_term_sent = true;
                }
                for (int i = 0; i < 10 && !observer_reaped; i++) {
                    wait_rc = waitpid(observer_pid, &observer_status, WNOHANG);
                    if (wait_rc == observer_pid) {
                        observer_reaped = true;
                        break;
                    }
                    usleep(100000);
                }
                if (!observer_reaped && (kill(observer_pid, SIGKILL) == 0 || errno == ESRCH)) {
                    observer_kill_sent = true;
                }
                for (int i = 0; i < 10 && !observer_reaped; i++) {
                    wait_rc = waitpid(observer_pid, &observer_status, WNOHANG);
                    if (wait_rc == observer_pid) {
                        observer_reaped = true;
                        break;
                    }
                    usleep(100000);
                }
            }
            if (observer_reaped) {
                if (WIFEXITED(observer_status)) {
                    observer_exit_code = WEXITSTATUS(observer_status);
                } else if (WIFSIGNALED(observer_status)) {
                    observer_signal = WTERMSIG(observer_status);
                }
            }
            dprintf(stdout_pipe[1],
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.term_sent=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.kill_sent=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.reaped=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.exit_code=%d\n"
                    "esoc_req_registered_subsys_hold_preflight.wait_for_req_observer.signal=%d\n",
                    observer_term_sent ? 1 : 0,
                    observer_kill_sent ? 1 : 0,
                    observer_reaped ? 1 : 0,
                    observer_exit_code,
                    observer_signal);
        }
        dprintf(stdout_pipe[1],
                "esoc_req_registered_subsys_hold_preflight.child_done=1\n");
        close(stdout_pipe[1]);
        _exit(esoc_fd >= 0 ? 0 : 31);
    }

    close(stdout_pipe[1]);
    stdout_pipe[1] = -1;
    set_nonblock(stdout_pipe[0]);
    pgid = wait_for_child_session_pgid(pid, 1000);
    if (append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.child_started=1\n"
                      "esoc_req_registered_subsys_hold_preflight.pid=%ld\n"
                      "esoc_req_registered_subsys_hold_preflight.pgid=%ld\n",
                      (long)pid,
                      (long)pgid) < 0) {
        goto fail;
    }
    usleep(500000);
    drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
    if (append_esoc_req_subsys_hold_snapshot(stdout_buf, "hold") < 0) {
        goto fail;
    }
    deadline = monotonic_ms() + cfg->timeout_sec * 1000L;
    while (stdout_open || !child_done) {
        struct pollfd fds[1];
        int nfds = 0;

        if (!child_done && monotonic_ms() >= deadline) {
            *timed_out = true;
            break;
        }
        if (stdout_open) {
            fds[nfds].fd = stdout_pipe[0];
            fds[nfds].events = POLLIN | POLLHUP | POLLERR;
            nfds++;
        }
        if (nfds > 0 && poll(fds, nfds, 50) > 0 && fds[0].revents != 0) {
            drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
        } else {
            usleep(50000);
        }
        if (!child_done) {
            pid_t wait_rc = waitpid(pid, &status, WNOHANG);

            if (wait_rc == pid) {
                child_done = true;
                reaped = true;
                if (WIFEXITED(status)) {
                    *child_exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    *child_signal = WTERMSIG(status);
                }
            } else if (wait_rc < 0 && errno != EINTR && errno != ECHILD) {
                append_format(stdout_buf,
                              "esoc_req_registered_subsys_hold_preflight.wait_error=%s\n",
                              strerror(errno));
                break;
            }
        }
    }
    if (!child_done) {
        if (kill(-pgid, SIGTERM) == 0 || errno == ESRCH) {
            term_sent = true;
        }
        deadline = monotonic_ms() + 1000L;
        while (!child_done && monotonic_ms() < deadline) {
            if (waitpid(pid, &status, WNOHANG) == pid) {
                child_done = true;
                reaped = true;
                if (WIFEXITED(status)) {
                    *child_exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    *child_signal = WTERMSIG(status);
                }
                break;
            }
            if (stdout_open) {
                drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
            }
            usleep(50000);
        }
    }
    if (!child_done) {
        if (kill(-pgid, SIGKILL) == 0 || errno == ESRCH) {
            kill_sent = true;
        }
        deadline = monotonic_ms() + 1000L;
        while (!child_done && monotonic_ms() < deadline) {
            if (waitpid(pid, &status, WNOHANG) == pid) {
                child_done = true;
                reaped = true;
                if (WIFEXITED(status)) {
                    *child_exit_code = WEXITSTATUS(status);
                } else if (WIFSIGNALED(status)) {
                    *child_signal = WTERMSIG(status);
                }
                break;
            }
            usleep(50000);
        }
    }
    if (stdout_open) {
        drain_fd(stdout_pipe[0], stdout_buf, &stdout_open);
    }
    close(req_fd);
    req_fd = -1;
    postflight_safe = reaped && (kill(-pgid, 0) < 0 && errno == ESRCH);
    if (append_esoc_req_subsys_hold_snapshot(stdout_buf, "after") < 0 ||
        append_format(stdout_buf,
                      "esoc_req_registered_subsys_hold_preflight.close_req_attempted=1\n"
                      "esoc_req_registered_subsys_hold_preflight.exited=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.exit_code=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.signal=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.timed_out=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.term_sent=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.kill_sent=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.reaped=%d\n"
                      "esoc_req_registered_subsys_hold_preflight.all_postflight_safe=%d\n",
                      child_done ? 1 : 0,
                      *child_exit_code,
                      *child_signal,
                      *timed_out ? 1 : 0,
                      term_sent ? 1 : 0,
                      kill_sent ? 1 : 0,
                      reaped ? 1 : 0,
                      postflight_safe ? 1 : 0) < 0) {
        goto fail;
    }
    if (!postflight_safe) {
        append_literal(stdout_buf,
                       "esoc_req_registered_subsys_hold_preflight.result=reboot-required\n"
                       "esoc_req_registered_subsys_hold_preflight.reason=child-not-proven-stopped\n");
    } else if (*child_exit_code == 0) {
        append_literal(stdout_buf,
                       "esoc_req_registered_subsys_hold_preflight.result=req-registered-subsys-hold-window-pass\n"
                       "esoc_req_registered_subsys_hold_preflight.reason=req-engine-held-while-subsys-esoc0-opened-and-cleaned\n");
    } else {
        append_literal(stdout_buf,
                       "esoc_req_registered_subsys_hold_preflight.result=subsys-esoc0-open-failed\n"
                       "esoc_req_registered_subsys_hold_preflight.reason=subsys-cdev-open-did-not-succeed\n");
    }
    append_literal(stdout_buf, "esoc_req_registered_subsys_hold_preflight.end=1\n");
    if (stdout_pipe[0] >= 0) close(stdout_pipe[0]);
    return 0;

fail:
    if (pid > 0) {
        kill(-pid, SIGKILL);
        kill(pid, SIGKILL);
        waitpid(pid, NULL, WNOHANG);
    }
    if (req_fd >= 0) close(req_fd);
    if (stdout_pipe[0] >= 0) close(stdout_pipe[0]);
    if (stdout_pipe[1] >= 0) close(stdout_pipe[1]);
    return -1;
}


static pid_t wait_for_child_session_pgid(pid_t pid, long timeout_ms) {
    long deadline = monotonic_ms() + timeout_ms;

    while (monotonic_ms() < deadline) {
        pid_t pgid = getpgid(pid);

        if (pgid == pid) {
            return pgid;
        }
        if (pgid < 0 && errno == ESRCH) {
            break;
        }
        usleep(10000);
    }
    return pid;
}

static int append_proc_fd_summary(struct buffer *buf, pid_t pid, bool *captured) {
    char path[MAX_PATH_LEN];
    DIR *dir;
    struct dirent *entry;
    int count = 0;

    *captured = false;
    proc_path(path, sizeof(path), pid, "fd");
    dir = opendir(path);
    if (dir == NULL) {
        return append_format(buf, "cnss_start.fd_summary.error=%s\n", strerror(errno));
    }
    while ((entry = readdir(dir)) != NULL) {
        if (strcmp(entry->d_name, ".") == 0 || strcmp(entry->d_name, "..") == 0) {
            continue;
        }
        count++;
    }
    closedir(dir);
    *captured = true;
    return append_format(buf, "cnss_start.fd_summary.count=%d\n", count);
}

static int append_proc_fdinfo_compact(struct buffer *buf,
                                      pid_t pid,
                                      const char *label,
                                      int entry_index,
                                      const char *fd_name) {
    char path[MAX_PATH_LEN];
    FILE *file;
    char line[256];
    int line_count = 0;
    bool truncated = false;

    if (snprintf(path,
                 sizeof(path),
                 "/proc/%ld/fdinfo/%s",
                 (long)pid,
                 fd_name) >= (int)sizeof(path)) {
        return append_format(buf,
                             "capture.%s.fd_links.entry_%02d.fdinfo.error=path-too-long\n",
                             label,
                             entry_index);
    }
    if (append_format(buf,
                      "capture.%s.fd_links.entry_%02d.fdinfo.begin=1\n"
                      "capture.%s.fd_links.entry_%02d.fdinfo.path=%s\n",
                      label,
                      entry_index,
                      label,
                      entry_index,
                      path) < 0) {
        return -1;
    }
    file = fopen(path, "re");
    if (file == NULL) {
        return append_format(buf,
                             "capture.%s.fd_links.entry_%02d.fdinfo.error=%s\n"
                             "capture.%s.fd_links.entry_%02d.fdinfo.end=1\n",
                             label,
                             entry_index,
                             strerror(errno),
                             label,
                             entry_index);
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        char key[64];
        char value[160];
        int parsed;

        sanitize_one_line(line);
        if (line_count < 16) {
            if (append_format(buf,
                              "capture.%s.fd_links.entry_%02d.fdinfo.line_%02d=%s\n",
                              label,
                              entry_index,
                              line_count,
                              line) < 0) {
                fclose(file);
                return -1;
            }
        } else {
            truncated = true;
        }
        parsed = sscanf(line, "%63[^:]:%159s", key, value);
        if (parsed == 2 &&
            (strcmp(key, "pos") == 0 ||
             strcmp(key, "flags") == 0 ||
             strcmp(key, "mnt_id") == 0 ||
             strcmp(key, "ino") == 0)) {
            if (append_format(buf,
                              "capture.%s.fd_links.entry_%02d.fdinfo.%s=%s\n",
                              label,
                              entry_index,
                              key,
                              value) < 0) {
                fclose(file);
                return -1;
            }
        }
        line_count++;
    }
    fclose(file);
    return append_format(buf,
                         "capture.%s.fd_links.entry_%02d.fdinfo.lines=%d\n"
                         "capture.%s.fd_links.entry_%02d.fdinfo.truncated=%d\n"
                         "capture.%s.fd_links.entry_%02d.fdinfo.end=1\n",
                         label,
                         entry_index,
                         line_count < 16 ? line_count : 16,
                         label,
                         entry_index,
                         truncated ? 1 : 0,
                         label,
                         entry_index);
}

static int append_proc_fd_links_compact(struct buffer *buf, pid_t pid, const char *label) {
    char dir_path[MAX_PATH_LEN];
    DIR *dir;
    struct dirent *entry;
    int count = 0;
    int shown = 0;
    int socket_count = 0;
    int anon_inode_count = 0;
    bool truncated = false;

    proc_path(dir_path, sizeof(dir_path), pid, "fd");
    if (append_format(buf,
                      "capture.%s.fd_links.begin=1\n"
                      "capture.%s.fd_links.path=%s\n",
                      label,
                      label,
                      dir_path) < 0) {
        return -1;
    }
    dir = opendir(dir_path);
    if (dir == NULL) {
        return append_format(buf,
                             "capture.%s.fd_links.error=%s\n"
                             "capture.%s.fd_links.end=1\n",
                             label,
                             strerror(errno),
                             label);
    }
    while ((entry = readdir(dir)) != NULL) {
        char fd_path[MAX_PATH_LEN];
        char target[MAX_PATH_LEN];
        ssize_t nread;

        if (strcmp(entry->d_name, ".") == 0 || strcmp(entry->d_name, "..") == 0) {
            continue;
        }
        count++;
        if (snprintf(fd_path, sizeof(fd_path), "%s/%s", dir_path, entry->d_name) >= (int)sizeof(fd_path)) {
            truncated = true;
            continue;
        }
        nread = readlink(fd_path, target, sizeof(target) - 1);
        if (nread < 0) {
            if (shown < 64 &&
                append_format(buf,
                              "capture.%s.fd_links.entry_%02d.fd=%s\n"
                              "capture.%s.fd_links.entry_%02d.error=%s\n",
                              label,
                              shown,
                              entry->d_name,
                              label,
                              shown,
                              strerror(errno)) < 0) {
                closedir(dir);
                return -1;
            }
            shown++;
            continue;
        }
        target[nread] = '\0';
        if (strncmp(target, "socket:", 7) == 0) {
            socket_count++;
        }
        if (strncmp(target, "anon_inode:", 11) == 0) {
            anon_inode_count++;
        }
        if (shown < 64) {
            if (append_format(buf,
                              "capture.%s.fd_links.entry_%02d.fd=%s\n"
                              "capture.%s.fd_links.entry_%02d.target=%s\n",
                              label,
                              shown,
                              entry->d_name,
                              label,
                              shown,
                              target) < 0) {
                closedir(dir);
                return -1;
            }
            if (strncmp(target, "socket:", 7) == 0 &&
                append_proc_fdinfo_compact(buf, pid, label, shown, entry->d_name) < 0) {
                closedir(dir);
                return -1;
            }
        } else {
            truncated = true;
        }
        shown++;
    }
    closedir(dir);
    return append_format(buf,
                         "capture.%s.fd_links.count=%d\n"
                         "capture.%s.fd_links.socket_count=%d\n"
                         "capture.%s.fd_links.anon_inode_count=%d\n"
                         "capture.%s.fd_links.shown=%d\n"
                         "capture.%s.fd_links.truncated=%d\n"
                         "capture.%s.fd_links.end=1\n",
                         label,
                         count,
                         label,
                         socket_count,
                         label,
                         anon_inode_count,
                         label,
                         shown < 64 ? shown : 64,
                         label,
                         truncated ? 1 : 0,
                         label);
}

static bool decimal_name(const char *name) {
    if (name == NULL || *name == '\0') {
        return false;
    }
    for (const char *ptr = name; *ptr != '\0'; ptr++) {
        if (*ptr < '0' || *ptr > '9') {
            return false;
        }
    }
    return true;
}

static int append_proc_task_stall_capture(struct buffer *buf, pid_t pid, const char *label) {
    char task_path[MAX_PATH_LEN];
    DIR *dir;
    struct dirent *entry;
    int count = 0;
    int shown = 0;
    bool truncated = false;

    if (snprintf(task_path, sizeof(task_path), "/proc/%ld/task", (long)pid) >= (int)sizeof(task_path)) {
        return append_format(buf,
                             "capture.%s.stall_tasks.begin=1\n"
                             "capture.%s.stall_tasks.error=path-too-long\n"
                             "capture.%s.stall_tasks.end=1\n",
                             label,
                             label,
                             label);
    }
    if (append_format(buf,
                      "capture.%s.stall_tasks.begin=1\n"
                      "capture.%s.stall_tasks.path=%s\n",
                      label,
                      label,
                      task_path) < 0) {
        return -1;
    }
    dir = opendir(task_path);
    if (dir == NULL) {
        return append_format(buf,
                             "capture.%s.stall_tasks.error=%s\n"
                             "capture.%s.stall_tasks.end=1\n",
                             label,
                             strerror(errno),
                             label);
    }
    while ((entry = readdir(dir)) != NULL) {
        char path[MAX_PATH_LEN];
        char capture_label[160];
        bool captured = false;

        if (!decimal_name(entry->d_name)) {
            continue;
        }
        count++;
        if (shown >= 16) {
            truncated = true;
            continue;
        }
        if (append_format(buf,
                          "capture.%s.stall_tasks.entry_%02d.tid=%s\n",
                          label,
                          shown,
                          entry->d_name) < 0) {
            closedir(dir);
            return -1;
        }
        if (snprintf(path, sizeof(path), "%s/%s/status", task_path, entry->d_name) < (int)sizeof(path) &&
            snprintf(capture_label, sizeof(capture_label), "%s_stall_task_%s_status", label, entry->d_name) < (int)sizeof(capture_label) &&
            append_path_file_capture_named(buf, path, capture_label, 4096, &captured) < 0) {
            closedir(dir);
            return -1;
        }
        if (snprintf(path, sizeof(path), "%s/%s/stat", task_path, entry->d_name) < (int)sizeof(path) &&
            snprintf(capture_label, sizeof(capture_label), "%s_stall_task_%s_stat", label, entry->d_name) < (int)sizeof(capture_label) &&
            append_path_file_capture_named(buf, path, capture_label, 2048, &captured) < 0) {
            closedir(dir);
            return -1;
        }
        if (snprintf(path, sizeof(path), "%s/%s/wchan", task_path, entry->d_name) < (int)sizeof(path) &&
            snprintf(capture_label, sizeof(capture_label), "%s_stall_task_%s_wchan", label, entry->d_name) < (int)sizeof(capture_label) &&
            append_path_file_capture_named(buf, path, capture_label, 1024, &captured) < 0) {
            closedir(dir);
            return -1;
        }
        if (snprintf(path, sizeof(path), "%s/%s/syscall", task_path, entry->d_name) < (int)sizeof(path) &&
            snprintf(capture_label, sizeof(capture_label), "%s_stall_task_%s_syscall", label, entry->d_name) < (int)sizeof(capture_label) &&
            append_path_file_capture_named(buf, path, capture_label, 1024, &captured) < 0) {
            closedir(dir);
            return -1;
        }
        shown++;
    }
    closedir(dir);
    return append_format(buf,
                         "capture.%s.stall_tasks.count=%d\n"
                         "capture.%s.stall_tasks.shown=%d\n"
                         "capture.%s.stall_tasks.truncated=%d\n"
                         "capture.%s.stall_tasks.end=1\n",
                         label,
                         count,
                         label,
                         shown,
                         label,
                         truncated ? 1 : 0,
                         label);
}

static int append_cnss_stall_snapshot_capture(struct buffer *buf, pid_t pid, const char *label) {
    bool wchan_captured = false;
    bool syscall_captured = false;
    bool stack_captured = false;
    bool stat_captured = false;
    bool sched_captured = false;
    bool netlink_captured = false;
    bool unix_captured = false;
    bool qrtr_captured = false;
    bool protocols_captured = false;
    bool task_captured = false;

    if (append_format(buf,
                      "capture.%s.stall_snapshot.begin=1\n"
                      "capture.%s.stall_snapshot.pid=%ld\n",
                      label,
                      label,
                      (long)pid) < 0 ||
        append_proc_file_capture_named(buf, pid, "wchan", "wifi_stall_cnss_wchan", 1024, &wchan_captured) < 0 ||
        append_proc_file_capture_named(buf, pid, "syscall", "wifi_stall_cnss_syscall", 1024, &syscall_captured) < 0 ||
        append_proc_file_capture_named(buf, pid, "stack", "wifi_stall_cnss_stack", 8192, &stack_captured) < 0 ||
        append_proc_file_capture_named(buf, pid, "stat", "wifi_stall_cnss_stat", 2048, &stat_captured) < 0 ||
        append_proc_file_capture_named(buf, pid, "sched", "wifi_stall_cnss_sched", 8192, &sched_captured) < 0 ||
        append_path_file_capture_named(buf, "/proc/net/netlink", "wifi_stall_proc_net_netlink", 32768, &netlink_captured) < 0 ||
        append_path_file_capture_named(buf, "/proc/net/unix", "wifi_stall_proc_net_unix", 32768, &unix_captured) < 0 ||
        append_path_file_capture_named(buf, "/proc/net/qrtr", "wifi_stall_proc_net_qrtr", 32768, &qrtr_captured) < 0 ||
        append_path_file_capture_named(buf, "/proc/net/protocols", "wifi_stall_proc_net_protocols", 32768, &protocols_captured) < 0 ||
        append_proc_task_stall_capture(buf, pid, label) < 0) {
        return -1;
    }
    task_captured = true;
    return append_format(buf,
                         "capture.%s.stall_snapshot.wchan_captured=%d\n"
                         "capture.%s.stall_snapshot.syscall_captured=%d\n"
                         "capture.%s.stall_snapshot.stack_captured=%d\n"
                         "capture.%s.stall_snapshot.stat_captured=%d\n"
                         "capture.%s.stall_snapshot.sched_captured=%d\n"
                         "capture.%s.stall_snapshot.netlink_captured=%d\n"
                         "capture.%s.stall_snapshot.unix_captured=%d\n"
                         "capture.%s.stall_snapshot.qrtr_captured=%d\n"
                         "capture.%s.stall_snapshot.protocols_captured=%d\n"
                         "capture.%s.stall_snapshot.task_captured=%d\n"
                         "capture.%s.stall_snapshot.end=1\n",
                         label,
                         wchan_captured ? 1 : 0,
                         label,
                         syscall_captured ? 1 : 0,
                         label,
                         stack_captured ? 1 : 0,
                         label,
                         stat_captured ? 1 : 0,
                         label,
                         sched_captured ? 1 : 0,
                         label,
                         netlink_captured ? 1 : 0,
                         label,
                         unix_captured ? 1 : 0,
                         label,
                         qrtr_captured ? 1 : 0,
                         label,
                         protocols_captured ? 1 : 0,
                         label,
                         task_captured ? 1 : 0,
                         label);
}

static int append_generic_stall_snapshot_capture(struct buffer *buf, pid_t pid, const char *label) {
    char capture_label[160];
    bool wchan_captured = false;
    bool syscall_captured = false;
    bool stack_captured = false;
    bool stat_captured = false;
    bool status_captured = false;
    bool sched_captured = false;
    bool task_captured = false;

    if (append_format(buf,
                      "capture.%s.stall_snapshot.begin=1\n"
                      "capture.%s.stall_snapshot.pid=%ld\n",
                      label,
                      label,
                      (long)pid) < 0) {
        return -1;
    }
    if (snprintf(capture_label, sizeof(capture_label), "%s_wchan", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "wchan", capture_label, 1024, &wchan_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_syscall", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "syscall", capture_label, 1024, &syscall_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_stack", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "stack", capture_label, 8192, &stack_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_stat", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "stat", capture_label, 2048, &stat_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_status", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "status", capture_label, 8192, &status_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_sched", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "sched", capture_label, 8192, &sched_captured) < 0 ||
        append_proc_task_stall_capture(buf, pid, label) < 0) {
        return -1;
    }
    task_captured = true;
    return append_format(buf,
                         "capture.%s.stall_snapshot.wchan_captured=%d\n"
                         "capture.%s.stall_snapshot.syscall_captured=%d\n"
                         "capture.%s.stall_snapshot.stack_captured=%d\n"
                         "capture.%s.stall_snapshot.stat_captured=%d\n"
                         "capture.%s.stall_snapshot.status_captured=%d\n"
                         "capture.%s.stall_snapshot.sched_captured=%d\n"
                         "capture.%s.stall_snapshot.task_captured=%d\n"
                         "capture.%s.stall_snapshot.end=1\n",
                         label,
                         wchan_captured ? 1 : 0,
                         label,
                         syscall_captured ? 1 : 0,
                         label,
                         stack_captured ? 1 : 0,
                         label,
                         stat_captured ? 1 : 0,
                         label,
                         status_captured ? 1 : 0,
                         label,
                         sched_captured ? 1 : 0,
                         label,
                         task_captured ? 1 : 0,
                         label);
}

static int append_qipcrtr_protocol_summary(struct buffer *buf, const char *prefix) {
    FILE *file;
    char line[512];
    bool found = false;
    int sockets = -1;
    long size = -1;

    if (append_format(buf, "%s.begin=1\n", prefix) < 0) {
        return -1;
    }
    file = fopen("/proc/net/protocols", "re");
    if (file == NULL) {
        return append_format(buf,
                             "%s.protocols_open=0\n"
                             "%s.protocols_error=%s\n"
                             "%s.qipcrtr_present=0\n"
                             "%s.qipcrtr_sockets=-1\n"
                             "%s.end=1\n",
                             prefix,
                             prefix,
                             strerror(errno),
                             prefix,
                             prefix,
                             prefix);
    }
    while (fgets(line, sizeof(line), file) != NULL) {
        char name[64];
        long parsed_size;
        int parsed_sockets;
        size_t len = strlen(line);

        while (len > 0 && (line[len - 1] == '\n' || line[len - 1] == '\r')) {
            line[--len] = '\0';
        }
        if (sscanf(line, "%63s %ld %d", name, &parsed_size, &parsed_sockets) == 3 &&
            strcmp(name, "QIPCRTR") == 0) {
            found = true;
            size = parsed_size;
            sockets = parsed_sockets;
            if (append_format(buf, "%s.qipcrtr_line=%s\n", prefix, line) < 0) {
                fclose(file);
                return -1;
            }
            break;
        }
    }
    fclose(file);
    return append_format(buf,
                         "%s.protocols_open=1\n"
                         "%s.qipcrtr_present=%d\n"
                         "%s.qipcrtr_size=%ld\n"
                         "%s.qipcrtr_sockets=%d\n"
                         "%s.end=1\n",
                         prefix,
                         prefix,
                         found ? 1 : 0,
                         prefix,
                         size,
                         prefix,
                         sockets,
                         prefix);
}

static bool parse_pid_name(const char *text, pid_t *pid) {
    char *end = NULL;
    long value;

    if (text == NULL || *text == '\0') {
        return false;
    }
    errno = 0;
    value = strtol(text, &end, 10);
    if (errno != 0 || end == text || *end != '\0' || value <= 0) {
        return false;
    }
    *pid = (pid_t)value;
    return true;
}

static void read_proc_comm(pid_t pid, char *out, size_t out_size) {
    char path[MAX_PATH_LEN];
    FILE *file;

    if (out_size == 0) {
        return;
    }
    out[0] = '\0';
    proc_path(path, sizeof(path), pid, "comm");
    file = fopen(path, "re");
    if (file == NULL) {
        snprintf(out, out_size, "unknown");
        return;
    }
    if (fgets(out, (int)out_size, file) == NULL) {
        snprintf(out, out_size, "unknown");
    } else {
        size_t len = strlen(out);

        while (len > 0 && (out[len - 1] == '\n' || out[len - 1] == '\r')) {
            out[--len] = '\0';
        }
    }
    fclose(file);
}

static char read_proc_state(pid_t pid) {
    char path[MAX_PATH_LEN];
    char line[512];
    FILE *file;
    char *close_paren;

    proc_path(path, sizeof(path), pid, "stat");
    file = fopen(path, "re");
    if (file == NULL) {
        return '?';
    }
    if (fgets(line, sizeof(line), file) == NULL) {
        fclose(file);
        return '?';
    }
    fclose(file);
    close_paren = strrchr(line, ')');
    if (close_paren == NULL || close_paren[1] != ' ' || close_paren[2] == '\0') {
        return '?';
    }
    return close_paren[2];
}

static bool read_first_line_path(const char *path, char *out, size_t out_size) {
    FILE *file;
    size_t len;

    if (out_size == 0) {
        return false;
    }
    out[0] = '\0';
    file = fopen(path, "re");
    if (file == NULL) {
        return false;
    }
    if (fgets(out, (int)out_size, file) == NULL) {
        fclose(file);
        out[0] = '\0';
        return false;
    }
    fclose(file);
    len = strlen(out);
    while (len > 0 && (out[len - 1] == '\n' || out[len - 1] == '\r')) {
        out[--len] = '\0';
    }
    return true;
}

static bool read_proc_cmdline_compact(pid_t pid, char *out, size_t out_size) {
    char path[MAX_PATH_LEN];
    int fd;
    ssize_t nread;

    if (out_size == 0) {
        return false;
    }
    out[0] = '\0';
    proc_path(path, sizeof(path), pid, "cmdline");
    fd = open(path, O_RDONLY | O_CLOEXEC);
    if (fd < 0) {
        return false;
    }
    nread = read(fd, out, out_size - 1);
    close(fd);
    if (nread <= 0) {
        return false;
    }
    out[nread] = '\0';
    for (ssize_t i = 0; i < nread; i++) {
        if (out[i] == '\0') {
            out[i] = ' ';
        }
    }
    sanitize_one_line(out);
    return true;
}

static int append_process_cmdline_match_scan(struct buffer *buf,
                                             const char *prefix,
                                             const char *phase,
                                             const char *needle,
                                             int max_entries,
                                             int *match_count) {
    DIR *dir;
    struct dirent *entry;
    int count = 0;
    int shown = 0;

    *match_count = -1;
    dir = opendir("/proc");
    if (dir == NULL) {
        return append_format(buf,
                             "%s.process_scan.%s.error=%s\n",
                             prefix,
                             phase,
                             strerror(errno));
    }
    while ((entry = readdir(dir)) != NULL) {
        pid_t pid;
        char cmdline[512];
        char comm[128];
        char state;

        if (!parse_pid_name(entry->d_name, &pid)) {
            continue;
        }
        if (!read_proc_cmdline_compact(pid, cmdline, sizeof(cmdline))) {
            continue;
        }
        if (strstr(cmdline, needle) == NULL) {
            continue;
        }
        read_proc_comm(pid, comm, sizeof(comm));
        state = read_proc_state(pid);
        if (shown < max_entries) {
            if (append_format(buf,
                              "%s.process_scan.%s.entry.%d.pid=%ld\n"
                              "%s.process_scan.%s.entry.%d.state=%c\n"
                              "%s.process_scan.%s.entry.%d.comm=%s\n"
                              "%s.process_scan.%s.entry.%d.cmdline=%s\n",
                              prefix,
                              phase,
                              shown,
                              (long)pid,
                              prefix,
                              phase,
                              shown,
                              state,
                              prefix,
                              phase,
                              shown,
                              comm,
                              prefix,
                              phase,
                              shown,
                              cmdline) < 0) {
                closedir(dir);
                return -1;
            }
            shown++;
        }
        count++;
    }
    closedir(dir);
    *match_count = count;
    return append_format(buf,
                         "%s.process_scan.%s.needle=%s\n"
                         "%s.process_scan.%s.count=%d\n"
                         "%s.process_scan.%s.shown=%d\n",
                         prefix,
                         phase,
                         needle,
                         prefix,
                         phase,
                         count,
                         prefix,
                         phase,
                         shown);
}

