static int mirror_mdm_helper_runtime_mhi_pipe_if_present(struct buffer *buf,
                                                         const struct paths *paths,
                                                         const char *phase) {
    const char *global_mhi = "/dev/mhi_0305_01.01.00_pipe_10";
    char private_mhi[MAX_PATH_LEN];
    struct stat global_st;
    struct stat private_st;
    int global_errno = 0;
    int private_errno = 0;
    int mirror_errno = 0;
    bool global_exists;
    bool private_ready;
    bool private_exists;
    bool mirrored = false;

    global_exists = stat(global_mhi, &global_st) == 0;
    if (!global_exists) {
        global_errno = errno;
    }
    private_ready =
        append_path(private_mhi, sizeof(private_mhi), paths->dev, "mhi_0305_01.01.00_pipe_10") == 0;
    private_exists = private_ready && lstat(private_mhi, &private_st) == 0;
    if (private_ready && !private_exists) {
        private_errno = errno;
    }
    if (global_exists && S_ISCHR(global_st.st_mode) && private_ready && !private_exists) {
        if (mknod(private_mhi, S_IFCHR | 0660, global_st.st_rdev) == 0 &&
            chmod(private_mhi, 0660) == 0) {
            mirrored = true;
            private_exists = true;
            private_errno = 0;
        } else {
            mirror_errno = errno;
        }
    }
    return append_format(buf,
                         "mdm_helper_runtime_contract.mhi_mirror.%s.global_exists=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.global_errno=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.global_is_chr=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.private_ready=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.private_exists=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.private_errno=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.mirrored=%d\n"
                         "mdm_helper_runtime_contract.mhi_mirror.%s.mirror_errno=%d\n",
                         phase,
                         global_exists ? 1 : 0,
                         phase,
                         global_errno,
                         phase,
                         (global_exists && S_ISCHR(global_st.st_mode)) ? 1 : 0,
                         phase,
                         private_ready ? 1 : 0,
                         phase,
                         private_exists ? 1 : 0,
                         phase,
                         private_errno,
                         phase,
                         mirrored ? 1 : 0,
                         phase,
                         mirror_errno);
}

static int append_proc_fd_target_match_scan(struct buffer *buf,
                                            pid_t pid,
                                            const char *prefix,
                                            const char *phase,
                                            const char *needle,
                                            int *match_count) {
    char dir_path[MAX_PATH_LEN];
    DIR *dir;
    struct dirent *entry;
    int count = 0;
    int shown = 0;
    bool truncated = false;

    *match_count = -1;
    proc_path(dir_path, sizeof(dir_path), pid, "fd");
    if (append_format(buf,
                      "%s.fd_match.%s.begin=1\n"
                      "%s.fd_match.%s.pid=%ld\n"
                      "%s.fd_match.%s.needle=%s\n"
                      "%s.fd_match.%s.path=%s\n",
                      prefix,
                      phase,
                      prefix,
                      phase,
                      (long)pid,
                      prefix,
                      phase,
                      needle,
                      prefix,
                      phase,
                      dir_path) < 0) {
        return -1;
    }
    dir = opendir(dir_path);
    if (dir == NULL) {
        return append_format(buf,
                             "%s.fd_match.%s.error=%s\n"
                             "%s.fd_match.%s.count=-1\n"
                             "%s.fd_match.%s.end=1\n",
                             prefix,
                             phase,
                             strerror(errno),
                             prefix,
                             phase,
                             prefix,
                             phase);
    }
    while ((entry = readdir(dir)) != NULL) {
        char fd_path[MAX_PATH_LEN];
        char target[MAX_PATH_LEN];
        ssize_t nread;

        if (strcmp(entry->d_name, ".") == 0 || strcmp(entry->d_name, "..") == 0) {
            continue;
        }
        if (snprintf(fd_path, sizeof(fd_path), "%s/%s", dir_path, entry->d_name) >= (int)sizeof(fd_path)) {
            truncated = true;
            continue;
        }
        nread = readlink(fd_path, target, sizeof(target) - 1);
        if (nread < 0) {
            continue;
        }
        target[nread] = '\0';
        if (strstr(target, needle) == NULL) {
            continue;
        }
        count++;
        if (shown >= 16) {
            truncated = true;
            continue;
        }
        sanitize_one_line(target);
        if (append_format(buf,
                          "%s.fd_match.%s.entry_%02d.fd=%s\n"
                          "%s.fd_match.%s.entry_%02d.target=%s\n",
                          prefix,
                          phase,
                          shown,
                          entry->d_name,
                          prefix,
                          phase,
                          shown,
                          target) < 0) {
            closedir(dir);
            return -1;
        }
        {
            char fdinfo_label[160];

            if (snprintf(fdinfo_label,
                         sizeof(fdinfo_label),
                         "%s.%s",
                         prefix,
                         phase) >= (int)sizeof(fdinfo_label) ||
                append_proc_fdinfo_compact(buf, pid, fdinfo_label, shown, entry->d_name) < 0) {
                closedir(dir);
                return -1;
            }
        }
        shown++;
    }
    closedir(dir);
    *match_count = count;
    return append_format(buf,
                         "%s.fd_match.%s.count=%d\n"
                         "%s.fd_match.%s.shown=%d\n"
                         "%s.fd_match.%s.truncated=%d\n"
                         "%s.fd_match.%s.end=1\n",
                         prefix,
                         phase,
                         count,
                         prefix,
                         phase,
                         shown,
                         prefix,
                         phase,
                         truncated ? 1 : 0,
                         prefix,
                         phase);
}

static int count_proc_fd_target_matches(pid_t pid, const char *needle) {
    char dir_path[MAX_PATH_LEN];
    DIR *dir;
    struct dirent *entry;
    int count = 0;

    proc_path(dir_path, sizeof(dir_path), pid, "fd");
    dir = opendir(dir_path);
    if (dir == NULL) {
        return -1;
    }
    while ((entry = readdir(dir)) != NULL) {
        char fd_path[MAX_PATH_LEN];
        char target[MAX_PATH_LEN];
        ssize_t nread;

        if (strcmp(entry->d_name, ".") == 0 || strcmp(entry->d_name, "..") == 0) {
            continue;
        }
        if (snprintf(fd_path, sizeof(fd_path), "%s/%s", dir_path, entry->d_name) >= (int)sizeof(fd_path)) {
            continue;
        }
        nread = readlink(fd_path, target, sizeof(target) - 1);
        if (nread < 0) {
            continue;
        }
        target[nread] = '\0';
        if (strstr(target, needle) != NULL) {
            count++;
        }
    }
    closedir(dir);
    return count;
}

static int count_all_proc_fd_target_matches(const char *needle) {
    DIR *dir;
    struct dirent *entry;
    int count = 0;

    dir = opendir("/proc");
    if (dir == NULL) {
        return -1;
    }
    while ((entry = readdir(dir)) != NULL) {
        pid_t pid;
        int one_count;

        if (!parse_pid_name(entry->d_name, &pid)) {
            continue;
        }
        one_count = count_proc_fd_target_matches(pid, needle);
        if (one_count > 0) {
            count += one_count;
        }
    }
    closedir(dir);
    return count;
}

static int count_process_cmdline_or_comm_matches(const char *cmdline_needle,
                                                 const char *comm_exact) {
    DIR *dir;
    struct dirent *entry;
    int count = 0;

    dir = opendir("/proc");
    if (dir == NULL) {
        return -1;
    }
    while ((entry = readdir(dir)) != NULL) {
        pid_t pid;
        char cmdline[512];
        char comm[128];
        bool matched = false;

        if (!parse_pid_name(entry->d_name, &pid)) {
            continue;
        }
        if (cmdline_needle != NULL &&
            read_proc_cmdline_compact(pid, cmdline, sizeof(cmdline)) &&
            strstr(cmdline, cmdline_needle) != NULL) {
            matched = true;
        }
        if (!matched && comm_exact != NULL) {
            read_proc_comm(pid, comm, sizeof(comm));
            if (strcmp(comm, comm_exact) == 0) {
                matched = true;
            }
        }
        if (matched) {
            count++;
        }
    }
    closedir(dir);
    return count;
}

