static const char *cnss_wlfw_pre_checkpoint(const struct mdm2ap_timing_summary *summary) {
    const bool cnss_daemon_started = summary->cnss_daemon_process_max > 0;
    const bool cld80211_seen = summary->cld80211_kmsg_max > 0;
    const bool wlfw_started =
        summary->wlfw_start_kmsg_max > 0 ||
        summary->wlfw_service_request_kmsg_max > 0;
    const bool icnss_qmi_seen = summary->icnss_qmi_kmsg_max > 0;
    const bool bdf_seen = summary->bdf_kmsg_max > 0;
    const bool fw_ready_seen = summary->fw_ready_kmsg_max > 0;

    if (!cnss_daemon_started) {
        return "cnss-not-started";
    }
    if (!cld80211_seen || !wlfw_started) {
        return "cnss-netlink-only";
    }
    if (!icnss_qmi_seen) {
        return "wlfw-start-no-qmi";
    }
    if (!bdf_seen) {
        return "qmi-no-bdf";
    }
    if (!fw_ready_seen) {
        return "bdf-no-fw-ready";
    }
    if (!summary->wlan0_seen) {
        return "fw-ready-no-wlan0";
    }
    return "wlan0-present";
}

static int append_cnss_wlfw_precondition_summary(struct buffer *buf,
                                                 const struct mdm2ap_timing_summary *summary) {
    const bool cnss_daemon_started = summary->cnss_daemon_process_max > 0;
    const bool cnss_diag_started = summary->cnss_diag_process_max > 0;
    const bool cld80211_seen = summary->cld80211_kmsg_max > 0;
    const bool wlfw_start_seen =
        summary->wlfw_start_kmsg_max > 0;
    const bool wlfw_service_request_seen = summary->wlfw_service_request_kmsg_max > 0;
    const bool icnss_qmi_seen = summary->icnss_qmi_kmsg_max > 0;
    const bool bdf_seen = summary->bdf_kmsg_max > 0;
    const bool fw_ready_seen = summary->fw_ready_kmsg_max > 0;

    return append_format(buf,
                         "cnss_wlfw_pre.begin=1\n"
                         "cnss_wlfw_pre.mode=current-route-cnss-wlfw-precondition\n"
                         "cnss_wlfw_pre.sample_interval_ms=%d\n"
                         "cnss_wlfw_pre.sample_count=%d\n"
                         "cnss_wlfw_pre.cnss_daemon_started=%d\n"
                         "cnss_wlfw_pre.cnss_daemon_process_max=%d\n"
                         "cnss_wlfw_pre.cnss_diag_started=%d\n"
                         "cnss_wlfw_pre.cnss_diag_process_max=%d\n"
                         "cnss_wlfw_pre.cld80211_seen=%d\n"
                         "cnss_wlfw_pre.cld80211_kmsg_max=%d\n"
                         "cnss_wlfw_pre.pm_register_ret=not-observed\n"
                         "cnss_wlfw_pre.pm_register_ret_observed=0\n"
                         "cnss_wlfw_pre.pm_connect_ret=not-observed\n"
                         "cnss_wlfw_pre.pm_connect_ret_observed=0\n"
                         "cnss_wlfw_pre.wlfw_start_seen=%d\n"
                         "cnss_wlfw_pre.wlfw_start_kmsg_max=%d\n"
                         "cnss_wlfw_pre.wlfw_service_request_seen=%d\n"
                         "cnss_wlfw_pre.wlfw_service_request_kmsg_max=%d\n"
                         "cnss_wlfw_pre.icnss_qmi_seen=%d\n"
                         "cnss_wlfw_pre.icnss_qmi_kmsg_max=%d\n"
                         "cnss_wlfw_pre.bdf_seen=%d\n"
                         "cnss_wlfw_pre.bdf_kmsg_max=%d\n"
                         "cnss_wlfw_pre.fw_ready_seen=%d\n"
                         "cnss_wlfw_pre.fw_ready_kmsg_max=%d\n"
                         "cnss_wlfw_pre.wlan0_seen=%d\n"
                         "cnss_wlfw_pre.last_checkpoint=%s\n"
                         "cnss_wlfw_pre.safety_wifi_hal_start=0\n"
                         "cnss_wlfw_pre.safety_scan_connect=0\n"
                         "cnss_wlfw_pre.safety_credentials=0\n"
                         "cnss_wlfw_pre.safety_dhcp_route=0\n"
                         "cnss_wlfw_pre.safety_external_ping=0\n"
                         "cnss_wlfw_pre.safety_pmic_write=0\n"
                         "cnss_wlfw_pre.safety_gpio_request=0\n"
                         "cnss_wlfw_pre.safety_direct_esoc_ioctl=0\n"
                         "cnss_wlfw_pre.end=1\n",
                         summary->sample_interval_ms,
                         summary->sample_count,
                         cnss_daemon_started ? 1 : 0,
                         summary->cnss_daemon_process_max,
                         cnss_diag_started ? 1 : 0,
                         summary->cnss_diag_process_max,
                         cld80211_seen ? 1 : 0,
                         summary->cld80211_kmsg_max,
                         wlfw_start_seen ? 1 : 0,
                         summary->wlfw_start_kmsg_max,
                         wlfw_service_request_seen ? 1 : 0,
                         summary->wlfw_service_request_kmsg_max,
                         icnss_qmi_seen ? 1 : 0,
                         summary->icnss_qmi_kmsg_max,
                         bdf_seen ? 1 : 0,
                         summary->bdf_kmsg_max,
                         fw_ready_seen ? 1 : 0,
                         summary->fw_ready_kmsg_max,
                         summary->wlan0_seen,
                         cnss_wlfw_pre_checkpoint(summary));
}

static int append_auto_readiness_summary(struct buffer *buf,
                                         const struct mdm2ap_timing_summary *summary) {
    const bool cnss_daemon_started = summary->cnss_daemon_process_max > 0;
    const bool cnss_diag_started = summary->cnss_diag_process_max > 0;
    const bool wlfw_start_seen = summary->wlfw_start_kmsg_max > 0;
    const bool wlfw_service_request_seen = summary->wlfw_service_request_kmsg_max > 0;
    const bool icnss_qmi_seen = summary->icnss_qmi_kmsg_max > 0;
    const bool bdf_seen = summary->bdf_kmsg_max > 0;
    const bool fw_ready_seen = summary->fw_ready_kmsg_max > 0;
    const unsigned long gpio142_delta =
        summary->gpio142_irq_max > summary->gpio142_irq_initial
            ? summary->gpio142_irq_max - summary->gpio142_irq_initial
            : 0;

    return append_format(buf,
                         "auto_readiness.begin=1\n"
                         "auto_readiness.mode=current-route-boot-readiness\n"
                         "auto_readiness.sample_interval_ms=%d\n"
                         "auto_readiness.sample_count=%d\n"
                         "auto_readiness.cnss_daemon_started=%d\n"
                         "auto_readiness.cnss_diag_started=%d\n"
                         "auto_readiness.wlfw_start_seen=%d\n"
                         "auto_readiness.wlfw_service_request_seen=%d\n"
                         "auto_readiness.icnss_qmi_seen=%d\n"
                         "auto_readiness.bdf_seen=%d\n"
                         "auto_readiness.fw_ready_seen=%d\n"
                         "auto_readiness.wlan0_seen=%d\n"
                         "auto_readiness.primary_checkpoint=%s\n"
                         "auto_readiness.gpio142_irq_delta=%lu\n"
                         "auto_readiness.pcie_rc1_transition_seen=%d\n"
                         "auto_readiness.pcie_current_link_state_last=%s\n"
                         "auto_readiness.pcie_link_state_last=%s\n"
                         "auto_readiness.pcie_runtime_status_last=%s\n"
                         "auto_readiness.pcie1_gdsc_last=%s\n"
                         "auto_readiness.pcie1_pipe_clk_last=%s\n"
                         "auto_readiness.mhi_bus_max=%d\n"
                         "auto_readiness.mhi_pipe_seen=%d\n"
                         "auto_readiness.mhi_pipe_fd_max=%d\n"
                         "auto_readiness.ks_process_max=%d\n"
                         "auto_readiness.safety_wifi_hal_start=0\n"
                         "auto_readiness.safety_scan_connect=0\n"
                         "auto_readiness.safety_credentials=0\n"
                         "auto_readiness.safety_dhcp_route=0\n"
                         "auto_readiness.safety_external_ping=0\n"
                         "auto_readiness.safety_pmic_write=0\n"
                         "auto_readiness.safety_gpio_request=0\n"
                         "auto_readiness.safety_direct_esoc_ioctl=0\n"
                         "auto_readiness.end=1\n",
                         summary->sample_interval_ms,
                         summary->sample_count,
                         cnss_daemon_started ? 1 : 0,
                         cnss_diag_started ? 1 : 0,
                         wlfw_start_seen ? 1 : 0,
                         wlfw_service_request_seen ? 1 : 0,
                         icnss_qmi_seen ? 1 : 0,
                         bdf_seen ? 1 : 0,
                         fw_ready_seen ? 1 : 0,
                         summary->wlan0_seen,
                         cnss_wlfw_pre_checkpoint(summary),
                         gpio142_delta,
                         summary->pcie_rc1_transition_seen,
                         summary->pcie_current_link_state_last,
                         summary->pcie_link_state_last,
                         summary->pcie_runtime_status_last,
                         summary->pcie1_gdsc_last,
                         summary->pcie1_pipe_clk_last,
                         summary->mhi_bus_max,
                         summary->mhi_pipe_seen,
                         summary->mhi_pipe_fd_max,
                         summary->ks_process_max);
}

struct fd_poll_summary {
    int polls;
    int seen;
    int max_count;
    int last_count;
    long first_seen_elapsed_ms;
};

static void fd_poll_summary_init(struct fd_poll_summary *summary) {
    summary->polls = 0;
    summary->seen = 0;
    summary->max_count = 0;
    summary->last_count = -1;
    summary->first_seen_elapsed_ms = -1;
}

static int append_service_window_mdm_helper_fd_poll(struct buffer *buf,
                                                   pid_t pid,
                                                   const char *phase,
                                                   int duration_ms,
                                                   int interval_ms,
                                                   struct fd_poll_summary *summary) {
    long started_ms = monotonic_ms();
    long deadline_ms = started_ms + duration_ms;
    int poll_index = 0;

    fd_poll_summary_init(summary);
    if (append_format(buf,
                      "android_wifi_service_window.fd_poll.%s.begin=1\n"
                      "android_wifi_service_window.fd_poll.%s.pid=%ld\n"
                      "android_wifi_service_window.fd_poll.%s.needle=/dev/esoc-0\n"
                      "android_wifi_service_window.fd_poll.%s.duration_ms=%d\n"
                      "android_wifi_service_window.fd_poll.%s.interval_ms=%d\n",
                      phase,
                      phase,
                      (long)pid,
                      phase,
                      phase,
                      duration_ms,
                      phase,
                      interval_ms) < 0) {
        return -1;
    }
    while (poll_index < 64) {
        char label[96];
        long now_ms = monotonic_ms();
        int count = -1;

        if (now_ms > deadline_ms && poll_index > 0) {
            break;
        }
        if (snprintf(label,
                     sizeof(label),
                     "mdm_helper_esoc0_%s_poll_%02d",
                     phase,
                     poll_index) >= (int)sizeof(label)) {
            return append_format(buf,
                                 "android_wifi_service_window.fd_poll.%s.error=label-too-long\n"
                                 "android_wifi_service_window.fd_poll.%s.end=1\n",
                                 phase,
                                 phase);
        }
        if (append_format(buf,
                          "android_wifi_service_window.fd_poll.%s.poll_%02d.elapsed_ms=%ld\n",
                          phase,
                          poll_index,
                          now_ms - started_ms) < 0 ||
            append_proc_fd_target_match_scan(buf,
                                             pid,
                                             "android_wifi_service_window",
                                             label,
                                             "/dev/esoc-0",
                                             &count) < 0 ||
            append_format(buf,
                          "android_wifi_service_window.fd_poll.%s.poll_%02d.count=%d\n",
                          phase,
                          poll_index,
                          count) < 0) {
            return -1;
        }
        summary->polls++;
        summary->last_count = count;
        if (count > summary->max_count) {
            summary->max_count = count;
        }
        if (count > 0 && summary->seen == 0) {
            summary->seen = 1;
            summary->first_seen_elapsed_ms = now_ms - started_ms;
        }
        poll_index++;
        if (monotonic_ms() >= deadline_ms) {
            break;
        }
        usleep((useconds_t)interval_ms * 1000U);
    }
    return append_format(buf,
                         "android_wifi_service_window.fd_poll.%s.polls=%d\n"
                         "android_wifi_service_window.fd_poll.%s.seen=%d\n"
                         "android_wifi_service_window.fd_poll.%s.max_count=%d\n"
                         "android_wifi_service_window.fd_poll.%s.last_count=%d\n"
                         "android_wifi_service_window.fd_poll.%s.first_seen_elapsed_ms=%ld\n"
                         "android_wifi_service_window.fd_poll.%s.end=1\n",
                         phase,
                         summary->polls,
                         phase,
                         summary->seen,
                         phase,
                         summary->max_count,
                         phase,
                         summary->last_count,
                         phase,
                         summary->first_seen_elapsed_ms,
                         phase);
}

static int append_service_window_mdm_helper_launch_contract(struct buffer *buf,
                                                           const struct config *cfg,
                                                           const struct paths *paths,
                                                           const char *child_name,
                                                           const char *target,
                                                           pid_t pid,
                                                           const char *phase) {
    const char *target_context = android_default_selinux_context_for_target("/vendor/bin/mdm_helper");
    const bool exec_context_planned =
        !streq(cfg->android_selinux_context_mode, "none") && target_context != NULL;
    const bool current_context_planned = cfg->pm_observer_set_mdm_helper_selinux_context;
    const bool property_socket_planned = cfg->property_root != NULL;
    const bool pm_proxy_contract_planned = cfg->allow_android_wifi_service_window_pm_proxy_contract;
    char path_prefix[160];
    int esoc0_fd_count = -1;
    int subsys_esoc0_fd_count = -1;
    int subsys_modem_fd_count = -1;

    if (snprintf(path_prefix,
                 sizeof(path_prefix),
                 "android_wifi_service_window.mdm_helper_launch_contract.%s",
                 phase) >= (int)sizeof(path_prefix)) {
        return append_format(buf,
                             "android_wifi_service_window.mdm_helper_launch_contract.%s.error=phase-too-long\n",
                             phase);
    }
    if (append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.begin=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.snapshot_only=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.helper_version=%s\n",
                      phase,
                      EXECNS_VERSION) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.child_name=%s\n",
                      phase,
                      child_name) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.target=%s\n",
                      phase,
                      target) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.identity=mdm_helper\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.argv.argc=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.argv.0=/vendor/bin/mdm_helper\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.env.mode=%s\n",
                      phase,
                      cfg->env_mode) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.env.PATH=/system/bin:/vendor/bin:/bin\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.env.ANDROID_ROOT=/system\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.env.ANDROID_DATA=/data\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.expected.uid=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.expected.gid=%d\n",
                      phase,
                      A90_AID_SYSTEM) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.expected.groups=%d,%d,%d\n",
                      phase,
                      A90_AID_SYSTEM,
                      A90_AID_WAKELOCK,
                      A90_AID_SHELL) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.expected.capability_mode=none\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.android_selinux_context_mode=%s\n",
                      phase,
                      cfg->android_selinux_context_mode) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.exec_context_planned=%d\n",
                      phase,
                      exec_context_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.exec_target_context=%s\n",
                      phase,
                      target_context != NULL ? target_context : "none") < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.current_context_planned=%d\n",
                      phase,
                      current_context_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.property_service_shim_needed=%d\n",
                      phase,
                      property_socket_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.pm_proxy_helper_start_planned=%d\n",
                      phase,
                      pm_proxy_contract_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.pm_proxy_start_planned=%d\n",
                      phase,
                      pm_proxy_contract_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.cnss_daemon_start_after_mdm_helper=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.subsys_esoc0_controller_open_planned=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.esoc_ioctl_attempted=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.scan_connect_linkup=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.credentials=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.dhcp_routing=0\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.external_ping=0\n",
                      phase) < 0 ||
        append_private_runtime_path_status(buf,
                                           paths,
                                           path_prefix,
                                           "dev_esoc_0",
                                           "/dev/esoc-0") < 0 ||
        append_private_runtime_path_status(buf,
                                           paths,
                                           path_prefix,
                                           "dev_subsys_esoc0",
                                           "/dev/subsys_esoc0") < 0 ||
        append_private_runtime_path_status(buf,
                                           paths,
                                           path_prefix,
                                           "dev_subsys_modem",
                                           "/dev/subsys_modem") < 0 ||
        append_private_runtime_path_status(buf,
                                           paths,
                                           path_prefix,
                                           "dev_socket_property_service",
                                           "/dev/socket/property_service") < 0) {
        return -1;
    }
    if (pid > 0) {
        if (append_format(buf,
                          "android_wifi_service_window.mdm_helper_launch_contract.%s.pid=%ld\n"
                          "android_wifi_service_window.mdm_helper_launch_contract.%s.pid_observable=%d\n",
                          phase,
                          (long)pid,
                          phase,
                          kill(pid, 0) == 0 ? 1 : 0) < 0 ||
            append_proc_fd_target_match_scan(buf,
                                             pid,
                                             "android_wifi_service_window",
                                             "mdm_helper_launch_contract_esoc0",
                                             "/dev/esoc-0",
                                             &esoc0_fd_count) < 0 ||
            append_proc_fd_target_match_scan(buf,
                                             pid,
                                             "android_wifi_service_window",
                                             "mdm_helper_launch_contract_subsys_esoc0",
                                             "/dev/subsys_esoc0",
                                             &subsys_esoc0_fd_count) < 0 ||
            append_proc_fd_target_match_scan(buf,
                                             pid,
                                             "android_wifi_service_window",
                                             "mdm_helper_launch_contract_subsys_modem",
                                             "/dev/subsys_modem",
                                             &subsys_modem_fd_count) < 0) {
            return -1;
        }
    } else if (append_format(buf,
                             "android_wifi_service_window.mdm_helper_launch_contract.%s.pid=-1\n"
                             "android_wifi_service_window.mdm_helper_launch_contract.%s.pid_observable=0\n",
                             phase,
                             phase) < 0) {
        return -1;
    }
    if (append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.fd.esoc0=%d\n",
                      phase,
                      esoc0_fd_count) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.fd.subsys_esoc0=%d\n",
                      phase,
                      subsys_esoc0_fd_count) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.fd.subsys_modem=%d\n",
                      phase,
                      subsys_modem_fd_count) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.reference.android_good_mdm_helper_target=/vendor/bin/mdm_helper\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.reference.reduced_native_positive_target=/vendor/bin/mdm_helper\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.target_match=%d\n",
                      phase,
                      streq(target, "/vendor/bin/mdm_helper") ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.argv_match=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.identity_match=1\n",
                      phase) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.exec_context_match=%d\n",
                      phase,
                      exec_context_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.current_context_delta=%d\n",
                      phase,
                      current_context_planned ? 0 : 1) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.pm_proxy_absent_delta=%d\n",
                      phase,
                      pm_proxy_contract_planned ? 0 : 1) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.pm_proxy_contract_planned=%d\n",
                      phase,
                      pm_proxy_contract_planned ? 1 : 0) < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.compare.result=%s\n",
                      phase,
                      (exec_context_planned &&
                       streq(target, "/vendor/bin/mdm_helper"))
                          ? (pm_proxy_contract_planned
                                 ? "launch-contract-recorded-with-pm-proxy-contract"
                                 : "launch-contract-recorded-with-pm-proxy-delta")
                          : "launch-contract-incomplete") < 0 ||
        append_format(buf,
                      "android_wifi_service_window.mdm_helper_launch_contract.%s.end=1\n",
                      phase) < 0) {
        return -1;
    }
    return 0;
}

static int append_mdm_helper_only_deep_snapshot(struct buffer *buf, pid_t pid, const char *phase) {
    char label[96];
    char capture_label[160];
    bool attr_captured = false;
    bool maps_captured = false;
    bool netlink_captured = false;
    bool unix_captured = false;
    bool qrtr_captured = false;
    bool protocols_captured = false;

    if (snprintf(label, sizeof(label), "mdm_helper_only_%s", phase) >= (int)sizeof(label)) {
        return append_format(buf,
                             "mdm_helper_only_capture.snapshot.%s.error=label-too-long\n",
                             phase);
    }
    if (append_format(buf,
                      "mdm_helper_only_capture.snapshot.%s.begin=1\n"
                      "mdm_helper_only_capture.snapshot.%s.pid=%ld\n",
                      phase,
                      phase,
                      (long)pid) < 0 ||
        append_generic_stall_snapshot_capture(buf, pid, label) < 0 ||
        append_proc_fd_links_compact(buf, pid, label) < 0) {
        return -1;
    }
    if (snprintf(capture_label, sizeof(capture_label), "%s_attr_current", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "attr/current", capture_label, 4096, &attr_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_maps", label) >= (int)sizeof(capture_label) ||
        append_proc_file_capture_named(buf, pid, "maps", capture_label, 32768, &maps_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_proc_net_netlink", label) >= (int)sizeof(capture_label) ||
        append_path_file_capture_named(buf, "/proc/net/netlink", capture_label, 32768, &netlink_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_proc_net_unix", label) >= (int)sizeof(capture_label) ||
        append_path_file_capture_named(buf, "/proc/net/unix", capture_label, 32768, &unix_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_proc_net_qrtr", label) >= (int)sizeof(capture_label) ||
        append_path_file_capture_named(buf, "/proc/net/qrtr", capture_label, 32768, &qrtr_captured) < 0 ||
        snprintf(capture_label, sizeof(capture_label), "%s_proc_net_protocols", label) >= (int)sizeof(capture_label) ||
        append_path_file_capture_named(buf, "/proc/net/protocols", capture_label, 32768, &protocols_captured) < 0) {
        return -1;
    }
    return append_format(buf,
                         "mdm_helper_only_capture.snapshot.%s.attr_current_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.maps_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.netlink_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.unix_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.qrtr_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.protocols_captured=%d\n"
                         "mdm_helper_only_capture.snapshot.%s.end=1\n",
                         phase,
                         attr_captured ? 1 : 0,
                         phase,
                         maps_captured ? 1 : 0,
                         phase,
                         netlink_captured ? 1 : 0,
                         phase,
                         unix_captured ? 1 : 0,
                         phase,
                         qrtr_captured ? 1 : 0,
                         phase,
                         protocols_captured ? 1 : 0,
                         phase);
}

