static bool qrtr_registry_line_interesting(const char *line) {
    return strcasestr(line, "wlan") != NULL ||
           strcasestr(line, "servloc") != NULL ||
           strcasestr(line, "service-locator") != NULL ||
           strcasestr(line, "service locator") != NULL ||
           strcasestr(line, "service_locator") != NULL ||
           strcasestr(line, "wlan/fw") != NULL ||
           strcasestr(line, "wlan_pd") != NULL ||
           strcasestr(line, "wlan-pd") != NULL;
}

static int append_qrtr_registry_file_summary(struct buffer *buf,
                                             const char *phase,
                                             const char *label,
                                             const char *path) {
    enum { QRTR_REGISTRY_CAPTURE_LIMIT = 32768 };
    char *text;
    char *line;
    char *saveptr = NULL;
    ssize_t nread;
    size_t total = 0;
    unsigned int line_count = 0;
    unsigned int interesting_lines = 0;
    bool truncated = false;
    bool wlan_text = false;
    bool service_locator_text = false;
    bool wlan_fw_text = false;
    bool wlan_pd_text = false;
    bool service74_text = false;
    bool service180_text = false;
    bool qmi_text = false;
    char first_interesting[192] = "";
    int fd;

    if (append_format(buf,
                      "wlan_pd_qrtr_registry.%s.%s.path=%s\n",
                      phase,
                      label,
                      path) < 0) {
        return -1;
    }
    fd = open(path, O_RDONLY | O_CLOEXEC);
    if (fd < 0) {
        return append_format(buf,
                             "wlan_pd_qrtr_registry.%s.%s.open=0\n"
                             "wlan_pd_qrtr_registry.%s.%s.errno=%d\n"
                             "wlan_pd_qrtr_registry.%s.%s.error=%s\n"
                             "wlan_pd_qrtr_registry.%s.%s.bytes=0\n"
                             "wlan_pd_qrtr_registry.%s.%s.lines=0\n",
                             phase,
                             label,
                             phase,
                             label,
                             errno,
                             phase,
                             label,
                             strerror(errno),
                             phase,
                             label,
                             phase,
                             label);
    }
    text = calloc(1U, QRTR_REGISTRY_CAPTURE_LIMIT + 1U);
    if (text == NULL) {
        close(fd);
        return append_format(buf,
                             "wlan_pd_qrtr_registry.%s.%s.open=1\n"
                             "wlan_pd_qrtr_registry.%s.%s.errno=%d\n"
                             "wlan_pd_qrtr_registry.%s.%s.error=%s\n"
                             "wlan_pd_qrtr_registry.%s.%s.bytes=0\n"
                             "wlan_pd_qrtr_registry.%s.%s.lines=0\n",
                             phase,
                             label,
                             phase,
                             label,
                             ENOMEM,
                             phase,
                             label,
                             strerror(ENOMEM),
                             phase,
                             label,
                             phase,
                             label);
    }
    while (total < QRTR_REGISTRY_CAPTURE_LIMIT) {
        nread = read(fd,
                     text + total,
                     QRTR_REGISTRY_CAPTURE_LIMIT - total);
        if (nread < 0) {
            if (errno == EINTR) {
                continue;
            }
            {
                int saved_errno = errno;

                close(fd);
                free(text);
                return append_format(buf,
                                     "wlan_pd_qrtr_registry.%s.%s.open=1\n"
                                     "wlan_pd_qrtr_registry.%s.%s.errno=%d\n"
                                     "wlan_pd_qrtr_registry.%s.%s.error=%s\n"
                                     "wlan_pd_qrtr_registry.%s.%s.bytes=%zu\n"
                                     "wlan_pd_qrtr_registry.%s.%s.lines=0\n",
                                     phase,
                                     label,
                                     phase,
                                     label,
                                     saved_errno,
                                     phase,
                                     label,
                                     strerror(saved_errno),
                                     phase,
                                     label,
                                     total,
                                     phase,
                                     label);
            }
        }
        if (nread == 0) {
            break;
        }
        total += (size_t)nread;
    }
    close(fd);
    text[total] = '\0';
    truncated = total >= QRTR_REGISTRY_CAPTURE_LIMIT;
    wlan_text = strcasestr(text, "wlan") != NULL;
    service_locator_text = strcasestr(text, "servloc") != NULL ||
                           strcasestr(text, "service-locator") != NULL ||
                           strcasestr(text, "service locator") != NULL ||
                           strcasestr(text, "service_locator") != NULL;
    wlan_fw_text = strcasestr(text, "wlan/fw") != NULL ||
                   strcasestr(text, "wlan_fw") != NULL ||
                   strcasestr(text, "wlan fw") != NULL;
    wlan_pd_text = strcasestr(text, "wlan_pd") != NULL ||
                   strcasestr(text, "wlan-pd") != NULL;
    service74_text = strstr(text, "74") != NULL;
    service180_text = strstr(text, "180") != NULL;
    qmi_text = strcasestr(text, "qmi") != NULL;
    for (line = strtok_r(text, "\n", &saveptr);
         line != NULL;
         line = strtok_r(NULL, "\n", &saveptr)) {
        line_count++;
        if (qrtr_registry_line_interesting(line)) {
            interesting_lines++;
            if (first_interesting[0] == '\0') {
                copy_klog_value(first_interesting, sizeof(first_interesting), line);
            }
        }
    }
    if (append_format(buf,
                      "wlan_pd_qrtr_registry.%s.%s.open=1\n"
                      "wlan_pd_qrtr_registry.%s.%s.errno=0\n"
                      "wlan_pd_qrtr_registry.%s.%s.error=none\n"
                      "wlan_pd_qrtr_registry.%s.%s.bytes=%zu\n"
                      "wlan_pd_qrtr_registry.%s.%s.truncated=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.lines=%u\n"
                      "wlan_pd_qrtr_registry.%s.%s.interesting_lines=%u\n"
                      "wlan_pd_qrtr_registry.%s.%s.wlan_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.service_locator_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.wlan_fw_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.wlan_pd_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.service74_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.service180_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.qmi_text=%d\n"
                      "wlan_pd_qrtr_registry.%s.%s.first_interesting=%s\n",
                      phase,
                      label,
                      phase,
                      label,
                      phase,
                      label,
                      phase,
                      label,
                      total,
                      phase,
                      label,
                      truncated ? 1 : 0,
                      phase,
                      label,
                      line_count,
                      phase,
                      label,
                      interesting_lines,
                      phase,
                      label,
                      wlan_text ? 1 : 0,
                      phase,
                      label,
                      service_locator_text ? 1 : 0,
                      phase,
                      label,
                      wlan_fw_text ? 1 : 0,
                      phase,
                      label,
                      wlan_pd_text ? 1 : 0,
                      phase,
                      label,
                      service74_text ? 1 : 0,
                      phase,
                      label,
                      service180_text ? 1 : 0,
                      phase,
                      label,
                      qmi_text ? 1 : 0,
                      phase,
                      label,
                      first_interesting[0] != '\0' ? first_interesting : "missing") < 0) {
        free(text);
        return -1;
    }
    free(text);
    return 0;
}

static int append_wlan_pd_qrtr_registry_snapshot(struct buffer *buf,
                                                 const char *phase) {
    struct stat st;
    int debug_qrtr_exists = lstat("/sys/kernel/debug/qrtr", &st) == 0 ? 1 : 0;
    int debug_msm_ipc_router_exists = lstat("/sys/kernel/debug/msm_ipc_router", &st) == 0 ? 1 : 0;

    if (append_format(buf,
                      "wlan_pd_qrtr_registry.%s.begin=1\n"
                      "wlan_pd_qrtr_registry.%s.mode=read-only-proc-debugfs-summary\n"
                      "wlan_pd_qrtr_registry.%s.debug_qrtr_exists=%d\n"
                      "wlan_pd_qrtr_registry.%s.debug_msm_ipc_router_exists=%d\n",
                      phase,
                      phase,
                      phase,
                      debug_qrtr_exists,
                      phase,
                      debug_msm_ipc_router_exists) < 0 ||
        append_qrtr_registry_file_summary(buf,
                                          phase,
                                          "proc_net_qrtr",
                                          "/proc/net/qrtr") < 0 ||
        append_qrtr_registry_file_summary(buf,
                                          phase,
                                          "debug_qrtr_nodes",
                                          "/sys/kernel/debug/qrtr/nodes") < 0 ||
        append_qrtr_registry_file_summary(buf,
                                          phase,
                                          "debug_qrtr_services",
                                          "/sys/kernel/debug/qrtr/services") < 0 ||
        append_qrtr_registry_file_summary(buf,
                                          phase,
                                          "debug_msm_ipc_router_dump",
                                          "/sys/kernel/debug/msm_ipc_router/dump") < 0) {
        return -1;
    }
    return append_format(buf,
                         "wlan_pd_qrtr_registry.%s.no_qrtr_lookup_send=1\n"
                         "wlan_pd_qrtr_registry.%s.no_service_start=1\n"
                         "wlan_pd_qrtr_registry.%s.no_esoc0_open=1\n"
                         "wlan_pd_qrtr_registry.%s.no_fake_online=1\n"
                         "wlan_pd_qrtr_registry.%s.no_pmic_gpio_gdsc_write=1\n"
                         "wlan_pd_qrtr_registry.%s.end=1\n",
                         phase,
                         phase,
                         phase,
                         phase,
                         phase,
                         phase);
}

struct icnss_ipc_focus_counts {
    unsigned int contexts;
    unsigned int readable_logs;
    unsigned int open_errors;
    unsigned int lines;
    unsigned int focus_lines;
    bool get_service_location;
    bool get_service_notify;
    bool wlan_pd_domain;
    bool pd_notification_registration;
    bool wlfw_server_arrive;
    bool service69_text;
    char first_source[MAX_PATH_LEN];
    char first_focus_line[192];
};

static bool icnss_ipc_line_focused(const char *line) {
    return strcasestr(line, "icnss") != NULL ||
           strcasestr(line, "wlfw") != NULL ||
           strcasestr(line, "wlan_pd") != NULL ||
           strcasestr(line, "wlan/fw") != NULL ||
           strcasestr(line, "domain_name") != NULL ||
           strcasestr(line, "service 69") != NULL;
}

static void update_icnss_ipc_focus_counts(struct icnss_ipc_focus_counts *counts,
                                          const char *source,
                                          const char *line) {
    counts->lines++;
    if (!icnss_ipc_line_focused(line)) {
        return;
    }
    counts->focus_lines++;
    if (counts->first_focus_line[0] == '\0') {
        copy_klog_value(counts->first_focus_line,
                        sizeof(counts->first_focus_line),
                        line);
        copy_klog_value(counts->first_source,
                        sizeof(counts->first_source),
                        source);
    }
    if (strcasestr(line, "Get service location") != NULL) {
        counts->get_service_location = true;
    }
    if (strcasestr(line, "Get service notify") != NULL) {
        counts->get_service_notify = true;
    }
    if (strcasestr(line, "msm/modem/wlan_pd") != NULL ||
        strcasestr(line, "wlan_pd") != NULL) {
        counts->wlan_pd_domain = true;
    }
    if (strcasestr(line, "PD notification registration happened") != NULL) {
        counts->pd_notification_registration = true;
    }
    if (strcasestr(line, "WLFW server arrive") != NULL) {
        counts->wlfw_server_arrive = true;
    }
    if (strcasestr(line, "service 69") != NULL ||
        strcasestr(line, "svc_id=0x45") != NULL ||
        strcasestr(line, "svc_id=69") != NULL) {
        counts->service69_text = true;
    }
}

static void scan_icnss_ipc_log_text(struct icnss_ipc_focus_counts *counts,
                                    const char *source,
                                    char *text) {
    char *line;
    char *saveptr = NULL;

    for (line = strtok_r(text, "\n", &saveptr);
         line != NULL;
         line = strtok_r(NULL, "\n", &saveptr)) {
        update_icnss_ipc_focus_counts(counts, source, line);
    }
}

static void scan_icnss_ipc_log_file(struct icnss_ipc_focus_counts *counts,
                                    const char *path) {
    enum { ICNSS_IPC_CAPTURE_LIMIT = 32768 };
    char *text;
    ssize_t nread;
    size_t total = 0;
    int fd;

    counts->contexts++;
    fd = open(path, O_RDONLY | O_CLOEXEC);
    if (fd < 0) {
        counts->open_errors++;
        return;
    }
    counts->readable_logs++;
    text = calloc(1U, ICNSS_IPC_CAPTURE_LIMIT + 1U);
    if (text == NULL) {
        close(fd);
        counts->open_errors++;
        return;
    }
    while (total < ICNSS_IPC_CAPTURE_LIMIT) {
        nread = read(fd, text + total, ICNSS_IPC_CAPTURE_LIMIT - total);
        if (nread < 0) {
            if (errno == EINTR) {
                continue;
            }
            counts->open_errors++;
            break;
        }
        if (nread == 0) {
            break;
        }
        total += (size_t)nread;
    }
    close(fd);
    text[total] = '\0';
    scan_icnss_ipc_log_text(counts, path, text);
    free(text);
}

static void scan_icnss_ipc_root(struct icnss_ipc_focus_counts *counts,
                                const char *root) {
    enum { ICNSS_IPC_CONTEXT_LIMIT = 128 };
    DIR *dir;
    struct dirent *entry;
    struct stat st;
    unsigned int context_count = 0;

    dir = opendir(root);
    if (dir == NULL) {
        return;
    }
    while ((entry = readdir(dir)) != NULL && context_count < ICNSS_IPC_CONTEXT_LIMIT) {
        char path[MAX_PATH_LEN];

        if (entry->d_name[0] == '.') {
            continue;
        }
        if (snprintf(path, sizeof(path), "%s/%s/log", root, entry->d_name) >= (int)sizeof(path)) {
            continue;
        }
        if (lstat(path, &st) == 0 && S_ISREG(st.st_mode)) {
            scan_icnss_ipc_log_file(counts, path);
            context_count++;
            continue;
        }
        if (snprintf(path, sizeof(path), "%s/%s", root, entry->d_name) >= (int)sizeof(path)) {
            continue;
        }
        if (lstat(path, &st) == 0 && S_ISREG(st.st_mode)) {
            scan_icnss_ipc_log_file(counts, path);
            context_count++;
        }
    }
    closedir(dir);
}

static int append_icnss_ipc_root_summary(struct buffer *buf,
                                         const char *phase,
                                         const char *label,
                                         const char *root) {
    struct stat st;
    struct icnss_ipc_focus_counts counts;
    bool root_exists = lstat(root, &st) == 0;

    memset(&counts, 0, sizeof(counts));
    if (root_exists && S_ISDIR(st.st_mode)) {
        scan_icnss_ipc_root(&counts, root);
    }
    return append_format(buf,
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.root=%s\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.root_exists=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.contexts=%u\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.readable_logs=%u\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.open_errors=%u\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.lines=%u\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.focus_lines=%u\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.get_service_location=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.get_service_notify=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.wlan_pd_domain=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.pd_notification_registration=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.wlfw_server_arrive=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.service69_text=%d\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.first_source=%s\n"
                         "wlan_pd_icnss_ipc_snapshot.%s.%s.first_focus_line=%s\n",
                         phase,
                         label,
                         root,
                         phase,
                         label,
                         root_exists ? 1 : 0,
                         phase,
                         label,
                         counts.contexts,
                         phase,
                         label,
                         counts.readable_logs,
                         phase,
                         label,
                         counts.open_errors,
                         phase,
                         label,
                         counts.lines,
                         phase,
                         label,
                         counts.focus_lines,
                         phase,
                         label,
                         counts.get_service_location ? 1 : 0,
                         phase,
                         label,
                         counts.get_service_notify ? 1 : 0,
                         phase,
                         label,
                         counts.wlan_pd_domain ? 1 : 0,
                         phase,
                         label,
                         counts.pd_notification_registration ? 1 : 0,
                         phase,
                         label,
                         counts.wlfw_server_arrive ? 1 : 0,
                         phase,
                         label,
                         counts.service69_text ? 1 : 0,
                         phase,
                         label,
                         counts.first_source[0] != '\0' ? counts.first_source : "missing",
                         phase,
                         label,
                         counts.first_focus_line[0] != '\0' ? counts.first_focus_line : "missing");
}

